window.allTests = window.allTests || {};

window.allTests["test_u3_genel_1"] = [
    {
        soru: "\"Hunların batıya doğru hareketi, Avrupa tarihinin seyrini kökten değiştirdi. Bu göç dalgası, önündeki kavimleri Roma İmparatorluğu'nun sınırlarına iterek domino etkisi yarattı; Vizigotlar, Ostrogotlar ve diğer Germen toplulukları Roma topraklarına sığınmak zorunda kaldı.\"\n— Peter Heather, The Fall of the Roman Empire, Oxford University Press, 2006\n\nMetne göre Hunların batıya göçünün Avrupa üzerindeki temel etkisi nedir?",
        secenekler: [
            "Roma İmparatorluğu'nun sınırlarını genişletmesi",
            "Germen kavimlerini Roma topraklarına sürüklemesi",
            "Hunların doğrudan Roma'yı fethetmesi",
            "Avrupa'da kalıcı bir Hun devletinin kurulması",
            "Ticaret yollarının Hunlar tarafından kontrol altına alınması"
        ],
        cevap: "Germen kavimlerini Roma topraklarına sürüklemesi",
        aciklama: "Metinde Hunların batıya göçünün 'domino etkisi' yarattığı ve Germen kavimlerini Roma topraklarına sığınmaya zorladığı açıkça belirtilmektedir. Diğer şıklar metinde geçmeyen ya da tersine olan iddialardır. Bu soru öğrenciden metnin temel nedensellik ilişkisini doğru okumasını beklemektedir."
    },
    {
        soru: "\"Cengiz Han'ın orduları, Orta Asya'dan batıya ve güneye doğru ilerlerken gittiği her yerde nüfus hareketlerine yol açtı. Kalabalık şehirler boşaltıldı; halklar ya öldürüldü ya sürgüne gönderildi ya da Moğol ordusu içinde eritildi. Bu süreç, Asya'dan Avrupa'ya uzanan geniş bir coğrafyada demografik yapıyı köklü biçimde dönüştürdü.\"\n— David Nicolle, The Mongol Warlords, Firebird Books, 1990\n\nMetne göre Moğol istilaları hangi açıdan kitlesel göçlerle doğrudan ilişkilidir?",
        secenekler: [
            "Moğolların fethettiği topraklara kalıcı olarak yerleşmesi",
            "Şehir nüfuslarının dağılmasına ve demografik dönüşüme yol açması",
            "İstila edilen bölgelerdeki ticaret yollarının canlanması",
            "Fethedilen halkların Moğol kültürünü gönüllü biçimde benimsemesi",
            "Avrupa devletlerinin Moğollara karşı kalıcı bir ittifak kurması"
        ],
        cevap: "Şehir nüfuslarının dağılmasına ve demografik dönüşüme yol açması",
        aciklama: "Metinde şehirlerin boşaltılması, halkların sürgün edilmesi ve Moğol kuvvetlerine katılmaya zorlanması demografik dönüşümün somut biçimleri olarak sunulmaktadır. Diğer şıklar metnin içeriğiyle çelişmektedir ya da metinde desteklenmemektedir."
    },
    {
        soru: "\"Vikinglerin 8. yüzyıldan itibaren başlattığı denizaşırı hareketler, salt yağma ya da savaştan ibaret değildi. İskandinav toplulukları İngiltere'den Rusya'ya, Normandiya'dan Kuzey Amerika kıyılarına kadar uzanan coğrafyalarda kalıcı yerleşim bölgeleri kurdu. Bu süreç, Avrupa'nın siyasi haritasını yeniden çizerken yeni kültürel ve ticari ağların oluşmasını da sağladı.\"\n— Neil Price, The Children of Ash and Elm: A History of the Vikings, Basic Books, 2020\n\nMetne göre Viking hareketlerini salt bir yağma ve savaş hareketinden ayıran temel özellik nedir?",
        secenekler: [
            "Yalnızca Kuzey Avrupa ile sınırlı kalmaları",
            "Dinî amaçlarla gerçekleştirilmeleri",
            "Kalıcı yerleşimler kurarak siyasi ve kültürel dönüşüme yol açmaları",
            "Kara yoluyla ilerleyerek denizden yararlanmamaları",
            "Fethedilen bölge halkları tarafından davet edilmeleri"
        ],
        cevap: "Kalıcı yerleşimler kurarak siyasi ve kültürel dönüşüme yol açmaları",
        aciklama: "Metin, Viking hareketlerinin yalnızca yıkıcı değil kalıcı yerleşim, siyasi dönüşüm ve ticari ağ kurma boyutlarına sahip olduğunu vurgulamaktadır. A seçeneği coğrafi kapsam açısından metinle çelişmekte, diğerleri ise metinde hiç geçmemektedir."
    },
    {
        soru: "\"Orta Çağ'daki Haçlı Seferleri, Avrupa'dan Orta Doğu'ya büyük insan akışlarını beraberinde getirdi. Ancak bu göç dalgası tek yönlü değildi; Müslüman, Yahudi ve Hristiyan topluluklar arasındaki çatışma ve etkileşimler, Levant bölgesinde kalıcı demografik izler bıraktı.\"\n— Norman Davies, Europe: A History, Oxford University Press, 1996\n\nMetne göre Haçlı Seferleri'nin demografik sonuçları hakkında hangi yorum doğrudur?",
        secenekler: [
            "Haçlı Seferleri yalnızca Müslüman nüfus üzerinde etkili oldu.",
            "Göç hareketleri yalnızca batıdan doğuya doğru gerçekleşti.",
            "Çok yönlü göç ve etkileşimler, bölgede kalıcı demografik değişimlere yol açtı.",
            "Haçlı Seferleri demografik değil yalnızca siyasi değişimlere neden oldu.",
            "Levant bölgesinde tek bir dini topluluk hâkimiyeti kuruldu."
        ],
        cevap: "Çok yönlü göç ve etkileşimler, bölgede kalıcı demografik değişimlere yol açtı.",
        aciklama: "Metin göç dalgasının 'tek yönlü olmadığını' ve üç farklı dini topluluk arasındaki etkileşimin bölgede kalıcı demografik izler bıraktığını açıkça belirtmektedir. B seçeneği 'tek yönlülük' iddiasıyla doğrudan metinle çelişmektedir."
    },
    {
        soru: "\"Büyük Göç döneminin ekonomik sonuçları paradoksal bir tablo ortaya koyar: Bir yanda Roma kent ekonomisinin çöküşü ve uzun mesafeli ticaretin daralması; öte yanda yeni halkların beraberinde getirdiği zanaatlar, tarım teknikleri ve ticari ilişkiler sayesinde ortaya çıkan yerel ekonomik canlanmalar. Göç hareketleri, geç antik dönem ekonomik düzenini tahrip ettiği kadar yeni ekonomik formların filizlenmesine de zemin hazırladı.\"\n— Michael McCormick, Origins of the European Economy, Cambridge University Press, 2001\n\nMetne göre Büyük Göç döneminin ekonomik değerlendirmesini en çok zorlaştıran etken nedir?",
        secenekler: [
            "Bu dönemin ekonomik kayıtlarının son derece yetersiz olması",
            "Göçlerin hem yıkıcı hem yapıcı ekonomik sonuçlar doğurmasının tek yönlü analize izin vermemesi",
            "Göçlerin yalnızca tarım ekonomisini etkileyip ticaret ağlarını etkilememesi",
            "Roma ekonomisinin göçlerden hiç etkilenmemiş olması",
            "Yeni kavimlerin ekonomik katkılarının modern tarihçiler tarafından abartılması"
        ],
        cevap: "Göçlerin hem yıkıcı hem yapıcı ekonomik sonuçlar doğurmasının tek yönlü analize izin vermemesi",
        aciklama: "Metin, göç dönemini 'paradoksal' olarak nitelendirmekte ve hem olumsuz (çöküş, daralma) hem de olumlu (yeni ekonomik formlar) sonuçları bir arada sunmaktadır. Bu karmaşık tablonun kendisi analizi güçleştirmektedir. Diğer şıklar metinde desteklenmemekte ya da yanlış olgular içermektedir. Bu soru öğrenciden 'paradoks' kavramını kavrayarak iki yönlü nedenselliği çözümlemesini beklemektedir."
    },
    {
        soru: "\"Göç döneminde Germen kavimleri, fethettikleri Roma topraklarına doğrudan bir yıkım getirmek yerine çoğunlukla mevcut Roma kurumlarını ve yönetim yapılarını kısmen benimsedi. Bu süreçte Germen gelenekleri ile Roma mirası iç içe geçerek yeni bir siyasi ve kültürel sentezi doğurdu.\"\n— Chris Wickham, The Inheritance of Rome: Illuminating the Dark Ages, Penguin, 2009\n\nMetne göre Germen kavimlerinin Roma topraklarındaki tutumu hakkında hangi çıkarım yapılabilir?",
        secenekler: [
            "Germen kavimleri Roma kurumlarını tamamen yıkarak kendi geleneklerini uyguladı.",
            "Roma ile Germen kültürü arasında yeni bir siyasi ve kültürel sentez ortaya çıktı.",
            "Germen kavimleri Roma kurumlarını hiçbir değişiklik yapmadan sürdürdü.",
            "Germen toplulukları fethedilen toprakları kısa süre içinde terk etti.",
            "Roma yönetim yapıları Germen istilalarından hiç etkilenmedi."
        ],
        cevap: "Roma ile Germen kültürü arasında yeni bir siyasi ve kültürel sentez ortaya çıktı.",
        aciklama: "Metin, Germen kavimlerinin ne tamamen yıkım getirdiğini ne de Roma kurumlarını olduğu gibi koruduğunu; ikisinin iç içe geçtiğini ve bir sentez doğurduğunu belirtmektedir. A ve C seçenekleri bu ikili yapıyı görmezden gelen aşırı yorumlardır."
    },
    {
        soru: "\"Orta Çağ'ın ilk yüzyıllarında Avrupa'da yaşanan göç hareketleri, kültürel belleğin aktarımını hem sekteye uğrattı hem de zenginleştirdi. Halklar yer değiştirirken yanlarında inançlarını, mitlerini ve sanatsal birikimlerini taşıdılar; bu buluşmalar bazen silinme, bazen de sentez ve yeniden doğuş anlamına geldi.\"\n— Umberto Eco, Art and Beauty in the Middle Ages, Yale University Press, 1986\n\nMetne göre Orta Çağ göçlerinin kültürel mirasa etkisi nasıl değerlendirilebilir?",
        secenekler: [
            "Göçler, kültürel mirası tamamen ve kalıcı biçimde yok etti.",
            "Göçler, kültürel mirasın değişmeden korunmasını sağladı.",
            "Göçler hem kültürel yıkıma hem de yeni sentezlerin doğmasına yol açtı.",
            "Kültürel aktarım yalnızca yazılı kaynaklar aracılığıyla sağlandı.",
            "Göçler, sanatsal gelişimi yalnızca yavaşlattı ve başka bir etkisi olmadı."
        ],
        cevap: "Göçler hem kültürel yıkıma hem de yeni sentezlerin doğmasına yol açtı.",
        aciklama: "Metin hem 'sekteye uğratma' (yıkım) hem de 'zenginleştirme' (sentez, yeniden doğuş) boyutlarına eşit ağırlıkla yer vermektedir. Yalnızca bir boyutu öne çıkaran A, B ve E seçenekleri bu ikili yapıyı yansıtamamaktadır."
    },
    {
        soru: "\"Arkeolojik bulgular, 5. ve 6. yüzyıllarda Batı Roma'nın çöküşünün yalnızca siyasi değil, derin bir maddi gerilemeyle de eş zamanlı olduğunu ortaya koyar. Seramik üretimi, yapı faaliyetleri ve okuryazarlık oranları dramatik biçimde düştü. Göç çağının bu sonuçlarını salt 'dönüşüm' olarak tanımlamak, yaşananların ağırlığını hafifletmek anlamına gelir.\"\n— Bryan Ward-Perkins, The Fall of Rome and the End of Civilization, Oxford University Press, 2005\n\nYazar, Büyük Göç dönemine ilişkin hangi tarihsel yoruma karşı çıkmaktadır?",
        secenekler: [
            "Göçlerin Roma'nın çöküşüne katkıda bulunduğu görüşüne",
            "Bu dönemin 'dönüşüm' olarak adlandırılmasına; yani yaşanan yıkımın önemsizleştirilmesine",
            "Arkeolojik bulguların tarihsel analiz için yetersiz olduğu görüşüne",
            "Roma'nın iç sorunlarının dış istilalardan daha etkili olduğu tezine",
            "Okuryazarlık oranlarının Orta Çağ tarihini anlamlandırmada kullanılmasına"
        ],
        cevap: "Bu dönemin 'dönüşüm' olarak adlandırılmasına; yani yaşanan yıkımın önemsizleştirilmesine",
        aciklama: "Yazar, göç döneminin 'dönüşüm' gibi nötr ya da olumlu çağrışımlı bir kavramla tanımlanmasına itiraz etmektedir. Arkeolojik kanıtların işaret ettiği maddi gerileme (seramik, yapı, okuryazarlık düşüşleri), bu dönemin gerçek ağırlığının teslim edilmesini gerektirmektedir. Bu soru öğrencinin tarih yazımındaki kavram seçiminin siyasi/ideolojik boyutlarını kavramasını beklemektedir."
    },
    {
        soru: "\"Feodal düzen, merkezi otoritenin çöküşünden doğan bir boşluğu doldurmak üzere gelişti. Bu sistemde toprak sahipliği, koruma ve hizmet yükümlülükleriyle iç içe geçerek karşılıklı bağımlılıklara dayalı bir sosyal ve siyasi yapı oluşturdu. Kral ile köylü arasındaki zincir, vasallık bağlarıyla birbirini izleyen bir dizi aracı unsurdan oluşuyordu.\"\n— Marc Bloch, Feudal Society, University of Chicago Press, 1961\n\nMetne göre feodal düzenin ortaya çıkmasındaki temel neden nedir?",
        secenekler: [
            "Kilisenin siyasi alanda güç kazanması",
            "Merkezi otoritenin çöküşünden doğan siyasi boşluk",
            "Ticaret yollarının güvensizleşmesi",
            "Şehirlerin nüfus artışıyla birlikte güçlenmesi",
            "Haçlı Seferlerinin yarattığı askerî ihtiyaçlar"
        ],
        cevap: "Merkezi otoritenin çöküşünden doğan siyasi boşluk",
        aciklama: "Metin feodal düzenin 'merkezi otoritenin çöküşünden doğan bir boşluğu doldurmak üzere' geliştiğini açıkça belirtmektedir. Bu şık doğrudan metinden çıkarılabilmektedir. Diğer seçenekler metinde yer almayan nedenler sunmaktadır."
    },
    {
        soru: "\"Hiçbir özgür insan, kendi eşitleri tarafından gerçekleştirilen yasal bir yargılama ya da ülkenin yasası olmaksızın tutuklanamaz, hapsedilemez, haklarından yoksun bırakılamaz, sürgün edilemez veya herhangi bir biçimde zarara uğratılamaz; biz de ona karşı kuvvet kullanamayız ya da başkalarına kullandırtamayız.\"\n— Magna Carta, 1215 (Madde 39)\n\nMetne göre Magna Carta'nın siyasi açıdan en temel katkısı nedir?",
        secenekler: [
            "Monarşinin yetkilerini genişletmesi",
            "Kilisenin siyasi otoritesini anayasal güvenceye kavuşturması",
            "Hükümdar iktidarını hukuki güvencelerle sınırlandırması",
            "Serfliği kaldırarak tüm sınıflara özgürlük tanıması",
            "Parlamentonun kurulmasını doğrudan emretmesi"
        ],
        cevap: "Hükümdar iktidarını hukuki güvencelerle sınırlandırması",
        aciklama: "Alıntı, 'yasal yargılama olmaksızın' bireyin tutuklanamayacağını belirterek iktidarın hukuk tarafından sınırlandırılması ilkesini ortaya koymaktadır. A seçeneği metinle tamamen çelişmekte; D ve E seçeneklerindeki iddialar ise Magna Carta'nın kapsamı dışında kalmaktadır."
    },
    {
        soru: "\"Haçlı Seferleri, basit bir Hristiyan-Müslüman çatışmasının ötesinde, Orta Çağ Avrupası'nın iç dinamiklerine dair önemli ipuçları sunar. Toprak arayan soyluların hesapları, ticaret yollarını güvence altına almak isteyen tüccarlar ve ruhani bir yenilenme arayan din adamlarının çıkarları, bu seferlerin karmaşık motivasyon yapısını oluşturuyordu.\"\n— Jonathan Riley-Smith, The Crusades: A History, Yale University Press, 2005\n\nMetne göre Haçlı Seferlerini açıklamakta yalnızca dinî motivasyon tezinin yetersiz kalmasının nedeni nedir?",
        secenekler: [
            "Haçlı Seferlerinin dini kurumlar tarafından hiç desteklenmemiş olması",
            "Seferlere katılanların büyük çoğunluğunun Müslüman olması",
            "Toprak, ticaret ve dinî çıkarlar gibi birden fazla motivasyonun bir arada bulunması",
            "Haçlı Seferlerinin yalnızca Orta Doğu'yu değil Orta Asya'yı da hedeflemiş olması",
            "Seferlerin dinî değil yalnızca ekonomik sonuçlar doğurmuş olması"
        ],
        cevap: "Toprak, ticaret ve dinî çıkarlar gibi birden fazla motivasyonun bir arada bulunması",
        aciklama: "Metin, toprak, ticaret ve dinî motivasyonların bir arada bulunduğuna dikkat çekerek tek bir açıklamanın yetersizliğini ortaya koymaktadır. Tarihsel olayları çok nedenli düşünme becerisi bu soruyla sınanmaktadır. A seçeneği metinle çelişmektedir."
    },
    {
        soru: "\"1453'te Konstantinopolis'in düşüşü, Orta Çağ siyasi düzeninin simgesel kapanışı sayılabilir. Bin yılı aşkın süredir Doğu Roma mirasını taşıyan Bizans İmparatorluğu'nun sona ermesi yalnızca bir şehrin kaybedilmesi değil; bir uygarlığın, bir yönetim geleneğinin ve kültürel belleğin tasfiyesiydi.\"\n— John Julius Norwich, Byzantium: The Decline and Fall, Knopf, 1995\n\nMetne göre Konstantinopolis'in düşüşünün 'simgesel' olarak nitelenmesinin nedeni nedir?",
        secenekler: [
            "Düşüşün gerçek değil efsanevi bir olay olarak aktarılması",
            "Şehrin fiziksel olarak tamamen yıkılmış olması",
            "Düşüşün yalnızca askeri değil; bir medeniyetin ve yönetim geleneğinin sonlanmasını temsil etmesi",
            "Konstantinopolis'in Orta Doğu ticaretindeki rolünün kalıcı olarak sona ermesi",
            "Bizans İmparatorluğu'nun daha önce de benzer yıkımlarla defalarca karşılaşmış olması"
        ],
        cevap: "Düşüşün yalnızca askeri değil; bir medeniyetin ve yönetim geleneğinin sonlanmasını temsil etmesi",
        aciklama: "'Simgesel' ifadesi, olayın somut siyasi sona ermenin ötesinde daha geniş bir medeniyetin kapanışını temsil ettiğine işaret etmektedir. Metin bu geniş kapsamı 'uygarlık, yönetim geleneği, kültürel bellek' üçlüsüyle pekiştirmektedir. Öğrenciden sembolik ve gerçek düzeyler arasında ayrım yapması beklenmektedir."
    },
    {
        soru: "\"Orta Çağ şövalyeliği, yalnızca bir savaş tekniği değil; aynı zamanda ayrıntılı bir davranış kuralları bütünüydü. Sadakat, cesaret ve dinî bağlılık gibi erdemler üzerine inşa edilen bu ideal, gerçek hayatta her zaman karşılık bulmasa da dönemin siyasi kültürünü derinden şekillendirdi.\"\n— Thomas Asbridge, The Greatest Knight, Free Press, 2015\n\nMetne göre şövalyelik idealinin Orta Çağ siyasi kültürü üzerindeki etkisi nasıl değerlendirilebilir?",
        secenekler: [
            "Şövalyelik ideali, pratikte tam uygulandığı için siyasi kültürü doğrudan belirledi.",
            "Şövalyelik yalnızca bir savaş yöntemi olduğu için siyasi alandan bağımsız kaldı.",
            "İdeal, gerçekte tam karşılık bulmasa da dönemin siyasi değerlerini ve kültürünü biçimlendirdi.",
            "Şövalyelik ideali, Orta Çağ siyasetinde hiçbir işlevsel rol oynamadı.",
            "Şövalyelik anlayışı, siyasi iktidarı kiliseden alarak soylulara aktardı."
        ],
        cevap: "İdeal, gerçekte tam karşılık bulmasa da dönemin siyasi değerlerini ve kültürünü biçimlendirdi.",
        aciklama: "Metin, idealin 'gerçek hayatta her zaman karşılık bulmasa da' siyasi kültürü biçimlendirdiğini belirtmektedir. Bu, idealin pratikten bağımsız olarak normatif bir işlev gördüğüne işaret etmektedir. A seçeneği metnin 'her zaman karşılık bulmayan' vurgusunu görmezden gelmektedir."
    },
    {
        soru: "\"Moğol İmparatorluğu'nun yükselişi, Orta Çağ dünyasının siyasi dengesini tek başına alt üst edecek güce sahip bir olguydu. Moğollar, hem İslam dünyasının siyasi merkezlerini yerle bir etti hem de Avrupa'nın doğu sınırlarını tehdit ederek Hristiyan hükümdarları ile diplomatik temas kurmaya zorladı.\"\n— Steven Runciman, A History of the Crusades, Cambridge University Press, 1951\n\nMetne göre Moğol İmparatorluğu'nun Orta Çağ dünyasına etkisi hangi açıdan en kapsamlıdır?",
        secenekler: [
            "Yalnızca İslam dünyasını etkileyen tek yönlü bir tahribat yaratması",
            "Hem Müslüman hem de Hristiyan siyasi yapıları etkileyen çok cepheli bir dönüşüm yaratması",
            "Moğolların Avrupa'yı tamamen fethederek Hristiyan devletlere son vermesi",
            "Ticaret yollarını kapatarak dünya ekonomisini çöküşe sürüklemesi",
            "Yalnızca askeri tahribat yaratıp siyasi dönüşüm üretmemesi"
        ],
        cevap: "Hem Müslüman hem de Hristiyan siyasi yapıları etkileyen çok cepheli bir dönüşüm yaratması",
        aciklama: "Metin, Moğolların hem İslam dünyasını hem de Hristiyan Avrupa'nın doğu sınırlarını etkilediğini belirtmektedir. Bu iki yönlü etki, cevabı A'nın 'yalnızca İslam dünyası' sınırlamasından ayıran temel unsurdur. C seçeneği ise metinde geçen 'tehdit' düzeyini aşarak yanlış bir sonuç sunmaktadır."
    },
    {
        soru: "\"Orta Çağ savaşlarında stratejik hedefleri belirleme biçimi, modern anlayıştan köklü biçimde ayrılıyordu. Ordu toplama, ikmal hatlarını sürdürme ve kalenin savunulması ya da ele geçirilmesi; salt savaş meydanı zaferlerinden çok daha belirleyiciydi. Bu bağlamda pek çok savaş, düşmanın fiziksel imhasından ziyade yıpratma ve kaynakları tüketme stratejileri etrafında şekillendi.\"\n— Philip Contamine, War in the Middle Ages, Basil Blackwell, 1984\n\nMetne göre Orta Çağ savaş anlayışının modern savaştan ayrılan en temel özelliği nedir?",
        secenekler: [
            "Süvari birliklerinin her savaşta kesin zafer kazandırması",
            "Dinî motivasyonun her savaşın merkezinde yer alması",
            "Zaferin savaş meydanı çatışması yerine ikmal, yıpratma ve kale stratejileriyle sağlanması",
            "Büyük kara ordularının deniz kuvvetlerine sürekli üstünlük sağlaması",
            "Haçlı Seferlerinin Orta Çağ savaş tekniklerini kökten dönüştürmesi"
        ],
        cevap: "Zaferin savaş meydanı çatışması yerine ikmal, yıpratma ve kale stratejileriyle sağlanması",
        aciklama: "Metin, Orta Çağ stratejisinin 'salt savaş meydanı zaferlerinden çok daha fazlasına', yani ikmal, yıpratma ve kale stratejilerine yaslandığını vurgulamaktadır. Bu soru öğrenciden 'modern savaş' kavramıyla kıyaslamalı bir analiz yapmasını ve Orta Çağ'a özgü stratejik mantığı metinden çıkarmasını beklemektedir."
    },
    {
        soru: "\"Oratores, bellatores ve laboratores; yani dua edenler, savaşanlar ve çalışanlar. 11. yüzyılda şekillenen bu üçlü toplumsal şema, yalnızca bir sınıflandırma girişimi değil, aynı zamanda mevcut iktidar ilişkilerini kutsayan ideolojik bir araçtı. Bu şema, toplumsal hiyerarşiyi doğal ve değiştirilemez göstererek hem meşrulaştırıyor hem de pekiştiriyordu.\"\n— Georges Duby, The Three Orders: Feudal Society Imagined, University of Chicago Press, 1978\n\nDuby'e göre Orta Çağ'ın üçlü toplumsal şemasının esas işlevi nedir?",
        secenekler: [
            "Üç sınıf arasındaki ekonomik farklılıkları pratik olarak azaltmak",
            "Din adamlarının siyasi üstünlüğünü kural koyarak güvence altına almak",
            "Var olan iktidar hiyerarşisini doğallaştırarak meşrulaştıran ideolojik bir araç işlevi görmek",
            "Toplumun her üyesine eşit görev ve haklar tanımak",
            "Savaşçı sınıfın kilise üzerindeki denetimini ideolojik açıdan pekiştirmek"
        ],
        cevap: "Var olan iktidar hiyerarşisini doğallaştırarak meşrulaştıran ideolojik bir araç işlevi görmek",
        aciklama: "Duby, üçlü şemanın yalnızca betimleyici değil normatif ve ideolojik bir işlev gördüğünü savunmaktadır: hiyerarşiyi 'doğal ve değiştirilemez' göstermek, onu hem meşrulaştırmak hem de pekiştirmektir. Bu soru öğrenciden 'ideoloji' kavramını sosyal bilimsel anlamda kavramasını ve metni eleştirel bir çerçevede okumasını beklemektedir."
    },
    {
        soru: "\"13. yüzyılda İpek Yolu yalnızca Çin'i Akdeniz dünyasına bağlamıyordu; bu güzergâh üzerinde konaklayan kentler, birden fazla medeniyetin kesişim noktasına dönüşerek canlı bir ticaret ve kültür ağının düğümlerini oluşturuyordu.\"\n— Janet Abu-Lughod, Before European Hegemony: The World System A.D. 1250–1350, Oxford University Press, 1989\n\nMetne göre İpek Yolu güzergâhındaki kentlerin önemi nereden kaynaklanıyordu?",
        secenekler: [
            "Bu kentlerin yalnızca ticari depo işlevi görmesinden",
            "Bu kentlerin farklı medeniyetlerin buluştuğu kültürel ve ticari düğüm noktaları olmasından",
            "Bu kentlerin İpek Yolu'na erişimi tekelinde bulundurmasından",
            "Bu kentlerin Çin mallarını Avrupa pazarlarına doğrudan nakletmesinden",
            "Bu kentlerin yalnızca askeri amaçlarla kurulmuş olmasından"
        ],
        cevap: "Bu kentlerin farklı medeniyetlerin buluştuğu kültürel ve ticari düğüm noktaları olmasından",
        aciklama: "Metin, kentlerin 'birden fazla medeniyetin kesişim noktası' ve 'ticaret ile kültür ağının düğümleri' olduğunu açıkça belirtmektedir. Diğer seçenekler ticari ya da askeri işlevi tek başına ön plana çıkarmakta; kültürel boyutu göz ardı etmektedir."
    },
    {
        soru: "\"Ortaçağ Akdeniz ticaretini inceleyen Kahire Geniza belgeleri, hem Müslüman hem de Yahudi tüccarların iç içe geçmiş ticari ağlar kurduğunu göstermektedir. Bu belgeler, Orta Çağ ticaretinin dinî sınırları aşan karmaşık ortaklık ve güven ilişkilerine dayandığını ortaya koymaktadır.\"\n— S. D. Goitein, A Mediterranean Society, University of California Press, 1967\n\nMetne göre Orta Çağ Akdeniz ticareti hakkında hangi sonuca ulaşılabilir?",
        secenekler: [
            "Ticaret yalnızca aynı dini inanca sahip topluluklar arasında yürütüldü.",
            "Ticari ilişkiler, dini farklılıkları aşan güven ve ortaklık ağları üzerine kuruluydu.",
            "Ticaret, devletlerin doğrudan müdahalesiyle merkezi olarak düzenleniyordu.",
            "Yahudi tüccarlar Müslümanlarla rekabet ederek onları piyasadan dışladı.",
            "Geniza belgeleri yalnızca Müslüman tüccarların faaliyetlerini kayıt altına aldı."
        ],
        cevap: "Ticari ilişkiler, dini farklılıkları aşan güven ve ortaklık ağları üzerine kuruluydu.",
        aciklama: "Metin açıkça hem Müslüman hem Yahudi tüccarların 'iç içe geçmiş ticari ağlar' kurduğunu ve bunun 'dinî sınırları aşan' güven ilişkilerine dayandığını belirtmektedir. A seçeneği metinle doğrudan çelişmektedir. E seçeneği ise metindeki 'hem... hem de...' vurgusunu tek bir topluluğa indirgeyerek yanlış bir sonuç vermektedir."
    },
    {
        soru: "\"11. ve 13. yüzyıllar arasında Avrupa'da yaşanan ticari devrim, yalnızca alışveriş hacmindeki artışla değil, kurumsal dönüşümlerle de kendini gösterdi. Ortaklık sözleşmeleri, kredi araçları ve sigorta benzeri mekanizmalar, tüccarların riski paylaşmasına ve sermayeyi daha verimli kullanmasına olanak tanıdı.\"\n— Robert S. Lopez, The Commercial Revolution of the Middle Ages, Cambridge University Press, 1976\n\nMetne göre Orta Çağ ticaret devrimini önceki dönemlerden ayıran en önemli özellik nedir?",
        secenekler: [
            "Yalnızca ticaret hacminin büyümesi",
            "Ticaretin yalnızca loncalar aracılığıyla örgütlenmesi",
            "Ortaklık, kredi ve risk paylaşımı gibi kurumsal yeniliklerin ortaya çıkması",
            "Ticaretin kilise denetiminden tamamen kurtulması",
            "Tüccarların devlet yönetimine doğrudan katılmaya başlaması"
        ],
        cevap: "Ortaklık, kredi ve risk paylaşımı gibi kurumsal yeniliklerin ortaya çıkması",
        aciklama: "Metin devrim niteliğindeki değişimi 'yalnızca hacim artışıyla değil, kurumsal dönüşümlerle' açıklamaktadır. A seçeneği metnin bizzat dışladığı 'yalnızca hacim' yorumunu tekrar etmektedir. Diğer şıklardaki iddialar metinde yer almamaktadır."
    },
    {
        soru: "\"Hansa Birliği, salt ekonomik bir ortaklıktan fazlasıydı. Kuzey Avrupa'nın ticaret kentlerini bir araya getiren bu yapı, ortak hukuki standartlar, ticari ayrıcalıklar ve zaman zaman askerî dayanışma yoluyla üye kentlerin çıkarlarını savunan yarı siyasi bir kurum kimliğine büründü.\"\n— Philippe Dollinger, The German Hansa, Stanford University Press, 1970\n\nMetne göre Hansa Birliği'ni salt bir ticaret örgütünden ayıran temel özellik nedir?",
        secenekler: [
            "Birliğin yalnızca Alman kentleri arasında oluşturulmuş olması",
            "Ortak hukuki standartlar, askerî dayanışma ve yarı siyasi işlevler üstlenmesi",
            "Birlik üyelerinin dini amaçlarla bir araya gelmiş olması",
            "Ticaret hacimleri bakımından Akdeniz ticaretine üstün gelmesi",
            "Hansa'nın merkezi bir monarşi tarafından yönetilmesi"
        ],
        cevap: "Ortak hukuki standartlar, askerî dayanışma ve yarı siyasi işlevler üstlenmesi",
        aciklama: "Metin 'salt ekonomik ortaklıktan fazlası' ifadesiyle birliğin hukuki, askerî ve yarı siyasi boyutlarına dikkat çekmektedir. Diğer seçenekler ya metinde geçmeyen ya da metinle çelişen bilgiler içermektedir."
    },
    {
        soru: "\"Büyük Han'ın topraklarında yollar o denli güvenli ve bakımlıydı ki bir tüccar, altın dolu bir kese ile ülkenin bir ucundan öbür ucuna yalnız başına yürüyebilir ve en ufak bir zarar görmeden geri dönebilirdi.\"\n— Marco Polo, The Travels of Marco Polo, çev. Ronald Latham, Penguin Classics, 1958\n\nMetne göre Marco Polo'nun aktardıkları ışığında Moğol hâkimiyetindeki ticaret koşulları hakkında ne söylenebilir?",
        secenekler: [
            "Ticaret, ağır vergi yükleri nedeniyle son derece zorlaşmıştı.",
            "Güvenlik ve ulaşım altyapısı, ticaretin gelişmesine elverişli koşullar sunuyordu.",
            "Yalnızca Çinli tüccarlara bu güzergâhlarda ticaret yapma izni veriliyordu.",
            "Moğol yönetimi ticaret yollarını kasıtlı olarak tahrip etti.",
            "Marco Polo'nun anlattıkları daha sonraki kaynaklarca geçersiz sayıldı."
        ],
        cevap: "Güvenlik ve ulaşım altyapısı, ticaretin gelişmesine elverişli koşullar sunuyordu.",
        aciklama: "Metin, yolların güvenliğini ve bakımlılığını somut bir örnekle gözler önüne sermiştir. Bir tüccarın altın dolu kese ile yalnız başına yolculuk yapabilmesi, hem fiziksel altyapıyı hem de güvenlik koşullarını simgelemektedir. Diğer seçenekler metinle çelişmektedir."
    },
    {
        soru: "\"14. yüzyılda Kara Veba'nın Orta Asya ticaret güzergâhları üzerinden Avrupa'ya taşınması, ticaret ağlarının yalnızca mal değil hastalık da taşıyabileceğini dramatik biçimde kanıtladı. Bu süreç, Doğu-Batı bağlantısının ne denli derinlere kök salmış olduğunu gözler önüne serdi; fakat aynı zamanda bu bağlantının yıkıcı bir potansiyel barındırdığını da ortaya koydu.\"\n— Janet Abu-Lughod, Before European Hegemony, Oxford University Press, 1989\n\nMetne göre Kara Veba'nın ticaret yolları aracılığıyla yayılması, Orta Çağ ticaret ağları hakkında hangi çok boyutlu çıkarımı en iyi destekler?",
        secenekler: [
            "Ticaret ağları yalnızca ekonomik değil sağlık politikasını da doğrudan belirleyebilirdi.",
            "Ticaret ağları hastalık taşıyabileceğinden derhal kapatılması gerekiyordu.",
            "Kara Veba'nın yayılmasından yalnızca Asya ticaret kentleri sorumluydu.",
            "Ticaret ağlarının derinden bütünleşmiş olması hem fırsatlar hem de yıkıcı riskler barındırıyordu.",
            "Veba salgını, Doğu-Batı ticaret bağlantısını kalıcı olarak kopardı."
        ],
        cevap: "Ticaret ağlarının derinden bütünleşmiş olması hem fırsatlar hem de yıkıcı riskler barındırıyordu.",
        aciklama: "Metin ticaret ağlarının bütünleşmişliğini hem olumlu (Doğu-Batı bağlantısı) hem de olumsuz (yıkıcı potansiyel) boyutlarıyla sunmaktadır. A seçeneği çıkarımı daraltarak yalnızca sağlık politikası boyutuna indirgemektedir. E seçeneği ise metinde geçmeyen ve tarihsel olarak yanlış olan bir iddia sunmaktadır. Bu soru öğrenciden karmaşık nedensellik ilişkilerini çok boyutlu okumasını beklemektedir."
    },
    {
        soru: "\"Bağdat'taki Bilgelik Evi, 9. yüzyılda dünyanın dört bir yanından bilginleri bünyesine katarak Yunan, Hint ve İran bilimsel mirasını Arapçaya aktardı. Bu çeviri hareketi, yalnızca bilginin korunmasını değil; matematikten astronomiye, tıptan felsefiye uzanan alanlarda özgün katkıların üretilmesini de sağladı.\"\n— Jim Al-Khalili, The House of Wisdom: How Arabic Science Saved Ancient Knowledge, Penguin, 2011\n\nMetne göre Bağdat Bilgelik Evi'nin Orta Çağ bilim tarihindeki temel önemi nedir?",
        secenekler: [
            "Bilgelik Evi yalnızca Yunan bilimini Arapçaya çevirerek korudu.",
            "Bilgelik Evi'nde üretilen bilgi yalnızca dinî amaçlarla kullanıldı.",
            "Bilgelik Evi hem eski bilgi birikimini korudu hem de özgün bilimsel katkılar üretti.",
            "Bilgelik Evi, Hint ve İran bilimini reddederek özgün çalışmalara odaklandı.",
            "Bilgelik Evi'nin önemi 10. yüzyıldan itibaren tamamen ortadan kalktı."
        ],
        cevap: "Bilgelik Evi hem eski bilgi birikimini korudu hem de özgün bilimsel katkılar üretti.",
        aciklama: "Metin hem 'bilginin korunması' hem de 'özgün katkıların üretilmesi' olmak üzere iki boyutu açıkça dile getirmektedir. A seçeneği yalnızca çeviri boyutunu vurgulayarak ikinci boyutu dışlamaktadır. D seçeneği ise metindeki 'Yunan, Hint ve İran' üçlüsünü çarpıtmaktadır."
    },
    {
        soru: "\"Asabiye, yani toplumsal dayanışma duygusu, siyasi iktidarın özüdür. Güçlü bir asabiyeye sahip topluluklar devlet kurar ve medeniyetler inşa eder; bu ruh zayıflayınca refah ve lüks içinde çürüme başlar, sonunda daha güçlü bir asabiyeye sahip yeni bir topluluk onların yerini alır.\"\n— İbn Haldun, Mukaddime, çev. Franz Rosenthal, Princeton University Press, 1967\n\nİbn Haldun'un asabiye kavramına göre medeniyetlerin çöküşünün temel nedeni nedir?",
        secenekler: [
            "Dış saldırıların kaçınılmaz biçimde her medeniyeti yıkması",
            "Ekonomik krizlerin her zaman siyasi çöküşü beraberinde getirmesi",
            "İktidarda uzun süre kalan toplulukların toplumsal dayanışma duygusunu yitirerek güçten düşmesi",
            "Dini inancın zayıflamasının siyasi çöküşü doğrudan tetiklemesi",
            "Coğrafi koşulların insan iradesi üzerinde belirleyici bir üstünlüğe sahip olması"
        ],
        cevap: "İktidarda uzun süre kalan toplulukların toplumsal dayanışma duygusunu yitirerek güçten düşmesi",
        aciklama: "İbn Haldun'a göre medeniyetin çöküşü bir döngünün parçasıdır: Güçlü asabiyeyle kurulan devlet, refah ve lüks içinde dayanışma ruhunu yitirir ve yerini daha güçlü bir asabiyeye sahip topluluk alır. Bu döngüsel tarih anlayışı diğer şıklardaki tek nedenli açıklamalardan temelden farklılaşmaktadır."
    },
    {
        soru: "\"Gotik mimari ile Skolastik felsefe arasındaki benzerlik tesadüfi değildir; her ikisi de parçaları şeffaf bir mantıksal düzen içinde bütünleştirme, bütünü parçalarına ayırabilme ve hiyerarşik bir uyum yaratma ilkesini paylaşmaktadır. Gotik katedral, taşa oyulmuş bir Skolastik Summa'dır.\"\n— Erwin Panofsky, Gothic Architecture and Scholasticism, Meridian Books, 1951\n\nPanofsky'e göre Gotik mimari ile Skolastik düşünce arasındaki temel benzerlik nedir?",
        secenekler: [
            "Her ikisinin de kilise inşasını doğrudan desteklemesi",
            "Her ikisinin de Antik Yunan geleneğine doğrudan ve birebir dayanması",
            "Her ikisinin de parçaları hiyerarşik ve mantıksal bir bütünlük içinde örgütleme ilkesini paylaşması",
            "Her ikisinin de İslam bilimine ve estetiğine özgün bir yanıt olarak gelişmesi",
            "Her ikisinin de bireysel sanatçının ve filozofun özgürlüğünü ön plana çıkarması"
        ],
        cevap: "Her ikisinin de parçaları hiyerarşik ve mantıksal bir bütünlük içinde örgütleme ilkesini paylaşması",
        aciklama: "Panofsky, mimari ve felsefi düşüncenin biçimsel yapısındaki ortak ilkeyi —parçaları şeffaf biçimde hiyerarşik bir bütüne örgütlemek— tespit etmektedir. 'Summa' metaforu bu ilkeyi kristalize etmektedir. Bu soru öğrenciden biçim-içerik ilişkisini sanat tarihi ve felsefe arasında kurabilen analitik düşünme becerisi beklemektedir."
    },
    {
        soru: "\"Kütüphane bir labirentti; ama aynı zamanda dünyanın bir imgesi... Kitaplar yalnızca yazılı söz değil, onları koruyanların iktidarını simgeliyordu. Bilgiye erişimi denetlemek, ruhları denetlemek demekti.\"\n— Umberto Eco, Gülün Adı (The Name of the Rose), 1980\n\nEco'nun bu pasajından hareketle Orta Çağ'da bilgiye erişimin denetlenmesi hakkında hangi yorum yapılabilir?",
        secenekler: [
            "Orta Çağ'da kütüphaneler herkese açık, eşitlikçi bilgi mekânlarıydı.",
            "Bilginin denetimi yalnızca kişisel merakı sınırlamanın pratik bir aracıydı.",
            "Bilgiye erişimin kısıtlanması, toplumsal ve siyasi iktidarı sürdürmenin bir aracıydı.",
            "Kütüphaneler Orta Çağ'da yalnızca dinî metinleri barındıran tarafsız mekânlardı.",
            "Bilgi denetimi Orta Çağ'a özgü bir olgu olup başka dönemlerde hiç görülmedi."
        ],
        cevap: "Bilgiye erişimin kısıtlanması, toplumsal ve siyasi iktidarı sürdürmenin bir aracıydı.",
        aciklama: "Metin 'bilgiye erişimi denetlemek = ruhları denetlemek' eşitliğini kurmakta; bilgiyi bir iktidar aracı olarak konumlandırmaktadır. Bu, Michel Foucault'nun bilgi-iktidar ilişkisi bağlamıyla da örtüşmektedir. Öğrenciden edebi bir metni siyasi-tarihsel çerçevede yorumlaması beklenmektedir."
    },
    {
        soru: "\"Orta Çağ'ın sonlarında Avrupa'da coğrafya bilgisinin dönüşümü, yalnızca teknik bir gelişme değil; dünya algısının ve insanlığın evrende konumlanışının köklü bir yeniden tanımlanmasıydı. Eski ve yeni bilginin sentezinden doğan haritalar, bilinmeyeni hem korkutucu hem de cazip kılıyordu.\"\n— Toby Lester, The Fourth Part of the World, Free Press, 2009\n\nMetne göre Orta Çağ sonunda Avrupa'da coğrafya bilgisinin dönüşümü ne anlama geliyordu?",
        secenekler: [
            "Yalnızca teknik navigasyon sorunlarına pratik çözümler üretilmesini sağladı.",
            "Bu dönüşüm, insanların dünyayı ve evreni algılayış biçimini temelden değiştiren entelektüel bir süreçti.",
            "Yeni coğrafi bilgiler Orta Çağ Avrupası'nda tam anlamıyla reddedildi ve benimsenmedi.",
            "Coğrafi keşifler yalnızca ticaret güzergâhlarının belirlenmesinde kullanıldı.",
            "Coğrafya bilgisi yalnızca din adamlarının tekelinde kaldı ve halk kesimine hiç yansımadı."
        ],
        cevap: "Bu dönüşüm, insanların dünyayı ve evreni algılayış biçimini temelden değiştiren entelektüel bir süreçti.",
        aciklama: "Metin coğrafi dönüşümü 'yalnızca teknik' olmayan, 'dünya algısını ve insanlığın konumlanışını köklü biçimde yeniden tanımlayan' bir süreç olarak nitelendirmektedir. A seçeneği, metnin bizzat dışladığı 'yalnızca teknik' yorumunu tekrarlamaktadır. Diğer şıklar ise metinde desteklenmeyen yorumlar sunmaktadır."
    },
    {
        soru: "\"12. yüzyıl, Avrupa'da entelektüel bir uyanışa sahne oldu. İslam dünyasından yapılan çeviriler, antik Yunan felsefesini ve bilimini Latin okuyuculara ulaştırırken üniversitelerin kuruluşu bu yeni bilgi birikiminin kurumsal çerçevesini oluşturdu.\"\n— C. H. Haskins, The Renaissance of the Twelfth Century, Harvard University Press, 1927\n\nMetne göre 12. yüzyıl Avrupa'sındaki entelektüel uyanışın temel kaynakları nelerdir?",
        secenekler: [
            "Bizans İmparatorluğu'nun kültürel mirasının doğrudan aktarımı",
            "Avrupa'nın dış etkilerden bağımsız olarak ürettiği özgün bilim",
            "İslam dünyasından gelen çeviriler ve üniversitelerin kuruluşu",
            "Haçlı Seferlerinin beraberinde getirdiği savaş teknolojisi yenilikleri",
            "Moğol istilasının Orta Asya bilginlerini Avrupa'ya sürmesi"
        ],
        cevap: "İslam dünyasından gelen çeviriler ve üniversitelerin kuruluşu",
        aciklama: "Metin iki kaynağı açıkça belirtmektedir: İslam dünyasından yapılan çeviriler ve üniversitelerin kuruluşu. Diğer seçeneklerin hiçbiri metinde yer almamaktadır; A, D ve E'nin anlattıkları ise tarihsel açıdan da 12. yüzyıl uyanışının temel kaynakları değildir."
    },
    {
        soru: "\"Selahaddin'in sarayı, kılıcın yanı sıra kalemin de hüküm sürdüğü bir yerdi. Şairler, matematikçiler ve hekimler, komutanlar kadar itibar görürdü; çünkü büyük bir devlet yalnızca toprak değil, bilgi ve güzellik de üretmek zorundaydı.\"\n— Tariq Ali, The Book of Saladin (Selahaddin'in Kitabı), Verso, 1998\n\nMetne göre Selahaddin'in yönetim anlayışı hakkında hangi çıkarım yapılabilir?",
        secenekler: [
            "Selahaddin yalnızca askerî zaferlerle ilgilenip kültürel alana hiç önem vermedi.",
            "Güçlü bir devlet inşası için askerî güçle birlikte bilim ve sanatın desteklenmesi gerekir.",
            "Selahaddin şair ve bilginleri saraydan uzaklaştırarak askeri disiplini ön plana çıkardı.",
            "Bilim ve sanat yalnızca barış dönemlerinde desteklenebilir.",
            "Selahaddin'in sarayında yalnızca İslam geleneğinden gelen bilginlere yer verildi."
        ],
        cevap: "Güçlü bir devlet inşası için askerî güçle birlikte bilim ve sanatın desteklenmesi gerekir.",
        aciklama: "Metin, kılıcın ve kalemin yan yana yer aldığı bir saray imgesi çizerek hem askerî hem de entelektüel/kültürel boyutların bir arada varlığını vurgulamaktadır. 'Büyük bir devlet yalnızca toprak değil, bilgi ve güzellik de üretmek zorundaydı' cümlesi bu anlayışı doğrudan ifade etmektedir."
    },
    {
        soru: "\"Orta Çağ estetiği bir çelişkiyi barındırıyordu: Bir yanda güzelliğin Tanrı'nın parlaklığı olduğu anlayışı ve duyusal zevklerden uzak durma çabası; öte yanda renk, ışık ve biçimin bu kadar özenle işlendiği katedral sanatı ve el yazmaları. Bu gerilim, bir çelişki değil; güzelliğin hem aşkın hem de maddi dünyada var olabileceğine dair inancın üretken paradoksuydu.\"\n— Umberto Eco, Art and Beauty in the Middle Ages, Yale University Press, 1986\n\nEco'ya göre Orta Çağ sanatındaki görünür estetik gerilim nasıl yorumlanmalıdır?",
        secenekler: [
            "Bu gerilim, din adamlarının sanatçılar üzerindeki baskısından kaynaklanıyordu.",
            "Orta Çağ sanatçıları bilinçsizce hem dinî hem de dünyevi unsurları bir arada kullandı.",
            "Gerilim, güzelliğin hem aşkın hem de maddi dünyada var olabileceği inancının üretken paradoksuydu.",
            "Orta Çağ kilisesi sanatı yasakladığı için sanatçılar gizlice eserler üretmek zorunda kaldı.",
            "Duyusal güzelliği ön plana çıkaran sanat, Orta Çağ'da yalnızca laik çevrelerde üretildi."
        ],
        cevap: "Gerilim, güzelliğin hem aşkın hem de maddi dünyada var olabileceği inancının üretken paradoksuydu.",
        aciklama: "Eco, görünürdeki çelişkinin aslında bir paradoks olduğunu savunmakta; güzelliğin hem aşkın (ilahi) hem de maddi bir gerçeklik olarak kavrandığı Orta Çağ teolojisinin bu gerilimi üretken kıldığını öne sürmektedir. 'Üretken paradoks' ifadesi, çelişkinin sanatsal yaratıcılığın motoru olduğuna işaret etmektedir. Bu soru öğrenciden estetik, teoloji ve sanat tarihini birleştiren bütünleşik bir analiz yapmasını beklemektedir."
    }
];

window.allTests["test_u3_genel_2"] = [
    {
        soru: "\"Slavların güneye ve batıya doğru yayılması, 6. ve 7. yüzyıllarda Balkan yarımadasının demografik çehresini köklü biçimde dönüştürdü. Bu topluluklar gittiği yerlerde kalıcı yerleşimler kurdu; böylece yüzyıllar içinde şekillenen Roma-Bizans kentsel düzeni, kırsal ve köy temelli yeni bir örgütlenmeyle yer değiştirdi.\"\n— Florin Curta, The Making of the Slavs, Cambridge University Press, 2001\n\nMetne göre Slav göçlerinin Balkan yarımadasındaki en belirgin etkisi nedir?",
        secenekler: [
            "Balkanlar'da Bizans kentsel yönetiminin güçlenmesi",
            "Bölgedeki Roma-Bizans kentsel düzeninin kırsal ve köy temelli bir yapıya dönüşmesi",
            "Slav topluluklarının Balkanlar'a yerleşmeyip yalnızca geçici konaklamalar kurması",
            "Demografik dönüşümün yalnızca kıyı bölgelerinde yaşanması",
            "Slav göçlerinin Bizans ordusunu güçlendirmesi"
        ],
        cevap: "Bölgedeki Roma-Bizans kentsel düzeninin kırsal ve köy temelli bir yapıya dönüşmesi",
        aciklama: "Metin, Slav yerleşimlerinin 'Roma-Bizans kentsel düzenini kırsal ve köy temelli örgütlenmeyle yer değiştirdiğini' açıkça belirtmektedir. Bu ifade doğrudan B seçeneğine karşılık gelmektedir. A seçeneği metinle çelişmekte, C seçeneği ise metnin 'kalıcı yerleşimler kurdu' ifadesini görmezden gelmektedir."
    },
    {
        soru: "\"Arap fethinin hızı ve kapsamı, yalnızca askerî üstünlükle açıklanamaz. Fethedilen topraklarda zaten var olan siyasi yorgunluk, vergi baskısı altındaki halklar ve mezhep çatışmalarıyla bölünmüş Doğu Roma ile Sasani imparatorlukları, Arap ordularının önünde beklenmedik ölçüde kırılgan bir zemin bırakmıştı.\"\n— Hugh Kennedy, The Great Arab Conquests, Da Capo Press, 2007\n\nMetne göre Arap fetihlerinin bu denli hızlı gerçekleşmesini açıklamada hangi etken göz ardı edilmemelidir?",
        secenekler: [
            "Arap ordularının sayıca büyük bir üstünlüğe sahip olması",
            "Fethedilen imparatorlukların siyasi, dinî ve ekonomik açıdan zaten zayıflamış olması",
            "İslam dininin yayılmak istediği topraklarda önceden hazırlık yapılmış olması",
            "Sasani ve Bizans ordularının Arapları önemsememesi",
            "Halkların Arap idaresini gönüllü olarak seçmiş olması"
        ],
        cevap: "Fethedilen imparatorlukların siyasi, dinî ve ekonomik açıdan zaten zayıflamış olması",
        aciklama: "Metin fethin hızını 'yalnızca askerî üstünlükle' açıklamanın yetersiz olduğunu öne sürmekte ve siyasi yorgunluk, vergi baskısı, mezhep çatışması gibi iç zayıflıkları ön plana çıkarmaktadır. Öğrenciden tarihsel olayları çok nedenli yorumlama becerisi beklenmektedir."
    },
    {
        soru: "\"Türklerin Orta Asya'dan batıya doğru hareketi salt bir askeri ilerleme değildi; bu göç dalgası beraberinde bozkır yaşam biçimini, hayvan yetiştirme pratiklerini ve göçebeliğe özgü siyasi kültürü taşıdı. Anadolu coğrafyasında yarı göçebe düzenin yerleşik uygarlıkla buluşması, özgün bir kültürel sentezin filizlenmesini sağladı.\"\n— Osman Turan, Selçuklular Tarihi ve Türk-İslam Medeniyeti, Ötüken Yayınları, 1969\n\nMetne göre Türklerin batıya göçünü salt askerî bir hareket olarak nitelendirmek neden yetersiz kalır?",
        secenekler: [
            "Türklerin yalnızca Bizans topraklarını değil Mısır'ı da hedeflemesi",
            "Bu göçün yaşam biçimi, ekonomik pratikler ve siyasi kültürü de beraberinde taşıması",
            "Türk ordularının dönemin en gelişmiş silahlarını kullanmış olması",
            "Türklerin göç sürecinde İslam dinini benimsememesi",
            "Anadolu'nun bu göçten önce tamamen boş ve ıssız olması"
        ],
        cevap: "Bu göçün yaşam biçimi, ekonomik pratikler ve siyasi kültürü de beraberinde taşıması",
        aciklama: "Metin, Türk göçünün beraberinde 'yaşam biçimi, hayvan yetiştirme pratikleri ve göçebe siyasi kültür' taşıdığını vurgulayarak salt askerî bir hareket olmadığını kanıtlamaktadır. Bu çok boyutlu etki, askerî açıklamanın yetersizliğinin temelidir."
    },
    {
        soru: "\"Normandiya'yı yurt edinen Vikingler, yalnızca bir nesil içinde Frankça konuşmaya başlamış ve yerel dini gelenekleri benimsemişti. Ne var ki Normanlar olarak adlandırılan bu topluluk, askerî disiplin ve denizcilik becerileri gibi kadim miraslarını yeni kimliklerine ustaca entegre etti.\"\n— David Crouch, The Normans: The History of a Dynasty, Hambledon Continuum, 2002\n\nMetne göre Normanların kısa sürede Franklaşması hangi açıdan tarihsel açıdan ilginç bir olgudur?",
        secenekler: [
            "Normanların tüm Viking geleneklerini tamamen terk etmesi",
            "Normanların dil ve din açısından asimile olurken özgün askeri miraslarını koruması",
            "Frankların Normanları zorla asimile etmesinin tarihin en hızlı kültürel dönüşümü olması",
            "Normanların Normandiya'yı hiçbir zaman kalıcı yurt olarak benimsememesi",
            "Bu asimilasyonun Normanları askerî açıdan tamamen güçsüz kılması"
        ],
        cevap: "Normanların dil ve din açısından asimile olurken özgün askeri miraslarını koruması",
        aciklama: "Metin iki boyutu bir arada sunmaktadır: dil ve din açısından hızlı asimilasyon ile askerî disiplin ve denizciliğin korunması. Bu ikili yapı, kültürel uyum süreçlerinde seçici benimsemenin nasıl işlediğini örneklemektedir. A seçeneği 'tamamen terk etme' iddiasıyla metinle çelişmektedir."
    },
    {
        soru: "\"Göç çalışmalarında sıkça yapılan bir yanlış, hareketi başlatan toplulukları 'aktif' fail, karşılaştıkları toplulukları ise 'pasif' mağdur olarak konumlandırmaktır. Oysa tarihsel kanıtlar, yerleşik toplulukların göçmen gruplarla müzakere ettiğini, onlara seçici biçimde kapı araladığını ya da aktif direnç gösterdiğini ortaya koymaktadır.\"\n— Guy Halsall, Barbarian Migrations and the Roman West, Cambridge University Press, 2007\n\nHalsall'ın eleştirisi hangi tarih yazımı sorununa işaret etmektedir?",
        secenekler: [
            "Göç çalışmalarının arkeolojik kanıtları yeterince kullanmamasına",
            "Göç anlatılarının göçmen toplulukları yüceltme eğiliminde olmasına",
            "Göç çalışmalarının yerleşik toplulukları edilgen kurban olarak konumlandırmasına ve karşılıklı etkileşimi göz ardı etmesine",
            "Orta Çağ tarihçilerinin yalnızca yazılı kaynaklara dayanmasına",
            "Göç hareketlerinin ekonomik boyutunun tarih yazımında hiç ele alınmamasına"
        ],
        cevap: "Göç çalışmalarının yerleşik toplulukları edilgen kurban olarak konumlandırmasına ve karşılıklı etkileşimi göz ardı etmesine",
        aciklama: "Halsall, yerleşik toplulukların müzakere ettiğini, seçici kapı araladığını ya da direnç gösterdiğini ortaya koyarak 'aktif fail – pasif mağdur' ikiliğini sorunsallaştırmaktadır. Bu soru öğrenciden tarih yazımının kavramsal araçlarını ve önyargılarını eleştirel biçimde sorgulamasını beklemektedir."
    },
    {
        soru: "\"Kara Ölüm salgını, 14. yüzyılda Avrupa nüfusunu yaklaşık üçte bir oranında azalttı. Bu demografik yıkım; köyden kente, tarımdan zanaate, serflikten özgür emeğe doğru dramatik toplumsal kaymalara zemin hazırladı. Nüfus azalmasının yarattığı emek kıtlığı, hayatta kalanların pazarlık gücünü beklenmedik biçimde artırdı.\"\n— William Chester Jordan, The Great Famine and the Black Death, Princeton University Press, 1996\n\nMetne göre Kara Ölüm'ün toplumsal sonuçları hakkında hangi yorum doğrudur?",
        secenekler: [
            "Kara Ölüm yalnızca kırsal nüfusu etkileyip kentleri görece korudu.",
            "Demografik yıkım, toplumsal hiyerarşinin değişmezliğini pekiştirdi.",
            "Nüfus azalması hayatta kalanların emek piyasasındaki konumunu güçlendirdi ve toplumsal dönüşümlere zemin hazırladı.",
            "Kara Ölüm toplumsal yapıyı yalnızca kısa vadede etkiledi ve hızla eski düzene dönüldü.",
            "Salgın yalnızca ekonomik değil öncelikle dinî bir kriz olarak yaşandı."
        ],
        cevap: "Nüfus azalması hayatta kalanların emek piyasasındaki konumunu güçlendirdi ve toplumsal dönüşümlere zemin hazırladı.",
        aciklama: "Metin, emek kıtlığının hayatta kalanların pazarlık gücünü artırdığını ve bu durumun toplumsal kaymalara —köyden kente, serflikten özgür emeğe— zemin hazırladığını açıklamaktadır. B seçeneği, metindeki dönüşüm dinamiğiyle doğrudan çelişmektedir."
    },
    {
        soru: "\"Endülüs'ün 711'de Müslüman kuvvetlerce fethinden sonra İberya Yarımadası'nda kendine özgü bir kültürel ekoloji oluştu. Araplar, Berberiler, Vizigotlar, Yahudiler ve yerli Hristiyanlar yüzyıllarca iç içe yaşadı; bu birliktelik zaman zaman gerilimli olsa da bilimsel ve sanatsal alanda olağanüstü bir üretkenlik doğurdu.\"\n— María Rosa Menocal, The Ornament of the World, Little, Brown and Company, 2002\n\nMetne göre Endülüs'teki çok kültürlü yapının en belirgin sonucu nedir?",
        secenekler: [
            "Endülüs'te tüm kültürel farklılıkların kısa sürede ortadan kalkması",
            "Çeşitli toplulukların bir arada yaşamasının bilimsel ve sanatsal alanda olağanüstü bir üretkenlik yaratması",
            "Müslüman kültürünün diğer tüm kültürleri tamamen asimile etmesi",
            "Endülüs'ün siyasi istikrarını bu çeşitliliğin engellemiş olması",
            "Yahudi ve Hristiyan toplulukların Endülüs kültürüne hiçbir katkıda bulunmaması"
        ],
        cevap: "Çeşitli toplulukların bir arada yaşamasının bilimsel ve sanatsal alanda olağanüstü bir üretkenlik yaratması",
        aciklama: "Metin, gerilimli de olsa bu birlikteliğin 'bilimsel ve sanatsal alanda olağanüstü bir üretkenlik doğurduğunu' açıkça belirtmektedir. A ve C seçenekleri, metnin vurguladığı çeşitliliğin sürekliliğini görmezden gelmektedir."
    },
    {
        soru: "\"Göç araştırmalarında 'barbar' kavramı, göç eden toplulukları medeniyetin karşısına konumlandıran ideolojik bir yük taşır. Roma kaynaklarından devralınan bu sözcük, onlarca yıl boyunca tarih yazımına bilinçsizce aktarıldı ve göçmen toplulukların kendi perspektiflerinden anlaşılmasını engelledi.\"\n— Patrick Geary, The Myth of Nations: The Medieval Origins of Europe, Princeton University Press, 2002\n\nGeary'nin eleştirisine göre 'barbar' kavramını tarih yazımında eleştirmeksizin kullanmanın temel sorunu nedir?",
        secenekler: [
            "Bu kavramın dilbilgisel açıdan yanlış kullanılması",
            "Kavramın yalnızca Germenlere uygulanıp Hunlara uygulanmaması",
            "Roma'nın ideolojik bakış açısını bilinçsizce yeniden üretmek ve göçmen toplulukları kendi perspektiflerinden anlamamak",
            "Tarihçilerin bu kavramla siyasi propaganda üretmesi",
            "'Barbar' kavramının göçlerin ekonomik boyutunu gizlemesi"
        ],
        cevap: "Roma'nın ideolojik bakış açısını bilinçsizce yeniden üretmek ve göçmen toplulukları kendi perspektiflerinden anlamamak",
        aciklama: "Geary, 'barbar' sözcüğünün Roma'nın egemen ideolojisini taşıdığını ve bu kavramın eleştirisiz aktarılmasının tarihçileri Roma merkezli bir bakış açısına hapsettiğini savunmaktadır. Bu soru öğrenciden tarih yazımındaki dil ve ideoloji ilişkisini kavramasını beklemektedir."
    },
    {
        soru: "\"Papa II. Urban'ın 1095'te Clermont'ta yaptığı konuşma, Birinci Haçlı Seferi'nin fitilini ateşledi. Papa; Kutsal Toprakları kurtarmayı, Hristiyanları birleştirmeyi ve Avrupa'nın iç savaşlarından yorulmuş şövalye sınıfına yeni bir çıkış yolu sunmayı bir arada hedefliyordu.\"\n— Thomas Asbridge, The First Crusade: A New History, Oxford University Press, 2004\n\nMetne göre Birinci Haçlı Seferi'nin başlatılmasında hangi faktörlerin bir araya geldiği söylenebilir?",
        secenekler: [
            "Yalnızca dinî motivasyon belirleyici oldu.",
            "Dinî, siyasi ve toplumsal faktörler bir arada etkili oldu.",
            "Şövalyelerin ekonomik kazanç elde etme isteği tek belirleyici etkendir.",
            "Papa'nın kişisel hırsı Haçlı Seferi'nin tek nedenidir.",
            "Seferin yalnızca Bizans'ı güçlendirme amacı taşıdığı açıktır."
        ],
        cevap: "Dinî, siyasi ve toplumsal faktörler bir arada etkili oldu.",
        aciklama: "Metin; Kutsal Topraklar (din), Hristiyan birliği (siyaset) ve şövalye sınıfının iç savaşlardan yorulması (toplumsal) olmak üzere üç farklı faktörü bir arada sunmaktadır. Yalnızca bir boyutu öne çıkaran diğer seçenekler bu çok nedenli tabloyu yansıtamamaktadır."
    },
    {
        soru: "\"Doğu Roma İmparatorluğu'nun bin yılı aşan varlığı, yalnızca askerî güce değil; büyük ölçüde esnek diplomasiye, vergi sisteminin etkinliğine ve Konstantinopolis'in coğrafi konumunun sunduğu stratejik üstünlüğe dayanıyordu. Bizans, zayıf göründüğünde dahi yeniden toparlanma kapasitesini korudu.\"\n— Judith Herrin, Byzantium: The Surprising Life of a Medieval Empire, Princeton University Press, 2007\n\nMetne göre Bizans'ın bin yıl boyunca ayakta kalabilmesinin temel nedeni nedir?",
        secenekler: [
            "Bizans'ın sürekli büyük askeri zaferler kazanması",
            "Diplomasi, vergi sistemi ve coğrafi konumun birlikte sunduğu çok boyutlu dayanıklılık",
            "Kilise ile siyasi iktidarın birbirinden tamamen bağımsız tutulması",
            "Bizans'ın İpek Yolu ticaretini tek başına denetlemesi",
            "Güçlü bir imparatorluk hanedanının kesintisiz sürmesi"
        ],
        cevap: "Diplomasi, vergi sistemi ve coğrafi konumun birlikte sunduğu çok boyutlu dayanıklılık",
        aciklama: "Metin, Bizans'ın dayanıklılığını üç farklı kaynağa bağlamaktadır: esnek diplomasi, vergi sisteminin etkinliği ve coğrafi stratejik üstünlük. 'Yalnızca askerî güce değil' ifadesi A seçeneğini açıkça dışlamaktadır."
    },
    {
        soru: "\"1215 sonrasında Magna Carta, İngiltere'de defalarca yeniden onaylandı ve içeriği her seferinde genişledi. Belge zaman içinde özgün hukuki içeriğinin ötesinde güçlü bir sembolik değer kazandı; keyfi yönetimin karşısında vatandaş haklarının simgesi hâline geldi.\"\n— David Carpenter, Magna Carta, Penguin Classics, 2015\n\nMetne göre Magna Carta'nın tarihsel etkisi nasıl değerlendirilebilir?",
        secenekler: [
            "Belge, yalnızca 1215 yılında hukuki önem taşıdı ve zamanla geçersiz sayıldı.",
            "Magna Carta'nın önemi yalnızca teknik hukuki içeriğiyle sınırlıdır.",
            "Belge hem tekrar onaylanarak genişledi hem de keyfi yönetime karşı simgesel bir değer kazandı.",
            "Magna Carta, Avrupa'daki tüm monarşiler için bağlayıcı bir anayasa niteliği taşıdı.",
            "Belge, halk tarafından değil yalnızca soylular tarafından sahiplenildi."
        ],
        cevap: "Belge hem tekrar onaylanarak genişledi hem de keyfi yönetime karşı simgesel bir değer kazandı.",
        aciklama: "Metin iki boyutu birlikte sunmaktadır: hem pratik hukuki gelişim (tekrar onaylanma ve genişleme) hem de sembolik işlev (keyfi yönetimin karşısında hak simgesi). B seçeneği, metnin açıkça vurguladığı sembolik boyutu görmezden gelmektedir."
    },
    {
        soru: "\"Orta Çağ İslam dünyasında halifelik kurumu, teoride dini ve siyasi otoriteyi aynı anda temsil ediyordu. Ne var ki pratikte halifeler zamanla sembolik figürlere dönüştü; gerçek siyasi ve askerî iktidar vezirler, emirler ve sonraç sultanlara geçti. Bu ayrışma, İslam siyasi düşüncesinde çözülemeyen gerilimler doğurdu.\"\n— Patricia Crone & Martin Hinds, God's Caliph: Religious Authority in the First Centuries of Islam, Cambridge University Press, 1986\n\nMetne göre Abbasi halifeliğindeki 'teori-pratik' ayrışması hangi açıdan önemlidir?",
        secenekler: [
            "Halifenin her zaman hem dinî hem siyasi otoriteyi fiilen kullanmış olması",
            "Bu ayrışmanın yalnızca ekonomik nedenlere bağlanabilmesi",
            "Nominal dini otoritenin gerçek siyasi iktidardan kopması ve bunun İslam siyasi düşüncesinde çözümsüz gerilimler yaratması",
            "Sultanların halifeliği tamamen lağvetmesi",
            "Bu sürecin İslam dünyasında demokratik bir yönetim anlayışının doğmasına zemin hazırlaması"
        ],
        cevap: "Nominal dini otoritenin gerçek siyasi iktidardan kopması ve bunun İslam siyasi düşüncesinde çözümsüz gerilimler yaratması",
        aciklama: "Metin, teorik iktidarın (halifelik) pratikte sembolik bir kılıfa büründüğünü ve gerçek gücün sultanlara devredildiğini anlatmaktadır. Bu yapısal ayrışmanın İslam siyasi düşüncesinde 'çözülemeyen gerilimler' yarattığı belirtilmektedir. Öğrenciden siyaset teorisi ile pratik iktidar arasındaki farkı kavraması beklenmektedir."
    },
    {
        soru: "\"Yüz Yıl Savaşları'nda Fransız zaferinin simgesi hâline gelen Jeanne d'Arc, salt askerî bir kahraman değildi. Onun etrafında şekillenen söylem, kraliyet meşruiyetini, millî kimliğin filizlenmesini ve dini yorumun siyasi kullanımını bir arada barındırıyordu.\"\n— Kelly DeVries, Joan of Arc: A Military Leader, Sutton Publishing, 1999\n\nMetne göre Jeanne d'Arc olgusunun yalnızca askerî bir zafer hikâyesi olarak anlatılması neden yetersiz kalır?",
        secenekler: [
            "Jeanne d'Arc'ın fiilen hiçbir savaşa katılmaması",
            "Jeanne d'Arc çevresindeki söylemin aynı zamanda dinî, siyasi ve ulusal kimlik boyutları taşıması",
            "Jeanne d'Arc'ın askerî başarılarının abartılmış olması",
            "Jeanne d'Arc'ın Fransız değil İngiliz tarafını desteklemesi",
            "Savaşların sonucunda Fransa'nın yenilgiye uğraması"
        ],
        cevap: "Jeanne d'Arc çevresindeki söylemin aynı zamanda dinî, siyasi ve ulusal kimlik boyutları taşıması",
        aciklama: "Metin, Jeanne d'Arc olgusunun 'kraliyet meşruiyeti, millî kimlik ve dini yorumun siyasi kullanımı' gibi birden fazla boyutu barındırdığını vurgulayarak salt askerî yorumun yetersizliğini ortaya koymaktadır."
    },
    {
        soru: "\"Orta Çağ'da kilise ile devlet arasındaki çatışma, iktidarın sınırları üzerindeki köklü bir anlaşmazlığı yansıtıyordu. Yatırım kavgasası olarak bilinen bu mücadele, ruhban atamalarının kimin elinde olduğu sorusu üzerine yüzyıl boyunca sürdü ve sonunda hem Papa'nın hem de imparatorun yetkilerini sınırlayan uzlaşmalarla noktalandı.\"\n— Uta-Renate Blumenthal, The Investiture Controversy: Church and Monarchy, University of Pennsylvania Press, 1988\n\nMetne göre yatırım kavgasının tarihsel önemi nereden kaynaklanmaktadır?",
        secenekler: [
            "Bu kavganın kilise ve devleti birbirinden tamamen ayırarak laik devletin kurulmasını sağlamasından",
            "İktidar sınırları üzerindeki köklü anlaşmazlığı ve her iki tarafın da yetkilerinin sınırlandırılmasını temsil etmesinden",
            "Papa'nın bu mücadeleyi kesin zaferle kazanarak tüm imparatorluklar üzerinde hâkimiyet kurmasından",
            "Yatırım kavgasının yalnızca Almanya ile İtalya arasında sınırlı kalan yerel bir çatışma olmasından",
            "Bu mücadelenin kilisede kapsamlı bir dinî reforma yol açmasından"
        ],
        cevap: "İktidar sınırları üzerindeki köklü anlaşmazlığı ve her iki tarafın da yetkilerinin sınırlandırılmasını temsil etmesinden",
        aciklama: "Metin yatırım kavgasını 'iktidarın sınırları üzerindeki köklü bir anlaşmazlık' olarak tanımlamakta ve sonucun her iki tarafın yetkilerini sınırlayan uzlaşmalar olduğunu belirtmektedir. A seçeneği çok ileri giderek 'laik devletin kurulması' gibi metinde desteklenmeyen bir sonuç sunmaktadır."
    },
    {
        soru: "\"Orta Çağ kentlerinin özerkliğini kazanması, feodal sistemin katı hiyerarşisine karşı aşağıdan yükselen bir itişin ürünüydü. Ticaret burjuvazisi ile zanaatkâr loncaları, kentsel özgürlükleri yasal güvenceye kavuşturan şartlar koparttı; bu süreç, Avrupa'da çoğulcu siyasi düşüncenin nüvelerini filizlendirdi.\"\n— Henri Pirenne, Medieval Cities: Their Origins and the Revival of Trade, Princeton University Press, 1925\n\nMetne göre Orta Çağ kentlerinin özerklik kazanması sürecinin Avrupa siyasi tarihi açısından önemi nedir?",
        secenekler: [
            "Bu sürecin feodal sistemi tamamen ve hızla çöküşe götürmesi",
            "Kent özerkliğinin yalnızca tüccar sınıfına yarar sağlayıp loncaları dışarıda bırakması",
            "Feodal hiyerarşiye karşı kazanılan yasal özgürlüklerin çoğulcu siyasi düşüncenin tohumlarını atması",
            "Kentsel özgürlüklerin papanın müdahalesiyle değil imparatorun izniyle kazanılması",
            "Lonca sisteminin kent özerkliğiyle birlikte ortadan kalkması"
        ],
        cevap: "Feodal hiyerarşiye karşı kazanılan yasal özgürlüklerin çoğulcu siyasi düşüncenin tohumlarını atması",
        aciklama: "Metin iki boyutu bağlamaktadır: yasal özgürlüklerin kazanılması (pratik) ve bunun çoğulcu siyasi düşüncenin nüvelerini filizlendirmesi (uzun vadeli siyasi etki). A seçeneği 'tamamen ve hızla çöküş' ifadesiyle metinin desteklemediği aşırı bir sonuç sunmaktadır."
    },
    {
        soru: "\"Saltanat, gücünü yalnızca kılıçtan değil rızadan aldığında kalıcı olur. Gücünü yalnızca kılıçla sürdüren hükümdar, uykusunda bile silahına sarılmak zorundadır. Oysa halkın rızasını kazanan hükümdar, tek başına dolaşabilir.\"\n— Nizamülmülk, Siyasetname, çev. Mehmet Altay Köymen, Türk Tarih Kurumu, 1982\n\nNizamülmülk'ün bu pasajından yola çıkarak Orta Çağ İslam siyaset düşüncesi hakkında hangi çıkarım yapılabilir?",
        secenekler: [
            "Nizamülmülk'e göre kalıcı iktidar yalnızca askerî güçle kurulabilir.",
            "İktidarın meşruiyeti, zorun yanı sıra halkın rızasına ve onayına da dayanmalıdır.",
            "Siyasetname, monarşi yerine meşruti yönetimi savunmaktadır.",
            "Halkın rızasının önemi yalnızca barış dönemlerinde geçerlidir.",
            "Nizamülmülk hükümdarın hiçbir zaman güç kullanmaması gerektiğini savunmaktadır."
        ],
        cevap: "İktidarın meşruiyeti, zorun yanı sıra halkın rızasına ve onayına da dayanmalıdır.",
        aciklama: "Nizamülmülk, kalıcı iktidarın yalnızca kılıçla değil rızayla mümkün olduğunu vurgulayarak meşruiyet kavramını iktidar teorisinin merkezine yerleştirmektedir. Bu, modern siyaset biliminde 'zor + meşruiyet' ikiliğine karşılık gelen bir çerçevedir. Öğrenciden klasik İslam siyaset düşüncesindeki meşruiyet kavramını kavraması beklenmektedir."
    },
    {
        soru: "\"Venedik, Doğu ile Batı arasındaki ticarette aracı konumunu ustalıkla sömürdü. Bu şehrin başarısı yalnızca coğrafi şansından değil; aynı zamanda deniz hukuku, ortaklık sözleşmeleri ve diplomatik ağlar gibi kurumsal yenilikleri geliştirme becerisinden kaynaklanıyordu.\"\n— Frederic C. Lane, Venice: A Maritime Republic, Johns Hopkins University Press, 1973\n\nMetne göre Venedik'in Orta Çağ ticaretindeki başarısının temel kaynağı nedir?",
        secenekler: [
            "Yalnızca coğrafi konum ve doğal liman avantajı",
            "Güçlü bir deniz ordusuna sahip olması",
            "Hem coğrafi avantaj hem de deniz hukuku, ortaklık ve diplomasi gibi kurumsal yenilikler",
            "Venedik'in Doğu mallarını üretip Batı'ya satması",
            "Kilise desteğiyle güçlenen ticari ayrıcalıklar"
        ],
        cevap: "Hem coğrafi avantaj hem de deniz hukuku, ortaklık ve diplomasi gibi kurumsal yenilikler",
        aciklama: "Metin 'yalnızca coğrafi şansından değil' diyerek doğal avantajın tek başına yetersiz olduğunu belirtmekte; kurumsal yenilikleri başarının ikinci ve tamamlayıcı kaynağı olarak sunmaktadır. A seçeneği metnin 'yalnızca değil' ifadesini görmezden gelmektedir."
    },
    {
        soru: "\"Orta Çağ boyunca Hint Okyanusu ticaret ağları, Avrupa merkezli tarih yazımında uzun süre görmezden gelindi. Oysa Arap, Hint, Malay ve Çinli tüccarların birlikte işlettiği bu sistem, İpek Yolu'ndan çok önce ve çok daha yüksek hacimli bir ticarete ev sahipliği yapıyordu.\"\n— K. N. Chaudhuri, Trade and Civilisation in the Indian Ocean, Cambridge University Press, 1985\n\nMetne göre Hint Okyanusu ticaret ağlarının tarih yazımında görmezden gelinmesinin temel nedeni nedir?",
        secenekler: [
            "Bu ticaret ağlarının gerçekte çok küçük hacimli olması",
            "Avrupa merkezli tarih yazımının kendi kıtası dışındaki ağları sistematik biçimde dışlaması",
            "Hint Okyanusu ticaretini belgeleleyen hiçbir yazılı kaynağın bulunmaması",
            "Bu ticaretin yalnızca Çin ile Hint arasında gerçekleşmesi",
            "Batılı tarihçilerin bu ağları İpek Yolu'nun bir parçası olarak sınıflandırması"
        ],
        cevap: "Avrupa merkezli tarih yazımının kendi kıtası dışındaki ağları sistematik biçimde dışlaması",
        aciklama: "Metin, söz konusu ağların 'Avrupa merkezli tarih yazımında uzun süre görmezden gelindi'ğini belirtmektedir. Bu, Avrupamerkezci tarih yazımını eleştiren bir argümandır. C seçeneği yanlıştır; Arap, Hint, Çin kaynaklarında bu ticaret zengin biçimde belgelenmiştir."
    },
    {
        soru: "\"Orta Çağ boyunca baharat ticareti, yalnızca bir gıda maddesi alışverişi değildi; aynı zamanda güç, prestij ve egzotik olanın sembolik ekonomisinin ta kendisiydi. Kimyon, tarçın ve karabiber; zenginliğin, nüfuzun ve uzak diyarlara olan erişimin somut göstergeleriydi.\"\n— Paul Freedman, Out of the East: Spices and the Medieval Imagination, Yale University Press, 2008\n\nMetne göre Orta Çağ baharat ticaretini ekonomik bir değiş tokuştan fazlası yapan nedir?",
        secenekler: [
            "Baharatların tıbbi tedavi amaçlı olarak dini törenlerde kullanılması",
            "Baharatların sembolik değer, prestij ve güç göstergesi işlevi görmesi",
            "Baharat ticaretinin yalnızca Avrupa saray mutfaklarına yönelik olması",
            "Baharatların para biriminin yerini alarak ödeme aracına dönüşmesi",
            "Baharat alımının kilise tarafından ahlaki bir görev olarak sunulması"
        ],
        cevap: "Baharatların sembolik değer, prestij ve güç göstergesi işlevi görmesi",
        aciklama: "Metin baharatları 'güç, prestij ve egzotik olanın sembolik ekonomisi' olarak konumlandırmakta; salt gıda maddesi alışverişinin ötesinde sembolik ve toplumsal işlevlerini vurgulamaktadır. Bu, kültürel ekonomi kavramının tarihsel örneğine işaret etmektedir."
    },
    {
        soru: "\"14. yüzyılda Doğu-Batı ticaret güzergâhlarının kesintiye uğraması, Avrupa'yİ yeni deniz yolları aramaya zorladı. Portekiz ve İspanya'nın öncülük ettiği bu arayış, ticaret güzergâhlarının değişmesinin yalnızca ekonomik değil jeopolitik sonuçlar doğurduğunu çarpıcı biçimde ortaya koyar.\"\n— Felipe Fernández-Armesto, Before Columbus: Exploration and Colonisation from the Mediterranean to the Atlantic, Macmillan, 1987\n\nMetne göre Orta Çağ sonunda ticaret güzergâhlarının değişmesi hangi daha geniş tarihsel süreci tetiklemiştir?",
        secenekler: [
            "Osmanlı İmparatorluğu'nun Doğu ticaretini tamamen sonlandırması",
            "Avrupa'nın yeni deniz yolları arayışına girmesi ve bunun hem ekonomik hem jeopolitik dönüşümlere yol açması",
            "Hansa Birliği'nin Akdeniz'deki ticaret hâkimiyetini pekiştirmesi",
            "İpek Yolu ticaretinin Orta Asya'dan Rusya üzerinden yeniden canlanması",
            "Orta Çağ ticaret ağlarının tüm işlevini yitirerek tamamen çökmesi"
        ],
        cevap: "Avrupa'nın yeni deniz yolları arayışına girmesi ve bunun hem ekonomik hem jeopolitik dönüşümlere yol açması",
        aciklama: "Metin, güzergâh değişiminin Portekiz ve İspanya'yı deniz yolları aramaya zorladığını ve bunun ekonomik-jeopolitik sonuçlar doğurduğunu belirtmektedir. Bu soruyla öğrenci, Orta Çağ ticaret dinamiklerinin Keşifler Çağı'nı nasıl hazırladığını kavramaya yönlendirilmektedir."
    },
    {
        soru: "\"Orta Çağ İslam dünyasında 'suftaca' adı verilen finansal araç, uzak mesafeli ticaretin riskini minimize etti. Bu araç, tüccarın fiziksel olarak altın taşımasına gerek kalmadan yazılı emirler aracılığıyla ödemeler gerçekleştirmesine olanak tanıyordu; özü itibarıyla modern banka havalesi sisteminin öncülüydü.\"\n— Abraham Udovitch, Partnership and Profit in Medieval Islam, Princeton University Press, 1970\n\nMetne göre suftacanın Orta Çağ ticaretine en önemli katkısı nedir?",
        secenekler: [
            "İslam dünyasının altın rezervlerini artırması",
            "Uzak mesafeli ticarette fiziksel para taşımanın riskini ortadan kaldıran bir ödeme sistemi sunması",
            "Ticareti yalnızca güvenilir Müslüman tüccarlarla sınırlaması",
            "Faiz yasağını devre dışı bırakarak kârlı kredi sistemleri kurulmasına olanak tanıması",
            "Hükümdar hazinelerini doğrudan desteklemesi"
        ],
        cevap: "Uzak mesafeli ticarette fiziksel para taşımanın riskini ortadan kaldıran bir ödeme sistemi sunması",
        aciklama: "Metin, suftacanın 'fiziksel olarak altın taşımaya gerek kalmadan' ödeme yapılmasına olanak tanıdığını belirtmektedir. Bu, uzak mesafeli ticaretin güvenlik riskini minimize eden kurumsal bir yeniliktir. Diğer seçenekler metinde yer almayan ya da metinle çelişen iddialar içermektedir."
    },
    {
        soru: "\"Orta Çağ fuarları, özellikle Champagne bölgesindeki büyük ticaret panayırları, Avrupa'nın farklı köşelerinden gelen tüccarları düzenli aralıklarla bir araya getiriyordu. Bu buluşmalar yalnızca mal değiş tokuşu değil; fiyat belirleme, kredi işlemleri ve ticari anlaşmazlıkların çözümü için ortak kuralların geliştirilmesi işlevini de üstlendi.\"\n— Robert-Henri Bautier, The Economic Development of Medieval Europe, Thames and Hudson, 1971\n\nMetne göre Champagne fuarlarının Avrupa ticaretindeki işlevi neydi?",
        secenekler: [
            "Yalnızca lüks malların alınıp satıldığı özel bir pazar işlevi gördü.",
            "Mal takasının yanı sıra fiyat belirleme, kredi ve ticari hukuk gibi düzenleyici işlevler de üstlendi.",
            "Kilise denetiminde yürütülen dinî bir ritüelin parçasıydı.",
            "Yalnızca Fransız tüccarlara açık olduğu için uluslararası ticaret açısından sınırlı öneme sahipti.",
            "Fuarların önemi, devlet müdahalesinin arttığı 14. yüzyıldan sonra belirginleşti."
        ],
        cevap: "Mal takasının yanı sıra fiyat belirleme, kredi ve ticari hukuk gibi düzenleyici işlevler de üstlendi.",
        aciklama: "Metin, fuarların 'yalnızca mal değiş tokuşu değil' aynı zamanda fiyat belirleme, kredi ve ortak kuralların geliştirilmesi gibi düzenleyici işlevler de üstlendiğini açıkça belirtmektedir. Bu çok işlevlilik, fuarları basit bir pazar yeri olmaktan çıkarmaktadır."
    },
    {
        soru: "\"Orta Çağ İslam astronomisi, yalnızca Yunan mirasını korumakla kalmadı; Batlamyus'un sistemindeki hataları eleştirerek ve yeni gözlem verileriyle onu düzelterek özgün bir katkı sundu. Bu çalışmalar, 16. yüzyılda Kopernik'in devrimi için vazgeçilmez bir zemin oluşturdu.\"\n— George Saliba, Islamic Science and the Making of the European Renaissance, MIT Press, 2007\n\nMetne göre İslam astronomisinin bilim tarihi açısından önemi nedir?",
        secenekler: [
            "İslam astronomisi Yunan mirasını olduğu gibi Batı'ya aktarmakla sınırlı kaldı.",
            "İslam astronomları yalnızca pratik denizcilik amaçlı çalışmalar yürüttü.",
            "İslam astronomisi hem Yunan sistemini eleştirip geliştirdi hem de Kopernik Devrimi için temel oluşturdu.",
            "İslam astronomisinin katkısı 16. yüzyılda Batılı bilginlerce reddedildi.",
            "İslam astronomları Batlamyus'un sistemini doğru buldukları için değiştirmeye gerek duymadı."
        ],
        cevap: "İslam astronomisi hem Yunan sistemini eleştirip geliştirdi hem de Kopernik Devrimi için temel oluşturdu.",
        aciklama: "Metin iki boyutu birlikte sunmaktadır: Batlamyus'u eleştirerek ve düzelterek aşmak (özgün katkı) ve Kopernik için zemin oluşturmak (tarihsel etki). A seçeneği 'salt aktarım' iddiasıyla metnin 'özgün katkı' vurgusunu görmezden gelmektedir."
    },
    {
        soru: "\"Dante'nin İlahi Komedya'sı salt bir dinî alegoriden ibaret değildir. Bu yapıt; Orta Çağ kozmolojisini, siyasi eleştiriyi, aşk ve sürgün temalarını ve yükselen vernacular edebiyat geleneğini tek bir anlatı çerçevesinde sentezlemektedir. Bu yönüyle Dante'nin yapıtı, Orta Çağ kültürel birikiminin olağanüstü bir özeti niteliğindedir.\"\n— R. W. B. Lewis, Dante, Viking Press, 2001\n\nMetne göre İlahi Komedya'nın Orta Çağ kültürü açısından önemi nereden kaynaklanmaktadır?",
        secenekler: [
            "İlahi Komedya'nın yalnızca dinî öğreti amacı taşımasından",
            "Yapıtın Latince yazılarak entelektüel çevrelere hitap etmesinden",
            "Kozmoloji, siyaset, aşk ve vernacular edebiyatı tek çerçevede buluşturarak Orta Çağ birikimini özetlemesinden",
            "Dante'nin eserinde yalnızca İtalyan siyasetini eleştirmesinden",
            "İlahi Komedya'nın Orta Çağ'dan çok Rönesans düşüncesini yansıtmasından"
        ],
        cevap: "Kozmoloji, siyaset, aşk ve vernacular edebiyatı tek çerçevede buluşturarak Orta Çağ birikimini özetlemesinden",
        aciklama: "Metin, yapıtı birden fazla alanı birleştiren bir sentez olarak tanımlamaktadır: kozmoloji, siyaset eleştirisi, aşk-sürgün temaları ve vernacular edebiyat. Bu çok katmanlılık, yapıtı Orta Çağ kültürünün bir özeti hâline getirmektedir. A seçeneği, metnin 'salt dinî alegoriden ibaret değil' ifadesini doğrudan çelişmektedir."
    },
    {
        soru: "\"Orta Çağ üniversitelerinde ders görme biçimi olan disputatio (tartışma), yalnızca bilgi aktarımını değil; argüman üretme, itiraz etme ve yanıt verme becerilerini geliştirmeyi hedefliyordu. Bu pedagojik yöntem, bilginin otorite aracılığıyla değil akıl yürütme yoluyla doğrulanabileceği anlayışını pekiştirdi.\"\n— Olga Weijers, In Search of the Truth: A History of Disputation Techniques from Antiquity to Early Modern Times, Brepols, 2013\n\nMetne göre disputatio yönteminin Orta Çağ entelektüel geleneğine en özgün katkısı nedir?",
        secenekler: [
            "Öğrencilerin yalnızca kilise otoritesinin öngördüğü bilgileri öğrenmesini sağlaması",
            "Bilginin akıl yürütme ve tartışma yoluyla test edilebileceği anlayışının yerleşmesi",
            "Disputatio yönteminin Antik Yunan felsefesinin birebir kopyalanmasından ibaret olması",
            "Bu yöntemin yalnızca hukuk eğitiminde kullanılması",
            "Üniversitelerin disputatio sayesinde kiliseden tamamen bağımsızlaşması"
        ],
        cevap: "Bilginin akıl yürütme ve tartışma yoluyla test edilebileceği anlayışının yerleşmesi",
        aciklama: "Metin, disputatio'nun bilgiyi 'otorite aracılığıyla değil akıl yürütme yoluyla doğrulama' anlayışını pekiştirdiğini belirtmektedir. Bu, skolastik felsefenin kritik akılcılık boyutunu vurgulayan ve Aydınlanma'ya uzanan bir zemin hazırlayan bir pedagojik anlayıştır. Öğrenciden bu derin anlayışı kavraması beklenmektedir."
    },
    {
        soru: "\"Orta Çağ boyunca İslam dünyasındaki tıp bilgisi, Galenos ve Hipokrat'ın Yunan mirasını yalnızca korumakla kalmayıp klinik gözlem, hastane pratiği ve sistematik farmakoloji alanlarında özgün gelişmeler üretti. İbn Sina'nın el-Kanun'u, 17. yüzyıla dek Avrupa tıp okullarında temel ders kitabı olarak okutuldu.\"\n— Peter E. Pormann & Emilie Savage-Smith, Medieval Islamic Medicine, Edinburgh University Press, 2007\n\nMetne göre İslam tıbbının tarihsel önemini en iyi hangi ifade yansıtmaktadır?",
        secenekler: [
            "İslam tıbbı Yunan mirasını birebir aktarmakla yetindi.",
            "İslam tıbbı, pratik ve kuramsal alanlarda özgün katkılar üretti ve Avrupa tıp eğitimini yüzyıllarca biçimlendirdi.",
            "İbn Sina'nın eserleri yalnızca İslam dünyasında okundu; Batı'ya hiç ulaşmadı.",
            "İslam tıbbının katkıları Rönesans döneminde tamamen terk edildi.",
            "İslam tıp anlayışı dini inançla çeliştiği için kilise tarafından Avrupa'da yasaklandı."
        ],
        cevap: "İslam tıbbı, pratik ve kuramsal alanlarda özgün katkılar üretti ve Avrupa tıp eğitimini yüzyıllarca biçimlendirdi.",
        aciklama: "Metin hem 'yalnızca korumakla kalmayıp özgün gelişmeler ürettiğini' hem de el-Kanun'un 17. yüzyıla dek Avrupa'da okutulduğunu belirtmektedir. Bu iki boyut birlikte B seçeneğini desteklemektedir. C seçeneği metnin 'Avrupa tıp okulları' ifadesini doğrudan çürütmektedir."
    },
    {
        soru: "\"Orta Çağ'da ilm-i nücum yani astroloji ile astronomi birbirinden keskin biçimde ayrılmıyordu. Gök cisimlerinin hareketlerini hesaplayan bilgin, aynı zamanda bu hareketlerin yeryüzündeki olayları nasıl etkilediğini yorumlayabilirdi. Bu bağlamda Orta Çağ kozmolojisi, gözlem ile yorumun iç içe geçtiği bütüncül bir dünya anlayışı sunuyordu.\"\n— Emilie Savage-Smith, Islamicate Celestial Globes, Smithsonian Institution Press, 1985\n\nMetne göre Orta Çağ kozmolojisinin modern bilimsel anlayıştan ayrılan temel özelliği nedir?",
        secenekler: [
            "Orta Çağ'da gök cisimlerinin hareketlerinin hiç gözlemlenmemiş olması",
            "Gözlem ile yorumun (astronomi ile astrolojinin) birbirinden ayrı tutulmaması",
            "Orta Çağ'da yalnızca din adamlarının gök gözlemi yapabilmesi",
            "Orta Çağ bilginlerinin Yunan mirasını tamamen reddetmesi",
            "Gök cisimlerinin hareketinin Orta Çağ'da siyasi karar almada hiç kullanılmaması"
        ],
        cevap: "Gözlem ile yorumun (astronomi ile astrolojinin) birbirinden ayrı tutulmaması",
        aciklama: "Metin, astronomi (gözlem/hesaplama) ile astroloji (yorumlama) arasındaki sınırın Orta Çağ'da net biçimde çizilmediğini ve bu ikisinin 'iç içe geçtiğini' belirtmektedir. Modern bilim bu iki alanı kesin olarak ayırır; bu fark, Orta Çağ kozmolojisinin ayırt edici özelliğidir."
    },
    {
        soru: "\"Orta Çağ'ın sonlarında Avrupa'da başlayan müzik kuramı gelişimi, yalnızca ses sistemlerini sınıflandırmakla kalmadı; çok sesli müziğin (polifoni) ortaya çıkışı, kilise müziğini köklü biçimde dönüştürdü. Bu değişim, zamanla dini otorite ile sanatsal özgünlük arasında gerilimlere yol açtı.\"\n— Richard Hoppin, Medieval Music, W. W. Norton & Company, 1978\n\nMetne göre Orta Çağ'da polifoninin gelişmesi hangi gerilimi beraberinde getirdi?",
        secenekler: [
            "Hristiyan kilisesi ile İslam müzik geleneği arasındaki çatışmayı",
            "Dini otorite ile kilise müziğinde sanatsal özgünlük arasındaki gerilimi",
            "Orta Çağ bestecilerinin telif hakları üzerindeki anlaşmazlıkları",
            "Müzikal kuram ile pratik icra arasındaki derin uçurumu",
            "Avrupa ve İslam müzik sistemleri arasındaki teknik farklılıkları"
        ],
        cevap: "Dini otorite ile kilise müziğinde sanatsal özgünlük arasındaki gerilimi",
        aciklama: "Metin, polifoninin kilise müziğini 'köklü biçimde dönüştürdüğünü' ve bu dönüşümün 'dinî otorite ile sanatsal özgünlük arasında gerilimler yarattığını' açıkça belirtmektedir. Bu, sanatsal gelişim ile kurumsal denetim çatışmasının Orta Çağ boyutunu örnekleyen bir olgudur."
    },
    {
        soru: "\"Orta Çağ minyatür sanatı, perspektifi Rönesans anlamında kullanmıyordu. Figürlerin büyüklüğü mekânsal derinliğe değil; hiyerarşik öneme göre belirleniyor, önemli figürler daha büyük, önemsizler daha küçük çiziliyordu. Bu 'hiyerarşik perspektif', görsel dilin doğrudan ideolojik amaçlarla biçimlendirildiğini ortaya koymaktadır.\"\n— Michael Camille, Image on the Edge: The Margins of Medieval Art, Reaktion Books, 1992\n\nCamille'in tanımladığı 'hiyerarşik perspektif' kavramı, sanat tarihi açısından hangi daha geniş soruyu gündeme getirir?",
        secenekler: [
            "Orta Çağ ressamlarının teknik beceriden yoksun olması nedeniyle gerçekçi perspektif çizememiş olup olmadığı sorusunu",
            "Orta Çağ sanatının estetik değerden tamamen yoksun olup olmadığı sorusunu",
            "Görsel temsil biçimlerinin ideolojik ve iktidar ilişkilerini nasıl yansıttığı sorusunu",
            "Hristiyan sanatının İslam sanatından üstün olup olmadığı sorusunu",
            "Rönesans perspektifinin Orta Çağ'dan devşirilen bir teknik olup olmadığı sorusunu"
        ],
        cevap: "Görsel temsil biçimlerinin ideolojik ve iktidar ilişkilerini nasıl yansıttığı sorusunu",
        aciklama: "'Hiyerarşik perspektif' kavramı, sanatın görsel kodlarının ideolojik ve toplumsal yapıyı yansıttığını (büyüklük = önem = iktidar hiyerarşisi) göstermektedir. Metin 'görsel dilin ideolojik amaçlarla biçimlendirildiğini' açıkça vurgularken öğrenciden bu kavramı daha geniş bir sanat-ideoloji ilişkisi sorusuna bağlaması beklenmektedir."
    },
    {
        soru: "\"Orta Çağ'ı 'karanlık çağ' olarak nitelendiren söylem, 19. yüzyıl Aydınlanma tarih yazımının bir ürünüdür. Oysa çağdaş tarih araştırmaları, bu dönemin bilim, felsefe, sanat ve kent yaşamı açısından son derece hareketli ve üretken bir dönem olduğunu kanıtlamaktadır. 'Karanlık çağ' metaforu, bir tarihsel gerçeği değil; bir bakış açısını yansıtmaktadır.\"\n— Umberto Eco (ed.), The Middle Ages, Rizzoli, 2015\n\nMetne göre 'karanlık çağ' söylemini eleştirmenin tarih yazımı açısından önemi nedir?",
        secenekler: [
            "Bu söylemin Orta Çağ'daki sorunları ve gerilemeyi abartmadan anlattığını kabul etmek",
            "Tarihsel dönemleri nitelendirirken kullanılan metaforların tarafsız olgular değil bakış açıları olduğunu fark etmek",
            "Orta Çağ'ın Rönesans'tan daha ileri bir dönem olduğunu savunmak",
            "Aydınlanma düşünürlerinin Orta Çağ'a olan eleştirilerini tamamen geçersiz saymak",
            "'Karanlık çağ' söyleminin yalnızca siyasi amaçlarla ve kasıtlı olarak üretildiğini kanıtlamak"
        ],
        cevap: "Tarihsel dönemleri nitelendirirken kullanılan metaforların tarafsız olgular değil bakış açıları olduğunu fark etmek",
        aciklama: "Metin, 'karanlık çağ' metaforunun 'bir tarihsel gerçeği değil bakış açısını yansıttığını' belirtmektedir. Bu, tarih yazımındaki dil ve perspektif sorununa ilişkin temel bir eleştirel farkındalıktır: kavramlar tarafsız değil ideolojiktir. Öğrenciden tarih yazımı ile ideoloji ilişkisine dair bu üst-düzey çıkarımı yapması beklenmektedir."
    }
];
window.allTests["test_u3_genel_3"] = [
    {
        soru: "\"Kavimler Göçü döneminde Roma sınırlarına akan Germen toplulukları arasındaki en belirgin ortak özellik homojenlik değil, çeşitlilikti. Bir 'Germen' kimliği yoktu; Vizigotlar, Ostrogotlar, Burgundlar ve Franklar birbirinden farklı diller, gelenekler ve siyasi yapılarla hareket etti. 'Kavimler Göçü' ifadesi, aslında çok sayıda birbirinden bağımsız hareketin sonradan yapıştırılmış bir adıdır.\"\n— Roger Collins, Early Medieval Europe 300–1000, Palgrave Macmillan, 1999\n\nMetne göre 'Kavimler Göçü' kavramının en temel sınırlılığı nedir?",
        secenekler: [
            "Bu kavramın yalnızca Germen topluluklarını kapsayıp Hunları dışarıda bırakması",
            "Birbirinden farklı toplulukların hareketlerini tek ve homojen bir süreçmiş gibi göstermesi",
            "Kavramın Roma sınırlarının önemini yeterince vurgulamaması",
            "Bu kavramın Orta Çağ'da değil 19. yüzyılda icat edilmiş olması",
            "Göçün gerçekte gerçekleşmediğini öne sürmesi"
        ],
        cevap: "Birbirinden farklı toplulukların hareketlerini tek ve homojen bir süreçmiş gibi göstermesi",
        aciklama: "Metin, 'Kavimler Göçü' ifadesinin birbiriyle özdeş olmayan çok sayıda hareketi tek bir çatı altında topladığını ve bu nedenle homojenlik yanılsaması yarattığını vurgulamaktadır. 'Sonradan yapıştırılmış bir ad' metaforu bu eleştiriyi doğrudan desteklemektedir. Bu soru öğrenciden tarihsel kavramların kendi başına inşai nitelik taşıdığını kavramasını beklemektedir."
    },
    {
        soru: "\"Habeşistan'a hicret eden ilk Müslümanların deneyimi, göç olgusunun erken İslam tarihindeki belirleyici rolünü gözler önüne serer. Mekke'deki baskıdan kaçan bu topluluk, Habeş Necaşisi'nin sağladığı koruma altında hem fiziksel güvenliğini hem de inanç pratiğini sürdürebildi. Bu göç, yalnızca bir kaçış değil; yeni bir toplumsal ve siyasi kimliğin şekillendiği bir deneyimdi.\"\n— Leila Ahmed, Women and Gender in Islam, Yale University Press, 1992\n\nMetne göre Habeşistan hicreti hangi açıdan salt bir kaçıştan fazlasıdır?",
        secenekler: [
            "Göçün Mekke'nin fethini doğrudan hazırlaması bakımından",
            "Hem korunak bulma hem de yeni bir toplumsal ve siyasi kimlik oluşturma süreci olması bakımından",
            "Bu göçün İslam'ın Afrika'da kökleşmesini sağlaması bakımından",
            "Göçmenlerin Habeşistan'da kalıcı bir devlet kurması bakımından",
            "Göçün dönemin en kalabalık nüfus hareketi olması bakımından"
        ],
        cevap: "Hem korunak bulma hem de yeni bir toplumsal ve siyasi kimlik oluşturma süreci olması bakımından",
        aciklama: "Metin hicretin iki boyutunu birlikte sunmaktadır: fiziksel güvenlik (kaçış) ve 'yeni toplumsal ve siyasi kimliğin şekillendiği deneyim' (kimlik inşası). Bu ikinci boyut, olayı salt kaçışın ötesine taşımaktadır. Diğer seçenekler metinde desteklenmeyen ya da metnin kapsamı dışındaki iddiaları içermektedir."
    },
    {
        soru: "\"Orta Çağ'daki büyük göç hareketleri incelendiğinde, göç güzergâhlarının büyük ölçüde önceden var olan iletişim ve ticaret ağlarıyla örtüştüğü görülür. Tamamen bilinmedik coğrafyalara gerçekleşen göçler son derece istisnaidir; göçmen topluluklar genellikle tanıdık rotaları, daha önce kurulmuş bağlantıları ve yerleşik bilgi ağlarını takip etti.\"\n— Nora Berend (ed.), Christianization and the Rise of Christian Monarchy, Cambridge University Press, 2007\n\nMetne göre Orta Çağ göç güzergâhları hakkında hangi çıkarım yapılabilir?",
        secenekler: [
            "Göçmenler her zaman en kısa ve direkt yolu tercih etti.",
            "Göç güzergâhları rastlantısal değil; önceden var olan ticaret ağları ve tanıdık bağlantılar tarafından biçimlendi.",
            "Büyük göçlerin tamamı deniz yoluyla gerçekleşti.",
            "Göçmenler ticaret yollarını kasıtlı olarak kullanmaktan kaçındı.",
            "Göç güzergâhları yalnızca askeri stratejiye göre belirlendi."
        ],
        cevap: "Göç güzergâhları rastlantısal değil; önceden var olan ticaret ağları ve tanıdık bağlantılar tarafından biçimlendi.",
        aciklama: "Metin, göçlerin 'önceden var olan iletişim ve ticaret ağlarıyla örtüştüğünü' ve tamamen bilinmedik güzergâhların istisna olduğunu belirtmektedir. Bu, göçü önceki sosyal altyapıyla bağlantılı bir süreç olarak çerçeveler. A seçeneğinin 'en kısa yol' iddiası metinde desteklenmemektedir."
    },
    {
        soru: "\"Göç tarihçileri uzun süre boyunca yazılı kaynakların sunduğu 'fatihin bakış açısı'na mahkûm kaldı. Kazananların yazdığı belgeler, kaybedenlerin deneyimini, göç eden toplulukların kendi sesini ve yerinden edilmenin insani boyutlarını görünmez kılıyordu. Arkeoloji ve dilbilim bu sessizliği kısmen doldurmaya başlayana dek göç tarihi, iktidarsızların tarihine yabancı kaldı.\"\n— Patrick Geary, Phantoms of Remembrance: Memory and Oblivion at the End of the First Millennium, Princeton University Press, 1994\n\nGeary'nin eleştirisi, tarih yazımında hangi yapısal soruna dikkat çekmektedir?",
        secenekler: [
            "Yazılı kaynakların arkeolojik bulgularla çeliştiğinde değersiz sayılması gerektiğine",
            "Tarih yazımının yalnızca iktidar sahiplerinin belgelerine dayanmasının iktidarsızların deneyimini sistematik biçimde dışladığına",
            "Dilbilimin göç tarihini anlayabilmek için tek güvenilir kaynak olduğuna",
            "Kazananların belgelerinin her zaman tarafsız ve güvenilir olduğuna",
            "Göç tarihinin yalnızca iktisadi yöntemlerle incelenmesi gerektiğine"
        ],
        cevap: "Tarih yazımının yalnızca iktidar sahiplerinin belgelerine dayanmasının iktidarsızların deneyimini sistematik biçimde dışladığına",
        aciklama: "Geary'nin eleştirisi, kaynak üretimindeki güç asimetrisine odaklanmaktadır: kazananların yazdığı belgeler tarih yazımına egemen olurken kaybedenlerin sesi susturulmaktadır. 'Fatihin bakış açısı' ifadesi bu egemenliği simgeler. Öğrenciden kaynak eleştirisi ve güç-bilgi ilişkisine dair bu üst-düzey farkındalığı kavraması beklenmektedir."
    },
    {
        soru: "\"Berber kabilelerinin Kuzey Afrika bozkırları ile Akdeniz kıyıları arasındaki mevsimlik göçleri, Orta Çağ boyunca hem İslam öncesi hem de İslam sonrası dönemlerde kesintisiz biçimde sürdü. Bu göçler; ticaret ile hayvancılığı, siyasi sadakati ve kültürel kimliği birbirine bağlayan karmaşık bir ağ üzerinde işliyordu. Arap fethinin bu sistemi dönüştürdüğü doğrudur; ama yok etmediği de bir o kadar doğrudur.\"\n— Elizabeth Fentress, Numidia and the Roman World, Oxford University Press, 1979\n\nMetne göre Berber göçlerinin Arap fethiyle ilişkisi hakkında hangi yorum en doğrudur?",
        secenekler: [
            "Arap fetihleri Berber göç geleneğini tamamen ortadan kaldırdı.",
            "Arap fetihleri Berber göç sistemini dönüştürdü ama var olan sürekliliği büsbütün silmedi.",
            "Berber toplulukları Arap fethinden sonra göç etmeyi bıraktı.",
            "Arap fetihleri Berber göç güzergâhlarını İslam öncesiyle birebir aynı bıraktı.",
            "Berber göçleri yalnızca ekonomik nedenlerle gerçekleşiyordu."
        ],
        cevap: "Arap fetihleri Berber göç sistemini dönüştürdü ama var olan sürekliliği büsbütün silmedi.",
        aciklama: "Metin 'dönüştürdüğü doğrudur; ama yok etmediği de bir o kadar doğrudur' ifadesiyle hem değişim hem de süreklilik boyutunu eş ağırlıkla sunmaktadır. Tarihsel değişimi 'tamamen yıkım' ya da 'tamamen süreklilik' olarak okuyan A ve D seçenekleri bu dengeli tabloyu yansıtamamaktadır."
    },
    {
        soru: "\"Orta Çağ'da Yahudi toplulukların Avrupa içindeki hareketleri, büyük ölçüde dışlama ve sürgün politikalarının ürünüydü. İngiltere'den 1290'da, Fransa'dan 1306'da ve İspanya'dan 1492'de gerçekleşen sürgünler; bu toplulukları Osmanlı topraklarına, Kuzey Afrika'ya ve Doğu Avrupa'ya taşıdı. Bu zoraki diaspora, Yahudi kültürel mirasının geniş bir coğrafyaya yayılmasına da zemin hazırladı.\"\n— Jonathan Ray, The Sephardic Frontier: The Reconquista and the Jewish Community in Medieval Iberia, Cornell University Press, 2006\n\nMetne göre Orta Çağ Yahudi sürgünlerinin kültürel bir boyutu da olduğu söylenebilir; bu boyut nedir?",
        secenekler: [
            "Yahudi toplulukların sürgün edildikleri ülkelerin kültürünü tamamen benimsemesi",
            "Zoraki diasporanın, Yahudi kültürel mirasının geniş bir coğrafyaya taşınmasına istem dışı zemin hazırlaması",
            "Sürgünlerin Yahudi kültürel kimliğini tamamen silmesi",
            "Yahudi toplulukların sürgün edildikleri yerlerde asimile olmayı reddederek izole yaşaması",
            "Bu sürgünlerin Orta Çağ boyunca tamamen farklı nedenlerle gerçekleşmesi"
        ],
        cevap: "Zoraki diasporanın, Yahudi kültürel mirasının geniş bir coğrafyaya taşınmasına istem dışı zemin hazırlaması",
        aciklama: "Metin, zorunlu sürgünün istem dışı bir sonuç olarak kültürel mirasın geniş coğrafyaya yayılmasına zemin hazırladığını belirtmektedir. Bu, bir felaketin beklenmedik kültürel etkisini tartışan diyalektik bir tarih okumasıdır. 'Zemin hazırladı' ifadesi bu istem dışı etkiyi vurgulamaktadır."
    },
    {
        soru: "\"Orta Çağ'da göç yalnızca bir felaket ya da fırsat olarak değil; zaman zaman bilinçli bir toplumsal yeniden örgütlenme stratejisi olarak da kullanıldı. Orta Avrupa'nın kolonizasyon dalgası sırasında Alman çiftçi ve zanaatkârlar, Bohemya, Polonya ve Macaristan'daki hükümdarlara davet edilerek yeni kentlerin kurulmasında ve tarımsal verimliliğin artırılmasında etkin rol üstlendi.\"\n— Robert Bartlett, The Making of Europe: Conquest, Colonization and Cultural Change, 950–1350, Princeton University Press, 1993\n\nMetne göre Orta Çağ Avrupa'sındaki kolonizasyon dalgasının ayırt edici özelliği nedir?",
        secenekler: [
            "Bu sürecin yalnızca dinî amaçlarla düzenlenmiş olması",
            "Alman çiftçi ve zanaatkârların hükümdar daveti üzerine belirli işlevleri üstlenmek amacıyla göç etmesi",
            "Kolonizasyonun zorunlu sürgün biçiminde gerçekleşmesi",
            "Bu hareketin yalnızca askeri sınıfı kapsayıp sivil nüfusu içermemesi",
            "Kolonizasyonun Orta Avrupa'yı siyasi açıdan parçalaması"
        ],
        cevap: "Alman çiftçi ve zanaatkârların hükümdar daveti üzerine belirli işlevleri üstlenmek amacıyla göç etmesi",
        aciklama: "Metin göçü 'davet edilme' ve 'etkin rol üstlenme' kavramlarıyla çerçevelemekte; bu göçü belirli bir işlevi yerine getirmek amacıyla planlı biçimde gerçekleştirilen bir hareket olarak sunmaktadır. Bu, göçü yalnızca zorunluluk ya da kaçış olarak okuyan kalıplaşmış anlatıların ötesine geçen bir örnektir."
    },
    {
        soru: "\"Büyük nüfus hareketlerinin ekonomik etkilerini ölçmek, Orta Çağ tarihçilerinin en zorlu görevlerinden biridir. Yerleşim bölgesi terk edildiğinde, tarım arazileri işlevsiz kaldığında ya da zanaatkâr nüfus çözüldüğünde bunların ekonomik maliyeti belgelere yansımaz; çünkü kayıplar çoğunlukla sessizce gerçekleşir. Tarih yazımı var olanı kayıt altına alır; yok olanı değil.\"\n— Michael McCormick, Origins of the European Economy: Communications and Commerce, AD 300–900, Cambridge University Press, 2001\n\nMetne göre Orta Çağ göçlerinin ekonomik etkilerini belgelemenin önündeki temel engel nedir?",
        secenekler: [
            "Bu dönemin ekonomik belgelerinin sonradan bilinçli olarak imha edilmiş olması",
            "Ekonomik kaybın çoğunlukla sessizce ve iz bırakmadan gerçekleşmesi; tarih yazımının ise varlıkları değil yoklukları kaydetmekte yetersiz kalması",
            "Orta Çağ ekonomisinin tamamen takas sistemine dayanması nedeniyle ölçülememesi",
            "Tarihçilerin ekonomik analizi tarih yazımının dışında tutması",
            "Göçlerin yalnızca artı değer üreten sektörleri etkilemesi"
        ],
        cevap: "Ekonomik kaybın çoğunlukla sessizce ve iz bırakmadan gerçekleşmesi; tarih yazımının ise varlıkları değil yoklukları kaydetmekte yetersiz kalması",
        aciklama: "Metin 'tarih yazımı var olanı kaydeder; yok olanı değil' diyerek tarihsel belgelemenin yapısal bir zaafını ortaya koymaktadır: kayıplar sessizce gerçekleştiğinde belgesel iz bırakmaz ve bu nedenle ölçülemez. Öğrenciden tarih yazımının epistemolojik sınırlarını kavraması beklenmektedir."
    },
    {
        soru: "\"Selahaddin'in 1187'de Kudüs'ü geri alması, yalnızca askerî bir zafer değildi. Zafer sonrasında şehirde yaşayan Hristiyan halka gösterilen göreceli hoşgörü —can ve mal güvencesi— dönemin kronikçilerini bile şaşırttı. Bu davranış biçimi, siyasi hesapların yanı sıra bilinçli bir meşruiyet inşası stratejisinin de parçasıydı.\"\n— Anne-Marie Eddé, Saladin, Harvard University Press, 2011\n\nMetne göre Selahaddin'in Kudüs'ü fetheden olarak sergilediği hoşgörülü tutumun arka planındaki çok boyutlu nedeni en iyi hangi seçenek yansıtmaktadır?",
        secenekler: [
            "Selahaddin'in Hristiyan halkı potansiyel müttefik olarak görmesi",
            "Hem insani değerler hem de bilinçli bir siyasi meşruiyet inşası stratejisinin bir arada etkili olması",
            "Selahaddin'in askerî zafer kazandıktan sonra güce ihtiyaç duymadığını düşünmesi",
            "Dönemin kronikçilerinin abartılı anlatılar üretmesiyle açıklanabilmesi",
            "Bu tutumun İslam hukukunun zorunlu kıldığı bir uygulama olmasından kaynaklanması"
        ],
        cevap: "Hem insani değerler hem de bilinçli bir siyasi meşruiyet inşası stratejisinin bir arada etkili olması",
        aciklama: "Metin, hoşgörülü tutumu 'siyasi hesapların yanı sıra bilinçli bir meşruiyet inşası stratejisi' olarak tanımlamaktadır. Bu 'yanı sıra' ifadesi, tek bir açıklamayı yeterli görmeyip çok nedenli bir yorum yapılmasını gerektirmektedir. Diğer seçenekler bu bütünlüklü tabloyu tek bir nedenle çözümlemeye çalışmaktadır."
    },
    {
        soru: "\"Orta Çağ devletlerinde taht mücadelesi yalnızca bir iktidar savaşı değil; aynı zamanda meşruiyetin ne anlama geldiğini belirleyen bir süreçti. Kimin hükümdar olacağını belirleyen ölçütler —soyun üstünlüğü, seçim, fetih ya da ilahi işaret— farklı siyasi kültürlerde farklı biçimler aldı ve bu farklılık, hanedanlıkların hem güçlenmesine hem de çöküşüne zemin hazırladı.\"\n— Georges Duby, France in the Middle Ages 987–1460, Blackwell, 1991\n\nMetne göre Orta Çağ taht mücadelelerinin yalnızca iktidar savaşı olarak değerlendirilmesinin sınırlılığı nedir?",
        secenekler: [
            "Taht mücadelelerinin çoğunlukla savaş yerine müzakereyle çözülmesi",
            "Bu mücadelelerin aynı zamanda meşruiyetin ne olduğunu tanımlayan ve farklı kültürlerde farklı biçimler alan bir süreç olması",
            "Orta Çağ taht mücadelelerinin modern anlamda güç siyasetiyle hiçbir ilgisi olmaması",
            "Taht mücadelelerinin yalnızca küçük hanedanlıklar arasında yaşanmış olması",
            "Bu mücadelelerin ekonomik nedenlerinin siyasi nedenlerden her zaman ağır basması"
        ],
        cevap: "Bu mücadelelerin aynı zamanda meşruiyetin ne olduğunu tanımlayan ve farklı kültürlerde farklı biçimler alan bir süreç olması",
        aciklama: "Metin taht mücadelesini 'meşruiyetin ne anlama geldiğini belirleyen süreç' olarak tanımlamakta ve bu meşruiyet ölçütlerinin kültüre göre farklılaştığını belirtmektedir. Bu çerçeve, mücadeleyi salt iktidar savaşından kavramsal bir zemin tartışmasına dönüştürmektedir."
    },
    {
        soru: "\"Orta Çağ'da bir şehrin teslim olması çoğunlukla uzun bir kuşatmanın değil, müzakerenin ürünüydü. Komutanlar, kaynaklarının tükenme noktasını hesaplar; savunucular, onurlu bir teslimiyetin şartlarını pazarlık ederdi. Bu çerçevede Orta Çağ savaşı, savaş meydanındaki çarpışmadan çok, müzakere, ittifak ve ikmal stratejileri üzerinden şekilleniyordu.\"\n— Jim Bradbury, The Medieval Siege, Boydell Press, 1992\n\nMetne göre Orta Çağ kuşatma savaşının modern savaş anlayışından ayrılan en belirgin özelliği nedir?",
        secenekler: [
            "Kuşatmaların her zaman saldırganın zaferiyle sonuçlanması",
            "Teslimiyetin savaş meydanı çatışmasından çok müzakere, kaynak hesabı ve diplomatik pazarlık yoluyla şekillenmesi",
            "Orta Çağ'da kalelerin hiçbir zaman düşürülememesi",
            "Kuşatmaların yalnızca dinî amaçlarla yürütülmesi",
            "Modern teknolojinin yokluğunun Orta Çağ savaşlarını anlamsız kılması"
        ],
        cevap: "Teslimiyetin savaş meydanı çatışmasından çok müzakere, kaynak hesabı ve diplomatik pazarlık yoluyla şekillenmesi",
        aciklama: "Metin, Orta Çağ savaşının 'çarpışmadan çok müzakere, ittifak ve ikmal stratejileri üzerinden şekillendiğini' belirtmektedir. Teslim olma sürecinde 'kaynak hesabı' ve 'onurlu teslimiyet şartları' müzakeresi bu alternatif dinamiğin somut biçimleridir."
    },
    {
        soru: "\"Orta Çağ İslam dünyasında 'adalet çemberi' kavramı, siyasi iktidara ilişkin köklü bir öğretiyi özetliyordu: adil yönetim refah doğurur, refah vergi geliri sağlar, vergi geliri orduyu besler, ordu devleti ayakta tutar, devlet adaleti mümkün kılar. Bu döngüsel şema, ekonomi ile siyaset arasındaki ilişkiyi keskin biçimde görselleştiriyordu.\"\n— Antony Black, The History of Islamic Political Thought, Edinburgh University Press, 2001\n\n'Adalet çemberi' kavramına göre Orta Çağ İslam siyaset düşüncesinde ekonomi ile siyaset arasındaki ilişki nasıl kurulmaktadır?",
        secenekler: [
            "Ekonomi ve siyaset birbirinden bağımsız alanlardır; biri diğerini etkilemez.",
            "Siyasi iktidar ekonomiye tamamen bağımlıdır; ekonomi çöküşe geçince devlet de çöker.",
            "Adalet, refah, vergi, ordu ve devlet birbirini karşılıklı besleyen döngüsel bir ilişki içinde bağlıdır.",
            "Ordu, adalet ve ekonominin üzerinde mutlak belirleyici konumundadır.",
            "Bu şema yalnızca İslam'ın ilk yüzyıllarında geçerli olup sonraki dönemlerde terk edilmiştir."
        ],
        cevap: "Adalet, refah, vergi, ordu ve devlet birbirini karşılıklı besleyen döngüsel bir ilişki içinde bağlıdır.",
        aciklama: "'Adalet çemberi', beş unsurun —adalet, refah, vergi, ordu, devlet— birbirini döngüsel biçimde beslediği bir model sunar. Hiçbir unsur diğerinin üzerinde mutlak belirleyici değildir; sistem karşılıklı bağımlılık üzerine kuruludur. B ve D seçenekleri bu döngüsel ilişkiyi tek yönlü nedenselliğe indirgemektedir."
    },
    {
        soru: "\"14. yüzyıl Avrupa'sında yaşanan siyasi krizler —papalığın Avignon'a taşınması, Büyük Bölünme ve Konsilerizm hareketi— kilise otoritesinin ciddi biçimde sorgulandığı bir döneme denk geldi. Bu süreçte ortaya çıkan tartışmalar; otoritenin kaynağı, meşruiyet sınırları ve kurumsal reformun imkânı gibi meseleleri gündemin merkezine taşıdı.\"\n— Brian Tierney, Foundations of the Conciliar Theory, Cambridge University Press, 1955\n\nMetne göre 14. yüzyıl kilise krizinin daha geniş siyasi önemi nedir?",
        secenekler: [
            "Bu krizin yalnızca kilise içi yönetim sorunlarıyla sınırlı kalması",
            "Krizin tetiklediği tartışmaların otorite, meşruiyet ve kurumsal reform gibi evrensel siyasi meselelere kapı aralamış olması",
            "Bu krizin Avrupa'da dinin tamamen önemini yitirmesine yol açması",
            "Konsilerizm hareketinin tek adam yönetimine karşı demokratik bir alternatif sunması",
            "Avignon papalığının Fransa'nın İtalya üzerinde tam denetim kurmasını sağlaması"
        ],
        cevap: "Krizin tetiklediği tartışmaların otorite, meşruiyet ve kurumsal reform gibi evrensel siyasi meselelere kapı aralamış olması",
        aciklama: "Metin kilise krizinin yol açtığı tartışmaların 'otorite kaynağı, meşruiyet sınırları ve kurumsal reform' gibi geniş kapsamlı siyasi meselelere uzandığını belirtmektedir. Bu çerçeve, kilise krizini salt dinî değil evrensel siyaset teorisi açısından da önemli kılar. A seçeneği bu genişlemeyi görmezden gelmektedir."
    },
    {
        soru: "\"Orta Çağ'da bir savaşın 'meşru savaş' olup olmadığını belirleyen ölçütler, salt askerî değil teolojik ve hukuki çerçevede belirlendi. Aziz Augustinus'un erken Orta Çağ'da temellendirdiği 'bellum iustum' (meşru savaş) kuramı; savaşın gerekçesi, ilan edeni ve yürütülüş biçimi açısından sınırlar çiziyordu. Bu kuram, hem savaşın başlatılmasını kısıtlamayı hem de başlatıldığında nasıl yürütüleceğini belirlemeyi amaçlıyordu.\"\n— Frederick H. Russell, The Just War in the Middle Ages, Cambridge University Press, 1975\n\nMetne göre 'bellum iustum' kuramının Orta Çağ savaş anlayışına katkısı nedir?",
        secenekler: [
            "Tüm savaşları meşru ilan ederek Orta Çağ'da savaşı sıradan bir siyasi araç haline getirmesi",
            "Savaşın gerekçesi, başlatanı ve yürütülüş biçimi üzerinde teolojik ve hukuki sınırlar çizerek onu denetim altına almaya çalışması",
            "Bu kuramın yalnızca Haçlı Seferleri için geçerli olup diğer savaşlarda uygulanmaması",
            "Bellum iustum'un savaşı tamamen ortadan kaldıran bir barış öğretisi sunması",
            "Bu kuramın papanın savaş ilan etme yetkisini sınırlandırması"
        ],
        cevap: "Savaşın gerekçesi, başlatanı ve yürütülüş biçimi üzerinde teolojik ve hukuki sınırlar çizerek onu denetim altına almaya çalışması",
        aciklama: "Metin kuramın 'savaşın gerekçesi, ilan edeni ve yürütülüş biçimi açısından sınırlar çizdiğini' belirtmektedir. Bu üç boyut birlikte hem savaşın başlatılmasını hem de yürütülmesini denetim altına almayı amaçlamaktadır. A seçeneği metnin tam tersi bir iddia sunmaktadır."
    },
    {
        soru: "\"Orta Çağ'da donanma gücü, kara gücünden daha az görünür ama eşit derecede belirleyiciydi. Venedik, Ceneviz ve Aragonlu donanmaların Akdeniz'deki hâkimiyeti; ticaret güzergâhlarını, kolonileri ve siyasi ittifakları doğrudan şekillendirdi. Deniz gücü olmadan Akdeniz'in siyasi coğrafyasını anlamak mümkün değildir.\"\n— John H. Pryor, Geography, Technology and War: Studies in the Maritime History of the Mediterranean, Cambridge University Press, 1988\n\nMetne göre Orta Çağ Akdeniz siyasi tarihini anlamak için donanma gücünün göz ardı edilmesi neden yanıltıcı olur?",
        secenekler: [
            "Deniz gücünün kara gücünden her açıdan üstün olduğu bu dönemde belirleyici olduğu için",
            "Donanma gücünün ticaret, kolonicilik ve siyasi ittifakları doğrudan biçimlendirmesi nedeniyle Akdeniz siyasetinin bu boyutsuz anlaşılamayacağı için",
            "Orta Çağ'da kara ordularının gereksiz hâle geldiği için",
            "Donanmanın yalnızca ticaret amaçlı kullanıldığı için siyasi tarih açısından önemsiz olduğu için",
            "Venedik ve Cenova'nın Akdeniz'i tamamen kontrol ettiği için diğer güçlerin önemsiz kaldığı için"
        ],
        cevap: "Donanma gücünün ticaret, kolonicilik ve siyasi ittifakları doğrudan biçimlendirmesi nedeniyle Akdeniz siyasetinin bu boyutsuz anlaşılamayacağı için",
        aciklama: "Metin donanma gücünün 'ticaret güzergâhlarını, kolonileri ve siyasi ittifakları doğrudan şekillendirdiğini' ve 'deniz gücü olmadan Akdeniz'in siyasi coğrafyasını anlamanın mümkün olmadığını' belirtmektedir. A seçeneği metnin böyle bir üstünlük iddiası içermediğini görmezden gelmektedir."
    },
    {
        soru: "\"Orta Çağ'da devlet kurma süreci, günümüzün kurumsal devlet anlayışından köklü biçimde ayrılıyordu. Orta Çağ'da 'devlet', soyut ve kalıcı bir kurum değil; büyük ölçüde belirli bir hükümdarın kişisel ağları, sadakatler ve anlık siyasi koşullar etrafında şekillenen ve hükümdarın ölümüyle sıklıkla yeniden yapılanmak zorunda kalan dinamik bir organizmaydı.\"\n— Susan Reynolds, Fiefs and Vassals: The Medieval Evidence Reinterpreted, Oxford University Press, 1994\n\nMetne göre Orta Çağ 'devleti'ni modern devlet anlayışıyla özdeşleştirmenin en temel riski nedir?",
        secenekler: [
            "Bu özdeşleştirmenin Orta Çağ'ı siyasi açıdan anlamsız göstermesi",
            "Orta Çağ siyasi yapısının kişisel sadakat ağlarına ve anlık koşullara dayalı dinamik yapısının, modern kurumsal devlet kalıbıyla anakronistik biçimde yorumlanması",
            "Modern devlet anlayışının Orta Çağ'dan doğrudan miras alındığının kabul edilmesi",
            "Bu özdeşleştirmenin Orta Çağ monarşisini demokrasinin öncüsü olarak sunması",
            "Orta Çağ devletlerinin herhangi bir hukuki çerçeve olmaksızın faaliyet gösterdiğinin varsayılması"
        ],
        cevap: "Orta Çağ siyasi yapısının kişisel sadakat ağlarına ve anlık koşullara dayalı dinamik yapısının, modern kurumsal devlet kalıbıyla anakronistik biçimde yorumlanması",
        aciklama: "Metin, Orta Çağ siyasi yapısının 'soyut ve kalıcı bir kurum' yerine 'kişisel ağlar, sadakatler ve anlık koşullar' etrafında şekillendiğini ve hükümdarın ölümüyle yeniden yapılanmak zorunda kaldığını vurgulamaktadır. Modern devlet kategorisini bu yapıya uygulamak, farklı bir olguyu tanıdık bir kalıba zorla sokmak anlamına gelir: anakronizm riski."
    },
    {
        soru: "\"Ortaçağ ticaret dünyasında güven, her şeyden önce geliyordu. Bir tüccar, tanımadığı bir şehirde yerel bir ortak bulabilmek için aile bağlarını, ortak dini kimliği ya da aynı lonca üyeliğini referans gösterirdi. Para ve meta elden ele geçmeden önce, güven mutlaka yerini bulmuş olurdu.\"\n— Avner Greif, 'Reputation and Coalitions in Medieval Trade: Evidence on the Maghribi Traders', Journal of Economic History, 49(4), 1989\n\nMetne göre Orta Çağ ticaretinde güven mekanizmasının temel işlevi neydi?",
        secenekler: [
            "Devletin ticaret üzerindeki denetimini pekiştirmek",
            "Tanıdık olmayan ortamda ticaret yapılmasını mümkün kılan bir sosyal zemin oluşturmak",
            "Dini ayrılıkların ticarette rekabet avantajına dönüştürülmesini sağlamak",
            "Vergi kaçakçılığını kolaylaştırmak",
            "Rekabeti sınırlayarak tüccarların karlarını garantilemek"
        ],
        cevap: "Tanıdık olmayan ortamda ticaret yapılmasını mümkün kılan bir sosyal zemin oluşturmak",
        aciklama: "Metin, güvenin aile bağı, din ya da lonca üyeliği aracılığıyla inşa edildiğini ve meta akışından önce devreye girdiğini belirtmektedir. Bu, güveni ticaretin ön koşulu olarak konumlandırmakta; tanıdık olmayan ortamlarda ticaret yapılabilmesinin sosyal zeminini açıklamaktadır."
    },
    {
        soru: "\"Orta Çağ boyunca Cenova ve Venedik arasındaki rekabet salt ekonomik değil; jeopolitik, diplomatik ve zaman zaman askerî bir nitelik taşıyordu. Bu iki deniz cumhuriyeti, Doğu Akdeniz'de ticaret ayrıcalıkları ve üs edinme hakkı için hem Bizans hem de Müslüman hükümdarlıklarla ittifak kurmaktan çekinmedi; bu durum, 'Hristiyan dayanışması' söylemini pragmatik hesapların önünde bırakıyordu.\"\n— David Jacoby, 'Venetian Commercial Expansion in the Eastern Mediterranean, 8th–11th Centuries', in Byzantine Trade, 4th–12th Centuries, Ashgate, 2009\n\nMetne göre Cenova-Venedik rekabetinin Orta Çağ siyaset anlayışına dair ortaya koyduğu en çarpıcı bulgu nedir?",
        secenekler: [
            "Hristiyan cumhuriyetlerin her zaman ortak dinî kimlik temelinde hareket ettiğinin kanıtlanması",
            "Ekonomik ve stratejik çıkarların, dini ittifak beklentilerinin önüne geçebildiğini göstermesi",
            "Bu iki şehrin rekabetinin Doğu Akdeniz ticaretini tamamen durdurduğunun görülmesi",
            "Cenova ve Venedik'in Bizans'a karşı her zaman birlikte hareket ettiğinin anlaşılması",
            "Bu rekabetin sonunda Venedik'in Cenova'yı kalıcı olarak yok etmesiyle sona ermesi"
        ],
        cevap: "Ekonomik ve stratejik çıkarların, dini ittifak beklentilerinin önüne geçebildiğini göstermesi",
        aciklama: "Metin, iki Hristiyan cumhuriyetin hem Bizans hem de Müslüman hükümdarlıklarla pragmatik ittifaklar kurduğunu belirtmekte ve 'Hristiyan dayanışması söylemini pragmatik hesapların önünde bırakıyordu' ifadesiyle ekonomik-stratejik çıkarın dini kimliğin üzerine çıkabildiğini göstermektedir."
    },
    {
        soru: "\"Kuzey Afrika ile Avrupa arasındaki Orta Çağ ticareti, olduğundan çok daha az araştırılmış bir alandır. Bu ticaret yalnızca altın ve kölelerle sınırlı değildi; fildişi, boya maddeleri, tuz ve zanaatkâr ürünler de bu güzergâhta dolaşıyordu. Akdeniz'i bir bariyer olarak değil, bir köprü olarak görmek, bu ticaretin neden bu denli canlı kaldığını açıklar.\"\n— Constance Hoffman Berman, Medieval Agriculture, the Southern French Countryside and the Early Cistercians, American Philosophical Society, 1986\n\nMetne göre Kuzey Afrika-Avrupa ticaretini anlamada 'Akdeniz = köprü' metaforunun işlevi nedir?",
        secenekler: [
            "Akdeniz'in her iki kıyısı arasında siyasi birlik bulunduğunu kanıtlamak",
            "Akdeniz'i bölünme değil bağlantı unsuru olarak okuyarak bu ticaretin canlılığını açıklamak",
            "Ticaretin neden yalnızca kuzey-güney yönünde aktığını göstermek",
            "Avrupa'nın Afrika üzerindeki tarihsel üstünlüğünü pekiştirmek",
            "Akdeniz'in coğrafi koşullarının ticareti her zaman engellediğini kabul etmek"
        ],
        cevap: "Akdeniz'i bölünme değil bağlantı unsuru olarak okuyarak bu ticaretin canlılığını açıklamak",
        aciklama: "Metin, Akdeniz'i 'bariyer' değil 'köprü' olarak okumanın bu ticaretin canlılığını açıkladığını belirtmektedir. Coğrafyayı engel değil bağlantı unsuru olarak görmek, farklı bir analitik çerçeve sunar. Bu, coğrafyaya atfedilen anlamın tarihi yorumlama biçimini nasıl değiştirdiğine dair metodolojik bir farkındalığa da işaret etmektedir."
    },
    {
        soru: "\"Orta Çağ'da mal fiyatlarının belirlenmesi, piyasa güçlerinin yanı sıra ahlaki ve dini normlarla da şekilleniyordu. Skolastik düşünürler 'iustum pretium' (adil fiyat) kavramı üzerinde uzun tartışmalar yürüttü; bu kavram, alıcı ile satıcıyı eşit derecede koruyan ve toplumsal denge ile ticarî ahlakı gözeten bir fiyat anlayışını ifade ediyordu.\"\n— Odd Langholm, Economics in the Medieval Schools: Wealth, Exchange, Value, Money and Usury, Brill, 1992\n\nMetne göre 'iustum pretium' kavramı, Orta Çağ iktisat anlayışı ile modern piyasa ekonomisi anlayışı arasındaki hangi temel farkı örneklemektedir?",
        secenekler: [
            "Orta Çağ'da fiyatların devlet tarafından belirlendiği, modern ekonomide ise serbest piyasanın belirleyici olduğu farkı",
            "Fiyat belirlemenin Orta Çağ'da ahlaki ve dini normlarla iç içe geçmesi; oysa modern piyasa ekonomisinin ahlaki boyutu dışlayan salt teknik bir süreç olarak kurulması",
            "Orta Çağ'da fiyatların hiçbir zaman piyasa dinamiklerine göre oluşmadığının kanıtlanması",
            "Modern piyasa ekonomisinin iustum pretium kavramını benimseyerek geliştirdiği gerçeğinin ortaya konması",
            "Bu kavramın yalnızca İslam iktisadında karşılık bulduğu ve Batı skolastiğiyle ilgisinin olmadığı"
        ],
        cevap: "Fiyat belirlemenin Orta Çağ'da ahlaki ve dini normlarla iç içe geçmesi; oysa modern piyasa ekonomisinin ahlaki boyutu dışlayan salt teknik bir süreç olarak kurulması",
        aciklama: "'İustum pretium', fiyat belirlemeyi salt piyasa mekanizmasına değil ahlaki ve dini normlara da bağlayan bir kavramdır. Modern piyasa ekonomisi ise fiyat belirlemeyi ahlaki değerlendirmenin dışında teknik bir süreç olarak kurar. Bu iki anlayış arasındaki fark, Orta Çağ ile modern iktisadın temel ayrışma noktalarından birini oluşturmaktadır."
    },
    {
        soru: "\"Orta Çağ'da Doğu ile Batı arasındaki ticaretin en az anlaşılan boyutlarından biri, bilgi ve teknoloji transferinin ticari mal takasıyla eş zamanlı ve iç içe gerçekleşmesiydi. Bir Arap kervanı yalnızca baharat değil; matematiksel hesap yöntemleri, sulama teknikleri ve yeni bitki türleri hakkında bilgi de taşıyordu. Ticaret güzergâhları, erken dönem küreselleşmenin bilgi otoyollarıydı.\"\n— Andrew Watson, Agricultural Innovation in the Early Islamic World, Cambridge University Press, 1983\n\nMetne göre Orta Çağ ticaret güzergâhlarını 'bilgi otoyolu' olarak nitelendirmenin tarihsel temeli nedir?",
        secenekler: [
            "Tüccarların yalnızca ticari bilgi değil; tarım, matematik ve teknoloji alanlarındaki bilgileri de taşımış olması",
            "Tüccarların birbirinin dini inançlarını değiştirme amacı gütmesi",
            "Ticaret güzergâhlarının yalnızca kâğıt ve kitap taşımak için kullanılması",
            "Orta Çağ'da bilginin yalnızca manastırlar aracılığıyla aktarılabildiği",
            "Tüccarların çoğunlukla entelektüel amaçlarla yolculuk ettiği"
        ],
        cevap: "Tüccarların yalnızca ticari bilgi değil; tarım, matematik ve teknoloji alanlarındaki bilgileri de taşımış olması",
        aciklama: "Metin, tüccarların baharat dışında 'matematiksel hesap yöntemleri, sulama teknikleri ve bitki bilgisi' taşıdığını vurgulayarak ticaret güzergâhlarının yalnızca mal değil bilgi de aktaran bir altyapı olduğunu göstermektedir. 'Bilgi otoyolu' metaforu bu çok boyutlu aktarımı özetlemektedir."
    },
    {
        soru: "\"Orta Çağ'da Çin'in ipek ihracatı yalnızca bir ticaret meselesi değil, bir diplomasi aracıydı. Tang hanedanlığı döneminde ipek; komşu hükümdarlara verilen hediyeler, ittifak karşılıkları ve elçilere sunulan armağanlar aracılığıyla ekonomik değerinin çok ötesinde siyasi işlevler üstlendi. İpek, yalnızca satın alınan değil; kazanılan, verilip alınan ve bazen zorla talep edilen bir meta olarak farklı bir anlam ekonomisi içinde dolaşıma girdi.\"\n— Xinru Liu, The Silk Road in World History, Oxford University Press, 2010\n\nMetne göre Tang döneminde ipeğin salt ticari bir meta olmaktan çıkıp daha geniş bir anlam ekonomisine girmesinin nedeni nedir?",
        secenekler: [
            "İpeğin bu dönemde yalnızca Budist ritüellerde kullanılmaya başlanması",
            "İpeğin hediye, ittifak karşılığı ve diplomatik araç olarak kullanılmasıyla siyasi ve simgesel değer kazanması",
            "Tang hanedanlığının ipeği ticari bir meta olmaktan çıkarıp tamamen devlet tekeline alması",
            "İpek fiyatlarının bu dönemde hızla yükselerek sıradan tüccarların erişiminin dışına çıkması",
            "İpeğin Avrupa pazarlarında dini sembolizm kazanarak kiliselerde kullanılması"
        ],
        cevap: "İpeğin hediye, ittifak karşılığı ve diplomatik araç olarak kullanılmasıyla siyasi ve simgesel değer kazanması",
        aciklama: "Metin ipeğin 'hediye, ittifak karşılığı ve armağan' işlevleriyle 'ekonomik değerinin çok ötesinde siyasi işlevler üstlendiğini' belirtmektedir. 'Satın alınan, verilen, alınan ve zorla talep edilen' dörtlüsü ipeğin birden fazla dolaşım biçiminin olduğunu göstermekte; bu da onu salt ticari kategorinin dışına taşımaktadır."
    },
    {
        soru: "\"Orta Çağ İslam dünyasında optik biliminin gelişimi, yalnızca ışığın fiziksel özelliklerini incelemekle sınırlı kalmadı. İbn el-Heysem'in Kitabü'l-Menazır adlı eseri; göz ile ışık arasındaki ilişkiyi, görsel algının nasıl çalıştıığını ve aynaların geometrisini sistematik deney yöntemiyle araştırdı. Bu yaklaşım, gözlem ve deneyi kuramın önüne yerleştiren erken bir bilimsel tutumu temsil ediyordu.\"\n— David C. Lindberg, Theories of Vision from Al-Kindi to Kepler, University of Chicago Press, 1976\n\nMetne göre İbn el-Heysem'in optik çalışmalarının bilim tarihi açısından önemi nerede yatmaktadır?",
        secenekler: [
            "Antik Yunan optik kuramlarını olduğu gibi koruması ve aktarmasında",
            "Gözlem ve deneyi kuram üretiminin temeline yerleştiren erken bir bilimsel tutumu temsil etmesinde",
            "Optik bilimini tamamen felsefeden bağımsız bir disipline dönüştürmesinde",
            "İbn el-Heysem'in çalışmalarının Rönesans öncesinde Avrupa'ya hiç ulaşmamış olmasında",
            "Bu eserin yalnızca geometrik konuları ele alıp görsel algıyı dışarıda bırakmasında"
        ],
        cevap: "Gözlem ve deneyi kuram üretiminin temeline yerleştiren erken bir bilimsel tutumu temsil etmesinde",
        aciklama: "Metin, İbn el-Heysem'in 'gözlem ve deneyi kuramın önüne yerleştirdiğini' açıkça belirtmektedir. Bu, modern bilimsel yöntemin temel özelliği olarak kabul edilen deneysel doğrulamayı Orta Çağ'da zaten kullanan bir tutumu temsil etmektedir. A seçeneği metnin 'salt aktarım değil özgün araştırma' vurgusunu görmezden gelmektedir."
    },
    {
        soru: "\"Bir sabah şehre ilk ışık vurduğunda, duvarlar yalnızca taş olmaktan çıkar; sabah namazında okunan dua sesi ise sokakları görünmez bir ağla örer. Şehir, taştan ve sesten; görünenden ve görünmeyenden yapılmıştır. Biz de bunun farkında olmadan bu şehrin içinde kaybolur gider, kendimizi bulur ve yeniden kaybederiz.\"\n— Orhan Pamuk, İstanbul: Hatıralar ve Şehir, YKY, 2003\n\nBu pasajdan yola çıkarak Orta Çağ İslam kentleri hakkında hangi tarihsel çıkarım yapılabilir?",
        secenekler: [
            "İslam kentleri yalnızca fiziksel mekânlardan oluşan işlevsel yapılardı.",
            "İslam kentleri, fiziksel mekânla dini pratik ve kültürel deneyimin iç içe geçtiği çok katmanlı bir anlam dünyası sunuyordu.",
            "Orta Çağ İslam kentleri yalnızca dini mekânlardan ibaret olup ticari alanlara yer vermiyordu.",
            "Pamuk'un betimlemesi yalnızca İstanbul için geçerlidir; diğer İslam kentleri için uygulanamaz.",
            "Bu pasaj Orta Çağ'a değil yalnızca modern döneme ait izlenimler sunmaktadır."
        ],
        cevap: "İslam kentleri, fiziksel mekânla dini pratik ve kültürel deneyimin iç içe geçtiği çok katmanlı bir anlam dünyası sunuyordu.",
        aciklama: "Pamuk'un dili, kenti salt fiziksel altyapıdan ibaret görmeyip dua sesi, ışık ve gündelik deneyimi de mekânın kurucu unsurları olarak sunar. Bu çerçeve, Orta Çağ İslam kentlerinin de yalnızca taş ve çamurdan değil; dini pratikler, ritimler ve kültürel deneyimlerden inşa edildiğini tarihsel açıdan desteklemektedir. Edebi bir metnin tarihsel çıkarım için nasıl kullanılabileceğini sorgulayan bu soru, disiplinlerarası okuma becerisini ölçmektedir."
    },
    {
        soru: "\"Orta Çağ'da Avrupa'da Kilise, sanatın hem en büyük hamisi hem de en güçlü sansürcüsü konumundaydı. Dinî ikonografi için belirlenen kural ve standartlar, sanatçının yaratıcı özgürlüğünü sınırlıyor; ama aynı zamanda eserlerine geniş bir izleyici kitlesi kazandırıyordu. Bu gerilim, söz konusu dönemde üretilen sanatın hem boyun eğme hem de yaratıcı direnişin iz bıraktığı karmaşık bir ürün olmasını sağladı.\"\n— Cynthia Hahn, 'Visio Dei: Changes in Medieval Visuality', in Visuality Before and Beyond the Renaissance, Cambridge University Press, 2000\n\nMetne göre Orta Çağ'da kilisenin sanat üzerindeki etkisi hangi paradoksu yaratıyordu?",
        secenekler: [
            "Kilise desteği sanatçıları ekonomik güvenceye kavuştururken onları dini temalar dışında üretimden alıkoyuyordu.",
            "Kilise hem yaratıcılığı kısıtlayan kurallar koyuyor hem de bu kuralların içinde sanatçıların geniş kitlelere ulaşmasını sağlıyordu; bu gerilim hem boyun eğmeyi hem de direnişi barındıran eserler doğurdu.",
            "Kilise yalnızca hamiliği üstlenip sansür işlevini tamamen devlete bıraktı.",
            "Kilise sanatçıları özgür bıraktı ama üretilen eserlerin dağıtımını kontrol etti.",
            "Bu paradoks yalnızca İtalyan sanatçılar için geçerliydi; Kuzey Avrupa'da kilise etkisi daha sınırlıydı."
        ],
        cevap: "Kilise hem yaratıcılığı kısıtlayan kurallar koyuyor hem de bu kuralların içinde sanatçıların geniş kitlelere ulaşmasını sağlıyordu; bu gerilim hem boyun eğmeyi hem de direnişi barındıran eserler doğurdu.",
        aciklama: "Metin, kilisenin aynı anda hem sınırlayıcı (kural koyucu, sansürcü) hem de genişletici (geniş kitle sağlayan, hamiliği üstlenen) bir rol oynadığını ve bu çelişkili konumun sanatsal üretimi hem boyun eğme hem direniş içeren karmaşık bir ürüne dönüştürdüğünü ortaya koymaktadır."
    },
    {
        soru: "\"Orta Çağ'da matematik, doğanın dili olarak değil Tanrı'nın düzeninin yansıması olarak kavranıyordu. Sayıların gizemli anlam taşıdığı inancı —üçün kutsallığı, yedinin tamlığı, on ikinin evrensel düzeni— hem ilahiyatı hem de mimariyi, müziği ve takvim düzenlemelerini biçimlendirdi.\"\n— Umberto Eco, The Aesthetics of Thomas Aquinas, Harvard University Press, 1988\n\nMetne göre Orta Çağ'da sayılara gizemli anlam yüklenmesi hangi alanlarda somut etkiler doğurmuştur?",
        secenekler: [
            "Yalnızca ilahiyat alanında felsefi tartışmalara yol açmıştır.",
            "İlahiyat, mimari, müzik ve takvim gibi birden fazla alanda yapısal ve biçimsel bir iz bırakmıştır.",
            "Bu inanç yalnızca Hristiyan Avrupa'ya özgüdür; İslam ve Yahudi dünyasında hiçbir karşılığı yoktur.",
            "Sayıların gizemli anlamı matematiksel ilerlemeyi engelleyerek Orta Çağ'ı bilimsel açıdan geride bırakmıştır.",
            "Bu inanç yalnızca kilise mimarisini etkilemiş; diğer alanları dışarıda bırakmıştır."
        ],
        cevap: "İlahiyat, mimari, müzik ve takvim gibi birden fazla alanda yapısal ve biçimsel bir iz bırakmıştır.",
        aciklama: "Metin 'hem ilahiyatı hem de mimariyi, müziği ve takvim düzenlemelerini biçimlendirdi' diyerek sayısal-gizemci anlayışın çok alanlı etkisini listelemiştir. A ve E seçenekleri bu geniş kapsamı tek bir alanla sınırlandırmaktadır."
    },
    {
        soru: "\"Orta Çağ İslam coğrafyasında şiir, yalnızca estetik bir etkinlik değil; hafızanın, kimliğin ve toplumsal değerlerin aktarım aracıydı. Şairin toplumsal statüsü yüksekti; hükümdar saraylarında şairler hem övgü hem de eleştiri işlevi üstlenebilirdi. Bu bağlamda şiir, iktidarla hem iş birliği hem de gerilim içinde var olan bir dil alanı oluşturuyordu.\"\n— Suzanne Pinckney Stetkevych, The Poetics of Islamic Legitimacy: Myth, Gender and Ceremony in the Classical Arabic Ode, Indiana University Press, 2002\n\nMetne göre Orta Çağ İslam şiirinin en belirgin özelliği nedir?",
        secenekler: [
            "Şiirin yalnızca saray dışı halk kesimlerine hitap eden bir popüler sanat formu olması",
            "Şiirin hem iktidarla iş birliği hem de gerilim içinde var olan; hafıza, kimlik ve toplumsal değerlerin taşıyıcısı olması",
            "Şiirin Orta Çağ İslam dünyasında yalnızca dini ritüellerde işlev görmesi",
            "Şairlerin saray tarafından her zaman sansüre tabi tutulması",
            "Şiirin siyasi işlevinin bilimsel söylemle çelişmesi nedeniyle giderek önemsizleşmesi"
        ],
        cevap: "Şiirin hem iktidarla iş birliği hem de gerilim içinde var olan; hafıza, kimlik ve toplumsal değerlerin taşıyıcısı olması",
        aciklama: "Metin şiiri üç boyutuyla sunmaktadır: toplumsal işlev (hafıza, kimlik, değer aktarımı), statü (yüksek saygınlık) ve iktidarla ilişki (hem iş birliği hem gerilim). Bu çok boyutluluk, şiiri salt estetik kategorinin dışına taşımaktadır."
    },
    {
        soru: "\"Orta Çağ biliminde bir tezi kabul etmek için deneyin yeterliliği bugünkü anlamda tartışmalıydı. Skolastik geleneğin güçlü olduğu ortamlarda otorite —özellikle Aristoteles ve kutsal metin— deneysel gözlemin önünde geliyordu. Ancak bu tablo hiçbir zaman tam anlamıyla donuk değildi: Roger Bacon ve Albertus Magnus gibi düşünürler, gözlem ve deneyin teorik bilgiye katkısını savunmaya başladı.\"\n— A. C. Crombie, Robert Grosseteste and the Origins of Experimental Science, Oxford University Press, 1953\n\nMetne göre Orta Çağ bilim anlayışında otorite ile gözlem arasındaki ilişki nasıl değerlendirilebilir?",
        secenekler: [
            "Orta Çağ boyunca otorite hiçbir zaman sorgulanmadı; gözlem tamamen dışlandı.",
            "Orta Çağ'da gözlem her zaman otoriteye baskın geldi ve deneysel yöntem yaygın biçimde kullanıldı.",
            "Otorite ve gözlem arasındaki ilişki sabit değildi; bazı düşünürler gözlemin önemini savunarak statik tabloya meydan okudu.",
            "Aristoteles ve kutsal metin hiçbir zaman bilimsel bir otorite olarak kabul görmedi.",
            "Roger Bacon ve Albertus Magnus Orta Çağ bilimini tamamen dönüştürerek modern bilimi kurdu."
        ],
        cevap: "Otorite ve gözlem arasındaki ilişki sabit değildi; bazı düşünürler gözlemin önemini savunarak statik tabloya meydan okudu.",
        aciklama: "Metin iki boyutu dengeli biçimde sunmaktadır: skolastik çevrelerde otoritenin üstünlüğü (Aristoteles ve kutsal metin) ve bu tabloya meydan okuyan bazı düşünürlerin (Roger Bacon, Albertus Magnus) gözlem ve deneyi savunması. 'Hiçbir zaman tam anlamıyla donuk değildi' ifadesi bu iç çeşitliliği vurgular. A ve B seçenekleri bu karmaşık tabloyu aşırı basitleştirmektedir."
    },
    {
        soru: "\"Orta Çağ'da eğitimin kurumsal çerçevesi, katedrallerle başlayıp üniversitelerle olgunlaştı. Üniversiteler yalnızca bilgi aktarım mekânları değil, öğrencilerin ve öğretmenlerin hukuki statü ve ayrıcalıklar kazandığı lonca benzeri yapılardı. Bu özerk statü, entelektüel tartışmanın zamanla daha bağımsız bir zemin kazanmasına olanak tanıdı.\"\n— Hastings Rashdall, The Universities of Europe in the Middle Ages, Oxford University Press, 1895 (1936 baskısı)\n\nMetne göre Orta Çağ üniversitelerini salt bir eğitim kurumundan ayıran temel özellik nedir?",
        secenekler: [
            "Üniversitelerin yalnızca Latince öğretim yapması",
            "Hukuki özerklik ve lonca benzeri yapılanmanın entelektüel bağımsızlık için bir zemin sağlaması",
            "Üniversitelerin tüm öğrencilere ücretsiz eğitim sunması",
            "Bu kurumların doğrudan kilise tarafından yönetilmesi",
            "Üniversitelerin yalnızca dini konuları öğretmekle yükümlü tutulması"
        ],
        cevap: "Hukuki özerklik ve lonca benzeri yapılanmanın entelektüel bağımsızlık için bir zemin sağlaması",
        aciklama: "Metin üniversitelerin 'lonca benzeri yapılar' olarak hukuki statü ve ayrıcalıklar barındırdığını; bu özerk statünün entelektüel tartışmanın bağımsız zemin kazanmasına olanak tanıdığını belirtmektedir. Bu çerçeve, üniversiteyi salt içerik aktarımının ötesinde kurumsal bir özerklik birimi olarak konumlandırmaktadır."
    },
    {
        soru: "\"Orta Çağ'da 'ilerleme' kavramı bugünkü anlamda var değildi. Zaman, çoğunlukla döngüsel ya da çöküşe doğru akan bir akış olarak kavranıyor; altın çağ geride kalmış, şimdiki zaman ise onun soluk bir yansıması sayılıyordu. Bu zaman anlayışı; mimari kanonların, edebi modellerin ve dini otoritenin neden bu denli güçlü biçimde 'eski'ye referans verdiğini açıklar.\"\n— Jacques Le Goff, Time, Work and Culture in the Middle Ages, University of Chicago Press, 1980\n\nLe Goff'a göre Orta Çağ'daki döngüsel zaman anlayışının kültürel üretim üzerindeki etkisi nedir?",
        secenekler: [
            "Bu zaman anlayışı sanatçıları özgün eser üretmekten tamamen alıkoydu.",
            "Döngüsel ya da çöküşe akan zaman anlayışı, mimari kanon, edebi model ve dini otorite gibi alanlarda 'eski'nin referans alınmasını meşrulaştırdı.",
            "Bu anlayış Orta Çağ düşünürlerinin geleceği hiç düşünmemelerine yol açtı.",
            "Döngüsel zaman anlayışı Orta Çağ'da bilimsel ilerlemeyi hızlandırdı.",
            "Bu anlayış yalnızca kilise çevrelerinde geçerliydi; laik kültür ilerlemeci bir zaman anlayışını benimsemişti."
        ],
        cevap: "Döngüsel ya da çöküşe akan zaman anlayışı, mimari kanon, edebi model ve dini otorite gibi alanlarda 'eski'nin referans alınmasını meşrulaştırdı.",
        aciklama: "Le Goff'a göre 'eski'nin sürekli referans alınması tesadüfi değil; geçmişi altın çağ, şimdiyi onun gölgesi olarak gören döngüsel/çöküşçü zaman anlayışının doğal sonucudur. Bu zaman anlayışı, kanona bağlılığı ve eski modellerin otoritesini meşrulaştıran derin bir kültürel mantığı yansıtmaktadır. Öğrenciden zaman kavrayışı ile kültürel üretim biçimi arasındaki ilişkiyi kavraması beklenmektedir."
    }
];

window.allTests["test_u3_genel_4"] = [
    {
        soru: "\"Kavimler Göçü döneminde Roma sınırlarına akan Germen toplulukları arasındaki en belirgin ortak özellik homojenlik değil, çeşitlilikti. Bir 'Germen' kimliği yoktu; Vizigotlar, Ostrogotlar, Burgundlar ve Franklar birbirinden farklı diller, gelenekler ve siyasi yapılarla hareket etti. 'Kavimler Göçü' ifadesi, aslında çok sayıda birbirinden bağımsız hareketin sonradan yapıştırılmış bir adıdır.\"\n— Roger Collins, Early Medieval Europe 300–1000, Palgrave Macmillan, 1999\n\nMetne göre 'Kavimler Göçü' kavramının en temel sınırlılığı nedir?",
        secenekler: [
            "Bu kavramın yalnızca Germen topluluklarını kapsayıp Hunları dışarıda bırakması",
            "Birbirinden farklı toplulukların hareketlerini tek ve homojen bir süreçmiş gibi göstermesi",
            "Kavramın Roma sınırlarının önemini yeterince vurgulamaması",
            "Bu kavramın Orta Çağ'da değil 19. yüzyılda icat edilmiş olması",
            "Göçün gerçekte gerçekleşmediğini öne sürmesi"
        ],
        cevap: "Birbirinden farklı toplulukların hareketlerini tek ve homojen bir süreçmiş gibi göstermesi",
        aciklama: "Metin, 'Kavimler Göçü' ifadesinin birbiriyle özdeş olmayan çok sayıda hareketi tek bir çatı altında topladığını ve bu nedenle homojenlik yanılsaması yarattığını vurgulamaktadır. 'Sonradan yapıştırılmış bir ad' metaforu bu eleştiriyi doğrudan desteklemektedir. Bu soru öğrenciden tarihsel kavramların kendi başına inşai nitelik taşıdığını kavramasını beklemektedir."
    },
    {
        soru: "\"Habeşistan'a hicret eden ilk Müslümanların deneyimi, göç olgusunun erken İslam tarihindeki belirleyici rolünü gözler önüne serer. Mekke'deki baskıdan kaçan bu topluluk, Habeş Necaşisi'nin sağladığı koruma altında hem fiziksel güvenliğini hem de inanç pratiğini sürdürebildi. Bu göç, yalnızca bir kaçış değil; yeni bir toplumsal ve siyasi kimliğin şekillendiği bir deneyimdi.\"\n— Leila Ahmed, Women and Gender in Islam, Yale University Press, 1992\n\nMetne göre Habeşistan hicreti hangi açıdan salt bir kaçıştan fazlasıdır?",
        secenekler: [
            "Göçün Mekke'nin fethini doğrudan hazırlaması bakımından",
            "Hem korunak bulma hem de yeni bir toplumsal ve siyasi kimlik oluşturma süreci olması bakımından",
            "Bu göçün İslam'ın Afrika'da kökleşmesini sağlaması bakımından",
            "Göçmenlerin Habeşistan'da kalıcı bir devlet kurması bakımından",
            "Göçün dönemin en kalabalık nüfus hareketi olması bakımından"
        ],
        cevap: "Hem korunak bulma hem de yeni bir toplumsal ve siyasi kimlik oluşturma süreci olması bakımından",
        aciklama: "Metin hicretin iki boyutunu birlikte sunmaktadır: fiziksel güvenlik (kaçış) ve 'yeni toplumsal ve siyasi kimliğin şekillendiği deneyim' (kimlik inşası). Bu ikinci boyut, olayı salt kaçışın ötesine taşımaktadır. Diğer seçenekler metinde desteklenmeyen ya da metnin kapsamı dışındaki iddiaları içermektedir."
    },
    {
        soru: "\"Orta Çağ'daki büyük göç hareketleri incelendiğinde, göç güzergâhlarının büyük ölçüde önceden var olan iletişim ve ticaret ağlarıyla örtüştüğü görülür. Tamamen bilinmedik coğrafyalara gerçekleşen göçler son derece istisnaidir; göçmen topluluklar genellikle tanıdık rotaları, daha önce kurulmuş bağlantıları ve yerleşik bilgi ağlarını takip etti.\"\n— Nora Berend (ed.), Christianization and the Rise of Christian Monarchy, Cambridge University Press, 2007\n\nMetne göre Orta Çağ göç güzergâhları hakkında hangi çıkarım yapılabilir?",
        secenekler: [
            "Göçmenler her zaman en kısa ve direkt yolu tercih etti.",
            "Göç güzergâhları rastlantısal değil; önceden var olan ticaret ağları ve tanıdık bağlantılar tarafından biçimlendi.",
            "Büyük göçlerin tamamı deniz yoluyla gerçekleşti.",
            "Göçmenler ticaret yollarını kasıtlı olarak kullanmaktan kaçındı.",
            "Göç güzergâhları yalnızca askeri stratejiye göre belirlendi."
        ],
        cevap: "Göç güzergâhları rastlantısal değil; önceden var olan ticaret ağları ve tanıdık bağlantılar tarafından biçimlendi.",
        aciklama: "Metin, göçlerin 'önceden var olan iletişim ve ticaret ağlarıyla örtüştüğünü' ve tamamen bilinmedik güzergâhların istisna olduğunu belirtmektedir. Bu, göçü önceki sosyal altyapıyla bağlantılı bir süreç olarak çerçeveler. A seçeneğinin 'en kısa yol' iddiası metinde desteklenmemektedir."
    },
    {
        soru: "\"Göç tarihçileri uzun süre boyunca yazılı kaynakların sunduğu 'fatihin bakış açısı'na mahkûm kaldı. Kazananların yazdığı belgeler, kaybedenlerin deneyimini, göç eden toplulukların kendi sesini ve yerinden edilmenin insani boyutlarını görünmez kılıyordu. Arkeoloji ve dilbilim bu sessizliği kısmen doldurmaya başlayana dek göç tarihi, iktidarsızların tarihine yabancı kaldı.\"\n— Patrick Geary, Phantoms of Remembrance: Memory and Oblivion at the End of the First Millennium, Princeton University Press, 1994\n\nGeary'nin eleştirisi, tarih yazımında hangi yapısal soruna dikkat çekmektedir?",
        secenekler: [
            "Yazılı kaynakların arkeolojik bulgularla çeliştiğinde değersiz sayılması gerektiğine",
            "Tarih yazımının yalnızca iktidar sahiplerinin belgelerine dayanmasının iktidarsızların deneyimini sistematik biçimde dışladığına",
            "Dilbilimin göç tarihini anlayabilmek için tek güvenilir kaynak olduğuna",
            "Kazananların belgelerinin her zaman tarafsız ve güvenilir olduğuna",
            "Göç tarihinin yalnızca iktisadi yöntemlerle incelenmesi gerektiğine"
        ],
        cevap: "Tarih yazımının yalnızca iktidar sahiplerinin belgelerine dayanmasının iktidarsızların deneyimini sistematik biçimde dışladığına",
        aciklama: "Geary'nin eleştirisi, kaynak üretimindeki güç asimetrisine odaklanmaktadır: kazananların yazdığı belgeler tarih yazımına egemen olurken kaybedenlerin sesi susturulmaktadır. 'Fatihin bakış açısı' ifadesi bu egemenliği simgeler. Öğrenciden kaynak eleştirisi ve güç-bilgi ilişkisine dair bu üst-düzey farkındalığı kavraması beklenmektedir."
    },
    {
        soru: "\"Berber kabilelerinin Kuzey Afrika bozkırları ile Akdeniz kıyıları arasındaki mevsimlik göçleri, Orta Çağ boyunca hem İslam öncesi hem de İslam sonrası dönemlerde kesintisiz biçimde sürdü. Bu göçler; ticaret ile hayvancılığı, siyasi sadakati ve kültürel kimliği birbirine bağlayan karmaşık bir ağ üzerinde işliyordu. Arap fethinin bu sistemi dönüştürdüğü doğrudur; ama yok etmediği de bir o kadar doğrudur.\"\n— Elizabeth Fentress, Numidia and the Roman World, Oxford University Press, 1979\n\nMetne göre Berber göçlerinin Arap fethiyle ilişkisi hakkında hangi yorum en doğrudur?",
        secenekler: [
            "Arap fetihleri Berber göç geleneğini tamamen ortadan kaldırdı.",
            "Arap fetihleri Berber göç sistemini dönüştürdü ama var olan sürekliliği büsbütün silmedi.",
            "Berber toplulukları Arap fethinden sonra göç etmeyi bıraktı.",
            "Arap fetihleri Berber göç güzergâhlarını İslam öncesiyle birebir aynı bıraktı.",
            "Berber göçleri yalnızca ekonomik nedenlerle gerçekleşiyordu."
        ],
        cevap: "Arap fetihleri Berber göç sistemini dönüştürdü ama var olan sürekliliği büsbütün silmedi.",
        aciklama: "Metin 'dönüştürdüğü doğrudur; ama yok etmediği de bir o kadar doğrudur' ifadesiyle hem değişim hem de süreklilik boyutunu eş ağırlıkla sunmaktadır. Tarihsel değişimi 'tamamen yıkım' ya da 'tamamen süreklilik' olarak okuyan A ve D seçenekleri bu dengeli tabloyu yansıtamamaktadır."
    },
    {
        soru: "\"Orta Çağ'da Yahudi toplulukların Avrupa içindeki hareketleri, büyük ölçüde dışlama ve sürgün politikalarının ürünüydü. İngiltere'den 1290'da, Fransa'dan 1306'da ve İspanya'dan 1492'de gerçekleşen sürgünler; bu toplulukları Osmanlı topraklarına, Kuzey Afrika'ya ve Doğu Avrupa'ya taşıdı. Bu zoraki diaspora, Yahudi kültürel mirasının geniş bir coğrafyaya yayılmasına da zemin hazırladı.\"\n— Jonathan Ray, The Sephardic Frontier: The Reconquista and the Jewish Community in Medieval Iberia, Cornell University Press, 2006\n\nMetne göre Orta Çağ Yahudi sürgünlerinin kültürel bir boyutu da olduğu söylenebilir; bu boyut nedir?",
        secenekler: [
            "Yahudi toplulukların sürgün edildikleri ülkelerin kültürünü tamamen benimsemesi",
            "Zoraki diasporanın, Yahudi kültürel mirasının geniş bir coğrafyaya taşınmasına istem dışı zemin hazırlaması",
            "Sürgünlerin Yahudi kültürel kimliğini tamamen silmesi",
            "Yahudi toplulukların sürgün edildikleri yerlerde asimile olmayı reddederek izole yaşaması",
            "Bu sürgünlerin Orta Çağ boyunca tamamen farklı nedenlerle gerçekleşmesi"
        ],
        cevap: "Zoraki diasporanın, Yahudi kültürel mirasının geniş bir coğrafyaya taşınmasına istem dışı zemin hazırlaması",
        aciklama: "Metin, zorunlu sürgünün istem dışı bir sonuç olarak kültürel mirasın geniş coğrafyaya yayılmasına zemin hazırladığını belirtmektedir. Bu, bir felaketin beklenmedik kültürel etkisini tartışan diyalektik bir tarih okumasıdır. 'Zemin hazırladı' ifadesi bu istem dışı etkiyi vurgulamaktadır."
    },
    {
        soru: "\"Orta Çağ'da göç yalnızca bir felaket ya da fırsat olarak değil; zaman zaman bilinçli bir toplumsal yeniden örgütlenme stratejisi olarak da kullanıldı. Orta Avrupa'nın kolonizasyon dalgası sırasında Alman çiftçi ve zanaatkârlar, Bohemya, Polonya ve Macaristan'daki hükümdarlara davet edilerek yeni kentlerin kurulmasında ve tarımsal verimliliğin artırılmasında etkin rol üstlendi.\"\n— Robert Bartlett, The Making of Europe: Conquest, Colonization and Cultural Change, 950–1350, Princeton University Press, 1993\n\nMetne göre Orta Çağ Avrupa'sındaki kolonizasyon dalgasının ayırt edici özelliği nedir?",
        secenekler: [
            "Bu sürecin yalnızca dinî amaçlarla düzenlenmiş olması",
            "Alman çiftçi ve zanaatkârların hükümdar daveti üzerine belirli işlevleri üstlenmek amacıyla göç etmesi",
            "Kolonizasyonun zorunlu sürgün biçiminde gerçekleşmesi",
            "Bu hareketin yalnızca askeri sınıfı kapsayıp sivil nüfusu içermemesi",
            "Kolonizasyonun Orta Avrupa'yı siyasi açıdan parçalaması"
        ],
        cevap: "Alman çiftçi ve zanaatkârların hükümdar daveti üzerine belirli işlevleri üstlenmek amacıyla göç etmesi",
        aciklama: "Metin göçü 'davet edilme' ve 'etkin rol üstlenme' kavramlarıyla çerçevelemekte; bu göçü belirli bir işlevi yerine getirmek amacıyla planlı biçimde gerçekleştirilen bir hareket olarak sunmaktadır. Bu, göçü yalnızca zorunluluk ya da kaçış olarak okuyan kalıplaşmış anlatıların ötesine geçen bir örnektir."
    },
    {
        soru: "\"Büyük nüfus hareketlerinin ekonomik etkilerini ölçmek, Orta Çağ tarihçilerinin en zorlu görevlerinden biridir. Yerleşim bölgesi terk edildiğinde, tarım arazileri işlevsiz kaldığında ya da zanaatkâr nüfus çözüldüğünde bunların ekonomik maliyeti belgelere yansımaz; çünkü kayıplar çoğunlukla sessizce gerçekleşir. Tarih yazımı var olanı kayıt altına alır; yok olanı değil.\"\n— Michael McCormick, Origins of the European Economy: Communications and Commerce, AD 300–900, Cambridge University Press, 2001\n\nMetne göre Orta Çağ göçlerinin ekonomik etkilerini belgelemenin önündeki temel engel nedir?",
        secenekler: [
            "Bu dönemin ekonomik belgelerinin sonradan bilinçli olarak imha edilmiş olması",
            "Ekonomik kaybın çoğunlukla sessizce ve iz bırakmadan gerçekleşmesi; tarih yazımının ise varlıkları değil yoklukları kaydetmekte yetersiz kalması",
            "Orta Çağ ekonomisinin tamamen takas sistemine dayanması nedeniyle ölçülememesi",
            "Tarihçilerin ekonomik analizi tarih yazımının dışında tutması",
            "Göçlerin yalnızca artı değer üreten sektörleri etkilemesi"
        ],
        cevap: "Ekonomik kaybın çoğunlukla sessizce ve iz bırakmadan gerçekleşmesi; tarih yazımının ise varlıkları değil yoklukları kaydetmekte yetersiz kalması",
        aciklama: "Metin 'tarih yazımı var olanı kaydeder; yok olanı değil' diyerek tarihsel belgelemenin yapısal bir zaafını ortaya koymaktadır: kayıplar sessizce gerçekleştiğinde belgesel iz bırakmaz ve bu nedenle ölçülemez. Öğrenciden tarih yazımının epistemolojik sınırlarını kavraması beklenmektedir."
    },
    {
        soru: "\"Selahaddin'in 1187'de Kudüs'ü geri alması, yalnızca askerî bir zafer değildi. Zafer sonrasında şehirde yaşayan Hristiyan halka gösterilen göreceli hoşgörü —can ve mal güvencesi— dönemin kronikçilerini bile şaşırttı. Bu davranış biçimi, siyasi hesapların yanı sıra bilinçli bir meşruiyet inşası stratejisinin de parçasıydı.\"\n— Anne-Marie Eddé, Saladin, Harvard University Press, 2011\n\nMetne göre Selahaddin'in Kudüs'ü fetheden olarak sergilediği hoşgörülü tutumun arka planındaki çok boyutlu nedeni en iyi hangi seçenek yansıtmaktadır?",
        secenekler: [
            "Selahaddin'in Hristiyan halkı potansiyel müttefik olarak görmesi",
            "Hem insani değerler hem de bilinçli bir siyasi meşruiyet inşası stratejisinin bir arada etkili olması",
            "Selahaddin'in askerî zafer kazandıktan sonra güce ihtiyaç duymadığını düşünmesi",
            "Dönemin kronikçilerinin abartılı anlatılar üretmesiyle açıklanabilmesi",
            "Bu tutumun İslam hukukunun zorunlu kıldığı bir uygulama olmasından kaynaklanması"
        ],
        cevap: "Hem insani değerler hem de bilinçli bir siyasi meşruiyet inşası stratejisinin bir arada etkili olması",
        aciklama: "Metin, hoşgörülü tutumu 'siyasi hesapların yanı sıra bilinçli bir meşruiyet inşası stratejisi' olarak tanımlamaktadır. Bu 'yanı sıra' ifadesi, tek bir açıklamayı yeterli görmeyip çok nedenli bir yorum yapılmasını gerektirmektedir. Diğer seçenekler bu bütünlüklü tabloyu tek bir nedenle çözümlemeye çalışmaktadır."
    },
    {
        soru: "\"Orta Çağ devletlerinde taht mücadelesi yalnızca bir iktidar savaşı değil; aynı zamanda meşruiyetin ne anlama geldiğini belirleyen bir süreçti. Kimin hükümdar olacağını belirleyen ölçütler —soyun üstünlüğü, seçim, fetih ya da ilahi işaret— farklı siyasi kültürlerde farklı biçimler aldı ve bu farklılık, hanedanlıkların hem güçlenmesine hem de çöküşüne zemin hazırladı.\"\n— Georges Duby, France in the Middle Ages 987–1460, Blackwell, 1991\n\nMetne göre Orta Çağ taht mücadelelerinin yalnızca iktidar savaşı olarak değerlendirilmesinin sınırlılığı nedir?",
        secenekler: [
            "Taht mücadelelerinin çoğunlukla savaş yerine müzakereyle çözülmesi",
            "Bu mücadelelerin aynı zamanda meşruiyetin ne olduğunu tanımlayan ve farklı kültürlerde farklı biçimler alan bir süreç olması",
            "Orta Çağ taht mücadelelerinin modern anlamda güç siyasetiyle hiçbir ilgisi olmaması",
            "Taht mücadelelerinin yalnızca küçük hanedanlıklar arasında yaşanmış olması",
            "Bu mücadelelerin ekonomik nedenlerinin siyasi nedenlerden her zaman ağır basması"
        ],
        cevap: "Bu mücadelelerin aynı zamanda meşruiyetin ne olduğunu tanımlayan ve farklı kültürlerde farklı biçimler alan bir süreç olması",
        aciklama: "Metin taht mücadelesini 'meşruiyetin ne anlama geldiğini belirleyen süreç' olarak tanımlamakta ve bu meşruiyet ölçütlerinin kültüre göre farklılaştığını belirtmektedir. Bu çerçeve, mücadeleyi salt iktidar savaşından kavramsal bir zemin tartışmasına dönüştürmektedir."
    },
    {
        soru: "\"Orta Çağ'da bir şehrin teslim olması çoğunlukla uzun bir kuşatmanın değil, müzakerenin ürünüydü. Komutanlar, kaynaklarının tükenme noktasını hesaplar; savunucular, onurlu bir teslimiyetin şartlarını pazarlık ederdi. Bu çerçevede Orta Çağ savaşı, savaş meydanındaki çarpışmadan çok, müzakere, ittifak ve ikmal stratejileri üzerinden şekilleniyordu.\"\n— Jim Bradbury, The Medieval Siege, Boydell Press, 1992\n\nMetne göre Orta Çağ kuşatma savaşının modern savaş anlayışından ayrılan en belirgin özelliği nedir?",
        secenekler: [
            "Kuşatmaların her zaman saldırganın zaferiyle sonuçlanması",
            "Teslimiyetin savaş meydanı çatışmasından çok müzakere, kaynak hesabı ve diplomatik pazarlık yoluyla şekillenmesi",
            "Orta Çağ'da kalelerin hiçbir zaman düşürülememesi",
            "Kuşatmaların yalnızca dinî amaçlarla yürütülmesi",
            "Modern teknolojinin yokluğunun Orta Çağ savaşlarını anlamsız kılması"
        ],
        cevap: "Teslimiyetin savaş meydanı çatışmasından çok müzakere, kaynak hesabı ve diplomatik pazarlık yoluyla şekillenmesi",
        aciklama: "Metin, Orta Çağ savaşının 'çarpışmadan çok müzakere, ittifak ve ikmal stratejileri üzerinden şekillendiğini' belirtmektedir. Teslim olma sürecinde 'kaynak hesabı' ve 'onurlu teslimiyet şartları' müzakeresi bu alternatif dinamiğin somut biçimleridir."
    },
    {
        soru: "\"Orta Çağ İslam dünyasında 'adalet çemberi' kavramı, siyasi iktidara ilişkin köklü bir öğretiyi özetliyordu: adil yönetim refah doğurur, refah vergi geliri sağlar, vergi geliri orduyu besler, ordu devleti ayakta tutar, devlet adaleti mümkün kılar. Bu döngüsel şema, ekonomi ile siyaset arasındaki ilişkiyi keskin biçimde görselleştiriyordu.\"\n— Antony Black, The History of Islamic Political Thought, Edinburgh University Press, 2001\n\n'Adalet çemberi' kavramına göre Orta Çağ İslam siyaset düşüncesinde ekonomi ile siyaset arasındaki ilişki nasıl kurulmaktadır?",
        secenekler: [
            "Ekonomi ve siyaset birbirinden bağımsız alanlardır; biri diğerini etkilemez.",
            "Siyasi iktidar ekonomiye tamamen bağımlıdır; ekonomi çöküşe geçince devlet de çöker.",
            "Adalet, refah, vergi, ordu ve devlet birbirini karşılıklı besleyen döngüsel bir ilişki içinde bağlıdır.",
            "Ordu, adalet ve ekonominin üzerinde mutlak belirleyici konumundadır.",
            "Bu şema yalnızca İslam'ın ilk yüzyıllarında geçerli olup sonraki dönemlerde terk edilmiştir."
        ],
        cevap: "Adalet, refah, vergi, ordu ve devlet birbirini karşılıklı besleyen döngüsel bir ilişki içinde bağlıdır.",
        aciklama: "'Adalet çemberi', beş unsurun —adalet, refah, vergi, ordu, devlet— birbirini döngüsel biçimde beslediği bir model sunar. Hiçbir unsur diğerinin üzerinde mutlak belirleyici değildir; sistem karşılıklı bağımlılık üzerine kuruludur. B ve D seçenekleri bu döngüsel ilişkiyi tek yönlü nedenselliğe indirgemektedir."
    },
    {
        soru: "\"14. yüzyıl Avrupa'sında yaşanan siyasi krizler —papalığın Avignon'a taşınması, Büyük Bölünme ve Konsilerizm hareketi— kilise otoritesinin ciddi biçimde sorgulandığı bir döneme denk geldi. Bu süreçte ortaya çıkan tartışmalar; otoritenin kaynağı, meşruiyet sınırları ve kurumsal reformun imkânı gibi meseleleri gündemin merkezine taşıdı.\"\n— Brian Tierney, Foundations of the Conciliar Theory, Cambridge University Press, 1955\n\nMetne göre 14. yüzyıl kilise krizinin daha geniş siyasi önemi nedir?",
        secenekler: [
            "Bu krizin yalnızca kilise içi yönetim sorunlarıyla sınırlı kalması",
            "Krizin tetiklediği tartışmaların otorite, meşruiyet ve kurumsal reform gibi evrensel siyasi meselelere kapı aralamış olması",
            "Bu krizin Avrupa'da dinin tamamen önemini yitirmesine yol açması",
            "Konsilerizm hareketinin tek adam yönetimine karşı demokratik bir alternatif sunması",
            "Avignon papalığının Fransa'nın İtalya üzerinde tam denetim kurmasını sağlaması"
        ],
        cevap: "Krizin tetiklediği tartışmaların otorite, meşruiyet ve kurumsal reform gibi evrensel siyasi meselelere kapı aralamış olması",
        aciklama: "Metin kilise krizinin yol açtığı tartışmaların 'otorite kaynağı, meşruiyet sınırları ve kurumsal reform' gibi geniş kapsamlı siyasi meselelere uzandığını belirtmektedir. Bu çerçeve, kilise krizini salt dinî değil evrensel siyaset teorisi açısından da önemli kılar. A seçeneği bu genişlemeyi görmezden gelmektedir."
    },
    {
        soru: "\"Orta Çağ'da bir savaşın 'meşru savaş' olup olmadığını belirleyen ölçütler, salt askerî değil teolojik ve hukuki çerçevede belirlendi. Aziz Augustinus'un erken Orta Çağ'da temellendirdiği 'bellum iustum' (meşru savaş) kuramı; savaşın gerekçesi, ilan edeni ve yürütülüş biçimi açısından sınırlar çiziyordu. Bu kuram, hem savaşın başlatılmasını kısıtlamayı hem de başlatıldığında nasıl yürütüleceğini belirlemeyi amaçlıyordu.\"\n— Frederick H. Russell, The Just War in the Middle Ages, Cambridge University Press, 1975\n\nMetne göre 'bellum iustum' kuramının Orta Çağ savaş anlayışına katkısı nedir?",
        secenekler: [
            "Tüm savaşları meşru ilan ederek Orta Çağ'da savaşı sıradan bir siyasi araç haline getirmesi",
            "Savaşın gerekçesi, başlatanı ve yürütülüş biçimi üzerinde teolojik ve hukuki sınırlar çizerek onu denetim altına almaya çalışması",
            "Bu kuramın yalnızca Haçlı Seferleri için geçerli olup diğer savaşlarda uygulanmaması",
            "Bellum iustum'un savaşı tamamen ortadan kaldıran bir barış öğretisi sunması",
            "Bu kuramın papanın savaş ilan etme yetkisini sınırlandırması"
        ],
        cevap: "Savaşın gerekçesi, başlatanı ve yürütülüş biçimi üzerinde teolojik ve hukuki sınırlar çizerek onu denetim altına almaya çalışması",
        aciklama: "Metin kuramın 'savaşın gerekçesi, ilan edeni ve yürütülüş biçimi açısından sınırlar çizdiğini' belirtmektedir. Bu üç boyut birlikte hem savaşın başlatılmasını hem de yürütülmesini denetim altına almayı amaçlamaktadır. A seçeneği metnin tam tersi bir iddia sunmaktadır."
    },
    {
        soru: "\"Orta Çağ'da donanma gücü, kara gücünden daha az görünür ama eşit derecede belirleyiciydi. Venedik, Ceneviz ve Aragonlu donanmaların Akdeniz'deki hâkimiyeti; ticaret güzergâhlarını, kolonileri ve siyasi ittifakları doğrudan şekillendirdi. Deniz gücü olmadan Akdeniz'in siyasi coğrafyasını anlamak mümkün değildir.\"\n— John H. Pryor, Geography, Technology and War: Studies in the Maritime History of the Mediterranean, Cambridge University Press, 1988\n\nMetne göre Orta Çağ Akdeniz siyasi tarihini anlamak için donanma gücünün göz ardı edilmesi neden yanıltıcı olur?",
        secenekler: [
            "Deniz gücünün kara gücünden her açıdan üstün olduğu bu dönemde belirleyici olduğu için",
            "Donanma gücünün ticaret, kolonicilik ve siyasi ittifakları doğrudan biçimlendirmesi nedeniyle Akdeniz siyasetinin bu boyutsuz anlaşılamayacağı için",
            "Orta Çağ'da kara ordularının gereksiz hâle geldiği için",
            "Donanmanın yalnızca ticaret amaçlı kullanıldığı için siyasi tarih açısından önemsiz olduğu için",
            "Venedik ve Cenova'nın Akdeniz'i tamamen kontrol ettiği için diğer güçlerin önemsiz kaldığı için"
        ],
        cevap: "Donanma gücünün ticaret, kolonicilik ve siyasi ittifakları doğrudan biçimlendirmesi nedeniyle Akdeniz siyasetinin bu boyutsuz anlaşılamayacağı için",
        aciklama: "Metin donanma gücünün 'ticaret güzergâhlarını, kolonileri ve siyasi ittifakları doğrudan şekillendirdiğini' ve 'deniz gücü olmadan Akdeniz'in siyasi coğrafyasını anlamanın mümkün olmadığını' belirtmektedir. A seçeneği metnin böyle bir üstünlük iddiası içermediğini görmezden gelmektedir."
    },
    {
        soru: "\"Orta Çağ'da devlet kurma süreci, günümüzün kurumsal devlet anlayışından köklü biçimde ayrılıyordu. Orta Çağ'da 'devlet', soyut ve kalıcı bir kurum değil; büyük ölçüde belirli bir hükümdarın kişisel ağları, sadakatler ve anlık siyasi koşullar etrafında şekillenen ve hükümdarın ölümüyle sıklıkla yeniden yapılanmak zorunda kalan dinamik bir organizmaydı.\"\n— Susan Reynolds, Fiefs and Vassals: The Medieval Evidence Reinterpreted, Oxford University Press, 1994\n\nMetne göre Orta Çağ 'devleti'ni modern devlet anlayışıyla özdeşleştirmenin en temel riski nedir?",
        secenekler: [
            "Bu özdeşleştirmenin Orta Çağ'ı siyasi açıdan anlamsız göstermesi",
            "Orta Çağ siyasi yapısının kişisel sadakat ağlarına ve anlık koşullara dayalı dinamik yapısının, modern kurumsal devlet kalıbıyla anakronistik biçimde yorumlanması",
            "Modern devlet anlayışının Orta Çağ'dan doğrudan miras alındığının kabul edilmesi",
            "Bu özdeşleştirmenin Orta Çağ monarşisini demokrasinin öncüsü olarak sunması",
            "Orta Çağ devletlerinin herhangi bir hukuki çerçeve olmaksızın faaliyet gösterdiğinin varsayılması"
        ],
        cevap: "Orta Çağ siyasi yapısının kişisel sadakat ağlarına ve anlık koşullara dayalı dinamik yapısının, modern kurumsal devlet kalıbıyla anakronistik biçimde yorumlanması",
        aciklama: "Metin, Orta Çağ siyasi yapısının 'soyut ve kalıcı bir kurum' yerine 'kişisel ağlar, sadakatler ve anlık koşullar' etrafında şekillendiğini ve hükümdarın ölümüyle yeniden yapılanmak zorunda kaldığını vurgulamaktadır. Modern devlet kategorisini bu yapıya uygulamak, farklı bir olguyu tanıdık bir kalıba zorla sokmak anlamına gelir: anakronizm riski."
    },
    {
        soru: "\"Ortaçağ ticaret dünyasında güven, her şeyden önce geliyordu. Bir tüccar, tanımadığı bir şehirde yerel bir ortak bulabilmek için aile bağlarını, ortak dini kimliği ya da aynı lonca üyeliğini referans gösterirdi. Para ve meta elden ele geçmeden önce, güven mutlaka yerini bulmuş olurdu.\"\n— Avner Greif, 'Reputation and Coalitions in Medieval Trade: Evidence on the Maghribi Traders', Journal of Economic History, 49(4), 1989\n\nMetne göre Orta Çağ ticaretinde güven mekanizmasının temel işlevi neydi?",
        secenekler: [
            "Devletin ticaret üzerindeki denetimini pekiştirmek",
            "Tanıdık olmayan ortamda ticaret yapılmasını mümkün kılan bir sosyal zemin oluşturmak",
            "Dini ayrılıkların ticarette rekabet avantajına dönüştürülmesini sağlamak",
            "Vergi kaçakçılığını kolaylaştırmak",
            "Rekabeti sınırlayarak tüccarların karlarını garantilemek"
        ],
        cevap: "Tanıdık olmayan ortamda ticaret yapılmasını mümkün kılan bir sosyal zemin oluşturmak",
        aciklama: "Metin, güvenin aile bağı, din ya da lonca üyeliği aracılığıyla inşa edildiğini ve meta akışından önce devreye girdiğini belirtmektedir. Bu, güveni ticaretin ön koşulu olarak konumlandırmakta; tanıdık olmayan ortamlarda ticaret yapılabilmesinin sosyal zeminini açıklamaktadır."
    },
    {
        soru: "\"Orta Çağ boyunca Cenova ve Venedik arasındaki rekabet salt ekonomik değil; jeopolitik, diplomatik ve zaman zaman askerî bir nitelik taşıyordu. Bu iki deniz cumhuriyeti, Doğu Akdeniz'de ticaret ayrıcalıkları ve üs edinme hakkı için hem Bizans hem de Müslüman hükümdarlıklarla ittifak kurmaktan çekinmedi; bu durum, 'Hristiyan dayanışması' söylemini pragmatik hesapların önünde bırakıyordu.\"\n— David Jacoby, 'Venetian Commercial Expansion in the Eastern Mediterranean, 8th–11th Centuries', in Byzantine Trade, 4th–12th Centuries, Ashgate, 2009\n\nMetne göre Cenova-Venedik rekabetinin Orta Çağ siyaset anlayışına dair ortaya koyduğu en çarpıcı bulgu nedir?",
        secenekler: [
            "Hristiyan cumhuriyetlerin her zaman ortak dinî kimlik temelinde hareket ettiğinin kanıtlanması",
            "Ekonomik ve stratejik çıkarların, dini ittifak beklentilerinin önüne geçebildiğini göstermesi",
            "Bu iki şehrin rekabetinin Doğu Akdeniz ticaretini tamamen durdurduğunun görülmesi",
            "Cenova ve Venedik'in Bizans'a karşı her zaman birlikte hareket ettiğinin anlaşılması",
            "Bu rekabetin sonunda Venedik'in Cenova'yı kalıcı olarak yok etmesiyle sona ermesi"
        ],
        cevap: "Ekonomik ve stratejik çıkarların, dini ittifak beklentilerinin önüne geçebildiğini göstermesi",
        aciklama: "Metin, iki Hristiyan cumhuriyetin hem Bizans hem de Müslüman hükümdarlıklarla pragmatik ittifaklar kurduğunu belirtmekte ve 'Hristiyan dayanışması söylemini pragmatik hesapların önünde bırakıyordu' ifadesiyle ekonomik-stratejik çıkarın dini kimliğin üzerine çıkabildiğini göstermektedir."
    },
    {
        soru: "\"Kuzey Afrika ile Avrupa arasındaki Orta Çağ ticareti, olduğundan çok daha az araştırılmış bir alandır. Bu ticaret yalnızca altın ve kölelerle sınırlı değildi; fildişi, boya maddeleri, tuz ve zanaatkâr ürünler de bu güzergâhta dolaşıyordu. Akdeniz'i bir bariyer olarak değil, bir köprü olarak görmek, bu ticaretin neden bu denli canlı kaldığını açıklar.\"\n— Constance Hoffman Berman, Medieval Agriculture, the Southern French Countryside and the Early Cistercians, American Philosophical Society, 1986\n\nMetne göre Kuzey Afrika-Avrupa ticaretini anlamada 'Akdeniz = köprü' metaforunun işlevi nedir?",
        secenekler: [
            "Akdeniz'in her iki kıyısı arasında siyasi birlik bulunduğunu kanıtlamak",
            "Akdeniz'i bölünme değil bağlantı unsuru olarak okuyarak bu ticaretin canlılığını açıklamak",
            "Ticaretin neden yalnızca kuzey-güney yönünde aktığını göstermek",
            "Avrupa'nın Afrika üzerindeki tarihsel üstünlüğünü pekiştirmek",
            "Akdeniz'in coğrafi koşullarının ticareti her zaman engellediğini kabul etmek"
        ],
        cevap: "Akdeniz'i bölünme değil bağlantı unsuru olarak okuyarak bu ticaretin canlılığını açıklamak",
        aciklama: "Metin, Akdeniz'i 'bariyer' değil 'köprü' olarak okumanın bu ticaretin canlılığını açıkladığını belirtmektedir. Coğrafyayı engel değil bağlantı unsuru olarak görmek, farklı bir analitik çerçeve sunar. Bu, coğrafyaya atfedilen anlamın tarihi yorumlama biçimini nasıl değiştirdiğine dair metodolojik bir farkındalığa da işaret etmektedir."
    },
    {
        soru: "\"Orta Çağ'da mal fiyatlarının belirlenmesi, piyasa güçlerinin yanı sıra ahlaki ve dini normlarla da şekilleniyordu. Skolastik düşünürler 'iustum pretium' (adil fiyat) kavramı üzerinde uzun tartışmalar yürüttü; bu kavram, alıcı ile satıcıyı eşit derecede koruyan ve toplumsal denge ile ticarî ahlakı gözeten bir fiyat anlayışını ifade ediyordu.\"\n— Odd Langholm, Economics in the Medieval Schools: Wealth, Exchange, Value, Money and Usury, Brill, 1992\n\nMetne göre 'iustum pretium' kavramı, Orta Çağ iktisat anlayışı ile modern piyasa ekonomisi anlayışı arasındaki hangi temel farkı örneklemektedir?",
        secenekler: [
            "Orta Çağ'da fiyatların devlet tarafından belirlendiği, modern ekonomide ise serbest piyasanın belirleyici olduğu farkı",
            "Fiyat belirlemenin Orta Çağ'da ahlaki ve dini normlarla iç içe geçmesi; oysa modern piyasa ekonomisinin ahlaki boyutu dışlayan salt teknik bir süreç olarak kurulması",
            "Orta Çağ'da fiyatların hiçbir zaman piyasa dinamiklerine göre oluşmadığının kanıtlanması",
            "Modern piyasa ekonomisinin iustum pretium kavramını benimseyerek geliştirdiği gerçeğinin ortaya konması",
            "Bu kavramın yalnızca İslam iktisadında karşılık bulduğu ve Batı skolastiğiyle ilgisinin olmadığı"
        ],
        cevap: "Fiyat belirlemenin Orta Çağ'da ahlaki ve dini normlarla iç içe geçmesi; oysa modern piyasa ekonomisinin ahlaki boyutu dışlayan salt teknik bir süreç olarak kurulması",
        aciklama: "'İustum pretium', fiyat belirlemeyi salt piyasa mekanizmasına değil ahlaki ve dini normlara da bağlayan bir kavramdır. Modern piyasa ekonomisi ise fiyat belirlemeyi ahlaki değerlendirmenin dışında teknik bir süreç olarak kurar. Bu iki anlayış arasındaki fark, Orta Çağ ile modern iktisadın temel ayrışma noktalarından birini oluşturmaktadır."
    },
    {
        soru: "\"Orta Çağ'da Doğu ile Batı arasındaki ticaretin en az anlaşılan boyutlarından biri, bilgi ve teknoloji transferinin ticari mal takasıyla eş zamanlı ve iç içe gerçekleşmesiydi. Bir Arap kervanı yalnızca baharat değil; matematiksel hesap yöntemleri, sulama teknikleri ve yeni bitki türleri hakkında bilgi de taşıyordu. Ticaret güzergâhları, erken dönem küreselleşmenin bilgi otoyollarıydı.\"\n— Andrew Watson, Agricultural Innovation in the Early Islamic World, Cambridge University Press, 1983\n\nMetne göre Orta Çağ ticaret güzergâhlarını 'bilgi otoyolu' olarak nitelendirmenin tarihsel temeli nedir?",
        secenekler: [
            "Tüccarların yalnızca ticari bilgi değil; tarım, matematik ve teknoloji alanlarındaki bilgileri de taşımış olması",
            "Tüccarların birbirinin dini inançlarını değiştirme amacı gütmesi",
            "Ticaret güzergâhlarının yalnızca kâğıt ve kitap taşımak için kullanılması",
            "Orta Çağ'da bilginin yalnızca manastırlar aracılığıyla aktarılabildiği",
            "Tüccarların çoğunlukla entelektüel amaçlarla yolculuk ettiği"
        ],
        cevap: "Tüccarların yalnızca ticari bilgi değil; tarım, matematik ve teknoloji alanlarındaki bilgileri de taşımış olması",
        aciklama: "Metin, tüccarların baharat dışında 'matematiksel hesap yöntemleri, sulama teknikleri ve bitki bilgisi' taşıdığını vurgulayarak ticaret güzergâhlarının yalnızca mal değil bilgi de aktaran bir altyapı olduğunu göstermektedir. 'Bilgi otoyolu' metaforu bu çok boyutlu aktarımı özetlemektedir."
    },
    {
        soru: "\"Orta Çağ'da Çin'in ipek ihracatı yalnızca bir ticaret meselesi değil, bir diplomasi aracıydı. Tang hanedanlığı döneminde ipek; komşu hükümdarlara verilen hediyeler, ittifak karşılıkları ve elçilere sunulan armağanlar aracılığıyla ekonomik değerinin çok ötesinde siyasi işlevler üstlendi. İpek, yalnızca satın alınan değil; kazanılan, verilip alınan ve bazen zorla talep edilen bir meta olarak farklı bir anlam ekonomisi içinde dolaşıma girdi.\"\n— Xinru Liu, The Silk Road in World History, Oxford University Press, 2010\n\nMetne göre Tang döneminde ipeğin salt ticari bir meta olmaktan çıkıp daha geniş bir anlam ekonomisine girmesinin nedeni nedir?",
        secenekler: [
            "İpeğin bu dönemde yalnızca Budist ritüellerde kullanılmaya başlanması",
            "İpeğin hediye, ittifak karşılığı ve diplomatik araç olarak kullanılmasıyla siyasi ve simgesel değer kazanması",
            "Tang hanedanlığının ipeği ticari bir meta olmaktan çıkarıp tamamen devlet tekeline alması",
            "İpek fiyatlarının bu dönemde hızla yükselerek sıradan tüccarların erişiminin dışına çıkması",
            "İpeğin Avrupa pazarlarında dini sembolizm kazanarak kiliselerde kullanılması"
        ],
        cevap: "İpeğin hediye, ittifak karşılığı ve diplomatik araç olarak kullanılmasıyla siyasi ve simgesel değer kazanması",
        aciklama: "Metin ipeğin 'hediye, ittifak karşılığı ve armağan' işlevleriyle 'ekonomik değerinin çok ötesinde siyasi işlevler üstlendiğini' belirtmektedir. 'Satın alınan, verilen, alınan ve zorla talep edilen' dörtlüsü ipeğin birden fazla dolaşım biçiminin olduğunu göstermekte; bu da onu salt ticari kategorinin dışına taşımaktadır."
    },
    {
        soru: "\"Orta Çağ İslam dünyasında optik biliminin gelişimi, yalnızca ışığın fiziksel özelliklerini incelemekle sınırlı kalmadı. İbn el-Heysem'in Kitabü'l-Menazır adlı eseri; göz ile ışık arasındaki ilişkiyi, görsel algının nasıl çalıştığını ve aynaların geometrisini sistematik deney yöntemiyle araştırdı. Bu yaklaşım, gözlem ve deneyi kuramın önüne yerleştiren erken bir bilimsel tutumu temsil ediyordu.\"\n— David C. Lindberg, Theories of Vision from Al-Kindi to Kepler, University of Chicago Press, 1976\n\nMetne göre İbn el-Heysem'in optik çalışmalarının bilim tarihi açısından önemi nerede yatmaktadır?",
        secenekler: [
            "Antik Yunan optik kuramlarını olduğu gibi koruması ve aktarmasında",
            "Gözlem ve deneyi kuram üretiminin temeline yerleştiren erken bir bilimsel tutumu temsil etmesinde",
            "Optik bilimini tamamen felsefeden bağımsız bir disipline dönüştürmesinde",
            "İbn el-Heysem'in çalışmalarının Rönesans öncesinde Avrupa'ya hiç ulaşmamış olmasında",
            "Bu eserin yalnızca geometrik konuları ele alıp görsel algıyı dışarıda bırakmasında"
        ],
        cevap: "Gözlem ve deneyi kuram üretiminin temeline yerleştiren erken bir bilimsel tutumu temsil etmesinde",
        aciklama: "Metin, İbn el-Heysem'in 'gözlem ve deneyi kuramın önüne yerleştirdiğini' açıkça belirtmektedir. Bu, modern bilimsel yöntemin temel özelliği olarak kabul edilen deneysel doğrulamayı Orta Çağ'da zaten kullanan bir tutumu temsil etmektedir. A seçeneği metnin 'salt aktarım değil özgün araştırma' vurgusunu görmezden gelmektedir."
    },
    {
        soru: "\"Bir sabah şehre ilk ışık vurduğunda, duvarlar yalnızca taş olmaktan çıkar; sabah namazında okunan dua sesi ise sokakları görünmez bir ağla örer. Şehir, taştan ve sesten; görünenden ve görünmeyenden yapılmıştır. Biz de bunun farkında olmadan bu şehrin içinde kaybolur gider, kendimizi bulur ve yeniden kaybederiz.\"\n— Orhan Pamuk, İstanbul: Hatıralar ve Şehir, YKY, 2003\n\nBu pasajdan yola çıkarak Orta Çağ İslam kentleri hakkında hangi tarihsel çıkarım yapılabilir?",
        secenekler: [
            "İslam kentleri yalnızca fiziksel mekânlardan oluşan işlevsel yapılardı.",
            "İslam kentleri, fiziksel mekânla dini pratik ve kültürel deneyimin iç içe geçtiği çok katmanlı bir anlam dünyası sunuyordu.",
            "Orta Çağ İslam kentleri yalnızca dini mekânlardan ibaret olup ticari alanlara yer vermiyordu.",
            "Pamuk'un betimlemesi yalnızca İstanbul için geçerlidir; diğer İslam kentleri için uygulanamaz.",
            "Bu pasaj Orta Çağ'a değil yalnızca modern döneme ait izlenimler sunmaktadır."
        ],
        cevap: "İslam kentleri, fiziksel mekânla dini pratik ve kültürel deneyimin iç içe geçtiği çok katmanlı bir anlam dünyası sunuyordu.",
        aciklama: "Pamuk'un dili, kenti salt fiziksel altyapıdan ibaret görmeyip dua sesi, ışık ve gündelik deneyimi de mekânın kurucu unsurları olarak sunar. Bu çerçeve, Orta Çağ İslam kentlerinin de yalnızca taş ve çamurdan değil; dini pratikler, ritimler ve kültürel deneyimlerden inşa edildiğini tarihsel açıdan desteklemektedir. Edebi bir metnin tarihsel çıkarım için nasıl kullanılabileceğini sorgulayan bu soru, disiplinlerarası okuma becerisini ölçmektedir."
    },
    {
        soru: "\"Orta Çağ'da Avrupa'da Kilise, sanatın hem en büyük hamisi hem de en güçlü sansürcüsü konumundaydı. Dinî ikonografi için belirlenen kural ve standartlar, sanatçının yaratıcı özgürlüğünü sınırlıyor; ama aynı zamanda eserlerine geniş bir izleyici kitlesi kazandırıyordu. Bu gerilim, söz konusu dönemde üretilen sanatın hem boyun eğme hem de yaratıcı direnişin iz bıraktığı karmaşık bir ürün olmasını sağladı.\"\n— Cynthia Hahn, 'Visio Dei: Changes in Medieval Visuality', in Visuality Before and Beyond the Renaissance, Cambridge University Press, 2000\n\nMetne göre Orta Çağ'da kilisenin sanat üzerindeki etkisi hangi paradoksu yaratıyordu?",
        secenekler: [
            "Kilise desteği sanatçıları ekonomik güvenceye kavuştururken onları dini temalar dışında üretimden alıkoyuyordu.",
            "Kilise hem yaratıcılığı kısıtlayan kurallar koyuyor hem de bu kuralların içinde sanatçıların geniş kitlelere ulaşmasını sağlıyordu; bu gerilim hem boyun eğmeyi hem de direnişi barındıran eserler doğurdu.",
            "Kilise yalnızca hamiliği üstlenip sansür işlevini tamamen devlete bıraktı.",
            "Kilise sanatçıları özgür bıraktı ama üretilen eserlerin dağıtımını kontrol etti.",
            "Bu paradoks yalnızca İtalyan sanatçılar için geçerliydi; Kuzey Avrupa'da kilise etkisi daha sınırlıydı."
        ],
        cevap: "Kilise hem yaratıcılığı kısıtlayan kurallar koyuyor hem de bu kuralların içinde sanatçıların geniş kitlelere ulaşmasını sağlıyordu; bu gerilim hem boyun eğmeyi hem de direnişi barındıran eserler doğurdu.",
        aciklama: "Metin, kilisenin aynı anda hem sınırlayıcı (kural koyucu, sansürcü) hem de genişletici (geniş kitle sağlayan, hamiliği üstlenen) bir rol oynadığını ve bu çelişkili konumun sanatsal üretimi hem boyun eğme hem direniş içeren karmaşık bir ürüne dönüştürdüğünü ortaya koymaktadır."
    },
    {
        soru: "\"Orta Çağ'da matematik, doğanın dili olarak değil Tanrı'nın düzeninin yansıması olarak kavranıyordu. Sayıların gizemli anlam taşıdığı inancı —üçün kutsallığı, yedinin tamlığı, on ikinin evrensel düzeni— hem ilahiyatı hem de mimariyi, müziği ve takvim düzenlemelerini biçimlendirdi.\"\n— Umberto Eco, The Aesthetics of Thomas Aquinas, Harvard University Press, 1988\n\nMetne göre Orta Çağ'da sayılara gizemli anlam yüklenmesi hangi alanlarda somut etkiler doğurmuştur?",
        secenekler: [
            "Yalnızca ilahiyat alanında felsefi tartışmalara yol açmıştır.",
            "İlahiyat, mimari, müzik ve takvim gibi birden fazla alanda yapısal ve biçimsel bir iz bırakmıştır.",
            "Bu inanç yalnızca Hristiyan Avrupa'ya özgüdür; İslam ve Yahudi dünyasında hiçbir karşılığı yoktur.",
            "Sayıların gizemli anlamı matematiksel ilerlemeyi engelleyerek Orta Çağ'ı bilimsel açıdan geride bırakmıştır.",
            "Bu inanç yalnızca kilise mimarisini etkilemiş; diğer alanları dışarıda bırakmıştır."
        ],
        cevap: "İlahiyat, mimari, müzik ve takvim gibi birden fazla alanda yapısal ve biçimsel bir iz bırakmıştır.",
        aciklama: "Metin 'hem ilahiyatı hem de mimariyi, müziği ve takvim düzenlemelerini biçimlendirdi' diyerek sayısal-gizemci anlayışın çok alanlı etkisini listelemiştir. A ve E seçenekleri bu geniş kapsamı tek bir alanla sınırlandırmaktadır."
    },
    {
        soru: "\"Orta Çağ İslam coğrafyasında şiir, yalnızca estetik bir etkinlik değil; hafızanın, kimliğin ve toplumsal değerlerin aktarım aracıydı. Şairin toplumsal statüsü yüksekti; hükümdar saraylarında şairler hem övgü hem de eleştiri işlevi üstlenebilirdi. Bu bağlamda şiir, iktidarla hem iş birliği hem de gerilim içinde var olan bir dil alanı oluşturuyordu.\"\n— Suzanne Pinckney Stetkevych, The Poetics of Islamic Legitimacy: Myth, Gender and Ceremony in the Classical Arabic Ode, Indiana University Press, 2002\n\nMetne göre Orta Çağ İslam şiirinin en belirgin özelliği nedir?",
        secenekler: [
            "Şiirin yalnızca saray dışı halk kesimlerine hitap eden bir popüler sanat formu olması",
            "Şiirin hem iktidarla iş birliği hem de gerilim içinde var olan; hafıza, kimlik ve toplumsal değerlerin taşıyıcısı olması",
            "Şiirin Orta Çağ İslam dünyasında yalnızca dini ritüellerde işlev görmesi",
            "Şairlerin saray tarafından her zaman sansüre tabi tutulması",
            "Şiirin siyasi işlevinin bilimsel söylemle çelişmesi nedeniyle giderek önemsizleşmesi"
        ],
        cevap: "Şiirin hem iktidarla iş birliği hem de gerilim içinde var olan; hafıza, kimlik ve toplumsal değerlerin taşıyıcısı olması",
        aciklama: "Metin şiiri üç boyutuyla sunmaktadır: toplumsal işlev (hafıza, kimlik, değer aktarımı), statü (yüksek saygınlık) ve iktidarla ilişki (hem iş birliği hem gerilim). Bu çok boyutluluk, şiiri salt estetik kategorinin dışına taşımaktadır."
    },
    {
        soru: "\"Orta Çağ biliminde bir tezi kabul etmek için deneyin yeterliliği bugünkü anlamda tartışmalıydı. Skolastik geleneğin güçlü olduğu ortamlarda otorite —özellikle Aristoteles ve kutsal metin— deneysel gözlemin önünde geliyordu. Ancak bu tablo hiçbir zaman tam anlamıyla donuk değildi: Roger Bacon ve Albertus Magnus gibi düşünürler, gözlem ve deneyin teorik bilgiye katkısını savunmaya başladı.\"\n— A. C. Crombie, Robert Grosseteste and the Origins of Experimental Science, Oxford University Press, 1953\n\nMetne göre Orta Çağ bilim anlayışında otorite ile gözlem arasındaki ilişki nasıl değerlendirilebilir?",
        secenekler: [
            "Orta Çağ boyunca otorite hiçbir zaman sorgulanmadı; gözlem tamamen dışlandı.",
            "Orta Çağ'da gözlem her zaman otoriteye baskın geldi ve deneysel yöntem yaygın biçimde kullanıldı.",
            "Otorite ve gözlem arasındaki ilişki sabit değildi; bazı düşünürler gözlemin önemini savunarak statik tabloya meydan okudu.",
            "Aristoteles ve kutsal metin hiçbir zaman bilimsel bir otorite olarak kabul görmedi.",
            "Roger Bacon ve Albertus Magnus Orta Çağ bilimini tamamen dönüştürerek modern bilimi kurdu."
        ],
        cevap: "Otorite ve gözlem arasındaki ilişki sabit değildi; bazı düşünürler gözlemin önemini savunarak statik tabloya meydan okudu.",
        aciklama: "Metin iki boyutu dengeli biçimde sunmaktadır: skolastik çevrelerde otoritenin üstünlüğü (Aristoteles ve kutsal metin) ve bu tabloya meydan okuyan bazı düşünürlerin (Roger Bacon, Albertus Magnus) gözlem ve deneyi savunması. 'Hiçbir zaman tam anlamıyla donuk değildi' ifadesi bu iç çeşitliliği vurgular. A ve B seçenekleri bu karmaşık tabloyu aşırı basitleştirmektedir."
    },
    {
        soru: "\"Orta Çağ'da eğitimin kurumsal çerçevesi, katedrallerle başlayıp üniversitelerle olgunlaştı. Üniversiteler yalnızca bilgi aktarım mekânları değil, öğrencilerin ve öğretmenlerin hukuki statü ve ayrıcalıklar kazandığı lonca benzeri yapılardı. Bu özerk statü, entelektüel tartışmanın zamanla daha bağımsız bir zemin kazanmasına olanak tanıdı.\"\n— Hastings Rashdall, The Universities of Europe in the Middle Ages, Oxford University Press, 1895 (1936 baskısı)\n\nMetne göre Orta Çağ üniversitelerini salt bir eğitim kurumundan ayıran temel özellik nedir?",
        secenekler: [
            "Üniversitelerin yalnızca Latince öğretim yapması",
            "Hukuki özerklik ve lonca benzeri yapılanmanın entelektüel bağımsızlık için bir zemin sağlaması",
            "Üniversitelerin tüm öğrencilere ücretsiz eğitim sunması",
            "Bu kurumların doğrudan kilise tarafından yönetilmesi",
            "Üniversitelerin yalnızca dini konuları öğretmekle yükümlü tutulması"
        ],
        cevap: "Hukuki özerklik ve lonca benzeri yapılanmanın entelektüel bağımsızlık için bir zemin sağlaması",
        aciklama: "Metin üniversitelerin 'lonca benzeri yapılar' olarak hukuki statü ve ayrıcalıklar barındırdığını; bu özerk statünün entelektüel tartışmanın bağımsız zemin kazanmasına olanak tanıdığını belirtmektedir. Bu çerçeve, üniversiteyi salt içerik aktarımının ötesinde kurumsal bir özerklik birimi olarak konumlandırmaktadır."
    },
    {
        soru: "\"Orta Çağ'da 'ilerleme' kavramı bugünkü anlamda var değildi. Zaman, çoğunlukla döngüsel ya da çöküşe doğru akan bir akış olarak kavranıyor; altın çağ geride kalmış, şimdiki zaman ise onun soluk bir yansıması sayılıyordu. Bu zaman anlayışı; mimari kanonların, edebi modellerin ve dini otoritenin neden bu denli güçlü biçimde 'eski'ye referans verdiğini açıklar.\"\n— Jacques Le Goff, Time, Work and Culture in the Middle Ages, University of Chicago Press, 1980\n\nLe Goff'a göre Orta Çağ'daki döngüsel zaman anlayışının kültürel üretim üzerindeki etkisi nedir?",
        secenekler: [
            "Bu zaman anlayışı sanatçıları özgün eser üretmekten tamamen alıkoydu.",
            "Döngüsel ya da çöküşe akan zaman anlayışı, mimari kanon, edebi model ve dini otorite gibi alanlarda 'eski'nin referans alınmasını meşrulaştırdı.",
            "Bu anlayış Orta Çağ düşünürlerinin geleceği hiç düşünmemelerine yol açtı.",
            "Döngüsel zaman anlayışı Orta Çağ'da bilimsel ilerlemeyi hızlandırdı.",
            "Bu anlayış yalnızca kilise çevrelerinde geçerliydi; laik kültür ilerlemeci bir zaman anlayışını benimsemişti."
        ],
        cevap: "Döngüsel ya da çöküşe akan zaman anlayışı, mimari kanon, edebi model ve dini otorite gibi alanlarda 'eski'nin referans alınmasını meşrulaştırdı.",
        aciklama: "Le Goff'a göre 'eski'nin sürekli referans alınması tesadüfi değil; geçmişi altın çağ, şimdiyi onun gölgesi olarak gören döngüsel/çöküşçü zaman anlayışının doğal sonucudur. Bu zaman anlayışı, kanona bağlılığı ve eski modellerin otoritesini meşrulaştıran derin bir kültürel mantığı yansıtmaktadır. Öğrenciden zaman kavrayışı ile kültürel üretim biçimi arasındaki ilişkiyi kavraması beklenmektedir."
    }
];
window.allTests["klasik_u3_genel_1"] = [
    {
        soru: "<i>Kaynak: Jean-Paul Roux, Türklerin Tarihi, 1984<br><br>\"Dördüncü yüzyılın sonlarına doğru Asya bozkırlarında yaşanan şiddetli kuraklık, otlakların kurumasına ve hayvan sürülerinin telef olmasına yol açtı. Hayatta kalmak isteyen Hun boyları, daha verimli topraklara ulaşmak için batıya doğru amansız bir yürüyüşe geçtiler.\"</i><br><br><b>Metne göre Kavimler Göçü'nü tetikleyen ilk hareketin temel nedeni nedir? Açıklayınız.</b>",
        cevap: "Göçün temel nedeni iklimsel değişimler (şiddetli kuraklık) ve buna bağlı olarak ortaya çıkan ekonomik/yaşamsal zorunluluklardır (otlakların kuruması, hayvanların telef olması)."
    },
    {
        soru: "<i>Kaynak: Peter Heather, Roma İmparatorluğu'nun Çöküşü, 2005<br><br>\"Hunların Karadeniz'in kuzeyine inmesiyle, burada yaşayan Gotlar, Vandallar ve Lombardlar gibi Cermen kavimleri büyük bir paniğe kapıldı. Adeta bir bilardo topu gibi birbirlerini iterek Roma İmparatorluğu'nun sınırlarından içeri girdiler.\"</i><br><br><b>Yazarın kullandığı 'bilardo topu' metaforu, Kavimler Göçü'nün hangi dinamiğini anlatmak için kullanılmıştır?</b>",
        cevap: "Göçlerin birbirini tetikleyen zincirleme (domino etkisi) bir kitlesel harekete dönüştüğünü; bir kavmin diğerini yerinden etmesiyle hareketin büyüdüğünü anlatır."
    },
    {
        soru: "<i>Kaynak: Patrick Geary, Ulusların Efsanesi: Avrupa'nın Kökleri, 2002<br><br>\"Avrupa'da Kavimler Göçü'nden sonra kurulan Frank, Burgond, Lombard ve Anglosakson krallıkları, bugünkü modern Fransa, Almanya, İtalya ve İngiltere devletlerinin isim ve etnik temellerini oluşturmuştur.\"</i><br><br><b>Kavimler Göçü'nün günümüz modern Avrupa'sı üzerindeki en kalıcı siyasi ve demografik etkisi nedir?</b>",
        cevap: "Avrupa'nın bugünkü modern siyasi sınırlarının ve etnik haritasının (ulus devletlerin) temellerini atmış olmasıdır."
    },
    {
        soru: "<i>Kaynak: Florin Curta, Güneydoğu Avrupa'nın Oluşumu, 2001<br><br>\"Slav kabileleri 6. yüzyıldan itibaren Balkanlara gruplar halinde sızarak yerleştiler. Başlangıçta küçük köyler halinde tarım yapıyorlardı. Ancak zamanla Bizans İmparatorluğu'nun elindeki Balkanların etnik ve demografik yapısını tamamen değiştirdiler.\"</i><br><br><b>Slav göçlerinin Bizans İmparatorluğu'nun Balkan coğrafyasındaki etkisini yorumlayınız.</b>",
        cevap: "Balkanların Helen (Yunan) ağırlıklı demografik yapısı kalıcı olarak Slavlaşmış ve bölge bugünkü etnik (Sırp, Hırvat vb.) karakterini kazanmıştır."
    },
    {
        soru: "<i>Kaynak: Modern Sosyoloji ve Tarih Terimleri Sözlüğü<br><br>\"Vandallar, 455 yılında Roma şehrini işgal ettiklerinde birçok sanat eserini, tapınağı ve kütüphaneyi tahrip ettiler. Bu eylemleri nedeniyle günümüzde anlamsız ve kasıtlı yıkım eylemlerine 'Vandalizm' denmektedir.\"</i><br><br><b>Vandalların eylemleri ve 'Vandalizm' kavramı, kitlesel göç süreçlerinin yerleşik medeniyetler üzerindeki hangi olumsuz boyutunu göstermektedir?</b>",
        cevap: "Göç ve istila hareketlerinin, yerleşik medeniyetlerin kültürel birikimine, mimarisine ve sanat eserlerine verdiği yıkıcı zararı (kültürel tahribatı) göstermektedir."
    },
    {
        soru: "<i>Kaynak: Simon Schama, Yahudilerin Hikayesi, 2013<br><br>\"Yahudiler, MS 70 yılında Roma İmparatorluğu tarafından Kudüs'ten sürülmelerinin ardından yüzyıllar boyunca Avrupa ve Orta Doğu'ya dağıldılar. Gittikleri birçok bölgede tarım yapmalarına veya toprak sahibi olmalarına izin verilmediği için daha çok ticaret ve zanaata yöneldiler.\"</i><br><br><b>Diaspora sonrası Yahudi göçmenlerin ticarette ve zanaatta yoğunlaşmasının sosyolojik ve hukuki nedeni nedir?</b>",
        cevap: "Sığındıkları topraklarda mülkiyet edinmelerinin ve tarım yapmalarının hukuken kısıtlanması (dışlanmaları), onları hayatta kalmak için sermayeye dayalı ve hareketli mesleklere yönelmeye zorlamıştır."
    },
    {
        soru: "<i>Kaynak: Arthur Christensen, Sasaniler Devrinde İran, 1936<br><br>\"Sasani İmparatorluğu döneminde, resmi din olan Zerdüştlükten saparak farklı fikirler savunan Mazdek taraftarları, devletin ağır baskısı ve katliamlarıyla karşılaşınca çareyi komşu bölgelere, özellikle Türkistan'a göç etmekte bulmuşlardır.\"</i><br><br><b>Mazdek isyanı sonrasında yaşanan bu durum, kitlesel göçlerin hangi spesifik nedeniyle açıklanabilir?</b>",
        cevap: "Dini baskı, inanç özgürlüğünün kısıtlanması ve siyasi zulüm nedenleriyle açıklanabilir."
    },
    {
        soru: "<i>Kaynak: Marc Bloch, Feodal Toplum, 1939<br><br>\"Batı Roma İmparatorluğu'nun çökmesiyle Avrupa'da merkezi devlet otoritesi ve can güvenliği kalmadı. Şehirler yağmalanırken halk, kendilerini koruyabilmeleri için devasa surlarla çevrili şatoları olan yerel lordların himayesine girmek zorunda kaldı.\"</i><br><br><b>Metne göre Avrupa'da feodalitenin (derebeylik) doğuşuna zemin hazırlayan en temel psikolojik ve siyasi ihtiyaç nedir?</b>",
        cevap: "Merkezi otoritenin çöküşüyle oluşan 'güvenlik ihtiyacı' ve halkın can/mal güvenliği için yerel güçlere sığınma zorunluluğudur."
    },
    {
        soru: "<i>Kaynak: Chris Wickham, Ortaçağ Avrupası'nın Mirası, 2016<br><br>\"Cermen kabileleri Roma sınırlarını aştıklarında amaçları Roma'yı yıkmak değildi. Çoğu Roma ordusunda asker olmak ve güvenli topraklarda çiftçilik yapmak istiyordu. Ancak Roma, bu devasa kitleyi sisteme entegre edecek ekonomik ve bürokratik esnekliği gösteremediği için içeriden çöktü.\"</i><br><br><b>Yazara göre Roma'nın yıkılışını sadece 'barbar saldırganlığı' ile açıklamak neden eksiktir?</b>",
        cevap: "Çünkü asıl sorun barbarların saldırganlığı değil, Roma'nın kendi bürokratik ve ekonomik sisteminin bu devasa göçmen nüfusu asimile edecek/entegre edecek kapasiteden yoksun olmasıdır."
    },
    {
        soru: "<i>Kaynak: Lynn White Jr., Ortaçağ Teknolojisi ve Toplumsal Değişim, 1962<br><br>\"Avarlar, Avrupa'ya geldiklerinde o güne kadar bilinmeyen 'demir üzengiyi' getirdiler. Üzengi sayesinde süvariler at üzerinde daha sağlam durabildi ve ağır zırhlı silahlar kullanabildi. Bu teknoloji, Avrupalı şövalye sınıfının doğuşunu tetikledi.\"</i><br><br><b>Üzenginin Avrupa'ya taşınması, teknolojik gelişmelerin siyasi/sosyal yapıları nasıl etkilediğine dair neyi kanıtlar?</b>",
        cevap: "Basit bir askeri teknolojinin (üzengi), yeni bir askeri taktik (ağır süvari) yaratarak Avrupa'da yepyeni bir toplumsal ve siyasi elit sınıfın (şövalyeler/feodal lordlar) doğmasına yol açtığını kanıtlar."
    }
];

window.allTests["klasik_u3_genel_2"] = [
    {
        soru: "<i>Kaynak: Richard Southern, Batı Toplumu ve Kilise, 1970<br><br>\"Kavimler Göçü'nün yarattığı kargaşa ortamında, Batı Avrupa'da devlet idaresi çökerken, Papalık ayakta kalan tek organize kurum oldu. Kilise, barbar kralları Hristiyanlaştırarak onları kontrol altına aldı ve parçalanmış Avrupa'da yeni bir birleştirici siyasi unsur haline geldi.\"</i><br><br><b>Metne göre Katolik Kilisesi'nin salt bir inanç merkezi olmaktan çıkıp siyasi bir otoriteye dönüşmesini sağlayan durum nedir?</b>",
        cevap: "Roma'nın yıkılışıyla oluşan otorite boşluğunu doldurması ve barbarları aynı inanç etrafında birleştirerek toplumsal ve siyasi entegrasyonu sağlamasıdır."
    },
    {
        soru: "<i>Kaynak: J.C. Holt, Magna Carta, 1992<br><br>\"1215 yılında İngiltere Kralı Yurtsuz John, soyluların baskısıyla Magna Carta'yı imzalamak zorunda kaldı. Bu belge, 'Hiçbir özgür insan, kanuni bir yargılama olmadan tutuklanamaz, sürgün edilemez' hükmünü getiriyordu.\"</i><br><br><b>Magna Carta'nın Avrupa'da hukukun ve demokrasinin gelişimi açısından taşıdığı tarihsel önem nedir?</b>",
        cevap: "Kralın yetkilerinin kanunlarla sınırlandırılabileceğini ve hukukun (kanunun) kraldan üstün olduğunu kabul eden ilk büyük anayasal adım olmasıdır."
    },
    {
        soru: "<i>Kaynak: Steven Runciman, Haçlı Seferleri Tarihi, 1951<br><br>\"Haçlı Seferleri, Avrupa'da 'Kutsal Toprakları kurtarmak' gibi dini bir söylemle başlatılmış olsa da; şövalyelerin Doğu'nun zenginliklerini ele geçirme arzusu ve İtalyan şehir devletlerinin Doğu Akdeniz ticaretini kontrol etme hırsı asıl itici güçlerdi.\"</i><br><br><b>Tarihçi Runciman'ın bu analizine göre Haçlı Seferleri'nin 'görünürdeki' nedeni ile 'gerçek' nedenleri arasındaki farkı açıklayınız.</b>",
        cevap: "Görünürdeki neden Kutsal Toprakları kurtarmak (dini) iken, gerçek nedenler Doğu'nun zenginliklerini yağmalamak ve Akdeniz ticaret yollarını ele geçirmektir (ekonomik ve siyasi)."
    },
    {
        soru: "<i>Kaynak: İbn Haldun, Mukaddime, 1377<br><br>\"İslam düşünürü İbn Haldun toplulukları Bedevi (göçebe) ve Hadari (yerleşik) olarak ayırır. Zor şartlarda yaşayan dayanışması güçlü göçebeler, savaş yeteneğini yitirmiş zengin yerleşikleri yıkarak devlet kurarlar. Ancak zamanla onlar da refaha alışıp zayıflar ve yeni göçebeler tarafından yıkılırlar.\"</i><br><br><b>İbn Haldun'un bu teorisi, Orta Çağ'daki devletlerin ömrü ve yıkılışı hakkında nasıl bir tarihsel yasa (felsefe) ortaya koymaktadır?</b>",
        cevap: "Devletlerin kuruluş, yükseliş ve yıkılışının döngüsel (tekerrür eden) bir süreç olduğunu; refahın ve yerleşikleşmenin toplumsal dayanışmayı (asabiyet) zayıflatarak kaçınılmaz bir çöküşe yol açtığını savunur."
    },
    {
        soru: "<i>Kaynak: Thomas Barfield, Tehlikeli Sınır, 1989<br><br>\"Büyük bozkır göçlerinin asimetrik doğası şuydu: Yerleşik devletler milyonlarca nüfusa sahipti. Ancak atlı göçebeler, stratejik hareket kabiliyetine sahipti. Çin ordusu hedefe varana kadar aylar geçerken, Hun süvarisi vur-kaç taktiğiyle şehri yağmalayıp sırra kadem basıyordu.\"</i><br><br><b>Nüfusça çok az olan göçebe imparatorlukların, devasa yerleşik devletlere karşı üstünlük kurmasını sağlayan askeri avantaj nedir?</b>",
        cevap: "Hız, stratejik hareket kabiliyeti ve vur-kaç gibi esnek askeri taktikleri kullanabilme (asimetrik savaş) avantajıdır."
    },
    {
        soru: "<i>Kaynak: İbn Battuta, Rihle (Seyahatname), YKY, 2004<br><br>\"Kervansaraylar, tüccarların ve hayvanlarının güvenle konakladığı, yolların üzerinde belirli aralıklarla inşa edilmiş yapılardı. Bu yapılar sayesinde uzak mesafeli ticaret hem daha güvenli hem de daha düzenli bir hal aldı.\"</i><br><br><b>Kervansarayların uzun mesafeli ticarete katkısını iki temel kavram üzerinden açıklayınız.</b>",
        cevap: "Güvenlik (tüccarların barınması ve korunması) ve lojistik düzen (dinlenme, hayvanları besleme imkânı sağlayarak ticaretin sürekliliğini temin etme)."
    },
    {
        soru: "<i>Kaynak: Valerie Hansen, İpek Yolu: Yeni Bir Tarih, 2012<br><br>\"İpek Yolu, Çin'den Akdeniz'e uzanan bu devasa ticaret güzergahı boyunca yalnızca ipek veya baharat taşınmıyordu; kağıt yapımı, pusula, matbaa gibi teknolojik buluşlar ve farklı dini inançlar da bu yolda seyahat ediyordu.\"</i><br><br><b>Yazarın bu tespiti, ticaret yollarının ekonomik işlevi dışında hangi tarihsel misyonu üstlendiğini kanıtlamaktadır?</b>",
        cevap: "Ticaret yollarının medeniyetler arası bir 'kültürel, teknolojik ve dini etkileşim (köprü)' misyonu üstlendiğini kanıtlar."
    },
    {
        soru: "<i>Kaynak: S.D. Goitein, Bir Akdeniz Toplumu, 1967<br><br>\"Orta Çağ'da Kahire'de bulunan Geniza belgeleri, tüccarların mektuplar aracılığıyla birbirlerine fiyat bilgisi, yol güvenliği ve siyasi durumlar hakkında sürekli bilgi aktardığını göstermektedir.\"</i><br><br><b>Tüccarların mektuplar aracılığıyla kurdukları bu haberleşme ağı, ticari faaliyetlerin hangi zorluğunu aşmaya yöneliktir?</b>",
        cevap: "Ticareti etkileyen belirsizlikleri, fiyat dalgalanmalarını ve güvenlik risklerini önceden öğrenerek zararı en aza indirme (risk yönetimi) zorluğunu aşmaya yöneliktir."
    },
    {
        soru: "<i>Kaynak: Robert Lopez, Ortaçağda Ticaret Devrimi, 1976<br><br>\"Orta Çağ'da Şampanya Fuarları, Kuzey Avrupa kumaşlarının Akdeniz baharatlarıyla buluştuğu bir pazardı. Ancak asıl devrim, tüccarların nakit altın taşımak yerine burada birbirlerine 'kambiyo senedi' (kredi kağıdı) vermeye başlamasıyla yaşandı.\"</i><br><br><b>Şampanya Fuarları'nın 'Ticaret Devrimi'nin merkezi olarak anılmasının sebebi, mal alım-satımından ziyade hangi gelişmeye ev sahipliği yapmasıdır?</b>",
        cevap: "Modern kredi, bankacılık ve nakit taşımadan kağıt üzeri para transferi (kambiyo) sistemlerinin ilk kez bu fuarlarda ortaya çıkmasıdır."
    },
    {
        soru: "<i>Kaynak: Avner Greif, Erken Dönem Ticaretin Kurumları, 2006<br><br>\"Avrupa'da kilise, faiz almayı 'tefecilik' olarak nitelendirip yasaklıyordu. Ancak tüccarlar bu yasağı 'kambiyo senedi' ve 'commenda' (risk paylaşım ortaklığı) gibi yeni yasal finansal sözleşmeler icat ederek aşmayı öğrendi.\"</i><br><br><b>Bu durum, tüccarların dogmatik engeller karşısında nasıl bir tutum sergilediğini göstermektedir?</b>",
        cevap: "Tüccarların dogmatik yasaklara boyun eğmeyip, ticareti sürdürebilmek için yasal kılıflar ve yeni finansal yenilikler (inovasyonlar) üreterek pragmatik (akılcı) çözümler bulduğunu gösterir."
    }
];

window.allTests["klasik_u3_genel_3"] = [
    {
        soru: "<i>Kaynak: Halil İnalcık, Osmanlı İmparatorluğu Klasik Çağ, 1973<br><br>\"Tarihçi Halil İnalcık, Osmanlı'nın İstanbul'u fethiyle ticaret yollarını kapattığı tezini reddeder: 'Osmanlılar, gümrük gelirlerine bağımlıydı ve yolu tamamen kapatmak kendi ekonomilerine zarar verirdi. Aslında ticareti açık tutmaya çalıştılar.'\"</i><br><br><b>İnalcık'ın bu tespitine göre, Avrupalıların Coğrafi Keşiflere yönelmesinin asıl ekonomik motivasyonu 'yolların kapanması' değilse nedir?</b>",
        cevap: "Avrupa'nın, aracıları (Osmanlı ve Venedik tüccarları ile onların aldığı gümrük vergilerini) aradan çıkarıp Doğu'nun mallarına doğrudan ve daha ucuza ulaşma isteğidir."
    },
    {
        soru: "<i>Kaynak: Janet Abu-Lughod, Avrupa Hegemonyasından Önce, 1989<br><br>\"1250-1350 yılları arasında Avrupa henüz marjinal bir güçtü; Asya, Afrika ve Akdeniz'i bağlayan sekiz büyük ticaret bölgesinden oluşan bir sistem mevcuttu. Hint Okyanusu ticareti, Avrupa ile kıyaslanamayacak ölçekte büyüktü.\"</i><br><br><b>Bu tarihi gerçek, günümüzdeki 'Avrupa Merkezci (Eurocentric)' tarih anlayışına nasıl bir eleştiri getirmektedir?</b>",
        cevap: "Avrupa'nın her zaman dünyanın merkezi ve en gelişmiş bölgesi olduğu yönündeki yanılgıyı yıkar; Doğu ve Asya ticaret ağlarının Avrupa'dan çok daha önce ve çok daha büyük ölçekte var olduğunu kanıtlar."
    },
    {
        soru: "<i>Kaynak: Umberto Eco, Ortaçağ Estetiğinde Sanat ve Güzellik, 1959<br><br>\"Orta Çağ'da inşa edilen devasa Gotik katedrallerin vitray pencerelerindeki resimler ve heykeller sadece süsleme değildi; okuma yazma bilmeyen halk için 'taştan ve camdan yapılmış birer resimli İncil' işlevi görüyordu.\"</i><br><br><b>Yazara göre Orta Çağ'da sanatın ve mimarinin estetik dışındaki en önemli toplumsal işlevi nedir?</b>",
        cevap: "Okuryazar olmayan kitlelere dini metinleri, kültürel bilgileri ve kilisenin mesajını görsel yolla aktarmak; yani eğitici ve ideolojik bir araç olmaktır."
    },
    {
        soru: "<i>Kaynak: Jacques Le Goff, Ortaçağda Entelektüeller, 1957<br><br>\"12. yüzyıldan itibaren Avrupa'da piskoposluk okulları ve manastırların yerini 'Üniversiteler' (Universitas) almaya başladı. Bologna, Paris ve Oxford gibi şehirlerde kurulan bu kurumlar, bilginin üretimini şekillendirdi.\"</i><br><br><b>Üniversitelerin kurulması, Orta Çağ Avrupa'sında eğitim ve bilgi üretimi tekelinin kimden kime geçtiğini simgelemektedir?</b>",
        cevap: "Bilginin üretim ve eğitim tekelinin kapalı kilise/manastır duvarlarından (din adamlarından) çıkarak şehirlerin dinamik, sivil ve entelektüel ortamına geçtiğini simgeler."
    },
    {
        soru: "<i>Kaynak: Jonathan Lyons, Bilgelik Evi, 2009<br><br>\"Orta Çağ'da İslam dünyası Bağdat'taki 'Beyt'ül Hikme' (Bilgelik Evi) sayesinde Antik Yunan, Hint ve Fars eserlerini Arapçaya çevirip bilimde altın çağını yaşarken; aynı dönemde Avrupa'da bilgi sadece manastırlara hapsolmuştu.\"</i><br><br><b>Metne göre İslam dünyasının Orta Çağ bilim tarihindeki 'kurtarıcı' veya 'köprü' rolü nasıl açıklanabilir?</b>",
        cevap: "Antik çağın unutulmaya yüz tutmuş bilimsel mirasını çevirilerle koruması, kendi katkılarıyla geliştirmesi ve ilerleyen yüzyıllarda bu birikimi tekrar Batı'ya aktarmasıyla açıklanır."
    },
    {
        soru: "<i>Kaynak: Howard Turner, Orta Çağ İslam Dünyasında Bilim<br><br>\"Müslüman bilgin El-Biruni, Hindistan'ı incelerken eski kitaplardaki teorileri körü körüne kabul etmemiş; dağlardaki deniz fosillerini kendi gözleriyle inceleyerek yeryüzünün jeolojik değişimler geçirdiğini bizzat kanıtlamıştır.\"</i><br><br><b>El-Biruni'nin kitaplardaki dogmatik bilgiyi reddedip fosilleri incelemesi, bilimsel bilginin üretilmesinde hangi modern yöntemin kullanıldığını gösterir?</b>",
        cevap: "Gözlem, deney ve sahada somut (ampirik) kanıt toplama yönteminin kullanıldığını gösterir."
    },
    {
        soru: "<i>Kaynak: Amin Maalouf, Arapların Gözünden Haçlı Seferleri, 1983<br><br>\"Arap kronikçisi İbn el-Esir, Haçlıların Kudüs'ü ele geçirdiklerinde yaptıkları katliamları dehşetle anlatır. Arapların gözünde Batı'dan gelen bu zırhlı adamlar (Franklar), medeniyetten uzak, yıkanmayı bile bilmeyen kaba saba barbarlardı.\"</i><br><br><b>Avrupalıların Doğu'yu 'kâfir', Arapların ise Avrupalıları 'barbar' olarak görmesi, tarih biliminde 'medeniyet algısı' ile ilgili bize ne öğretir?</b>",
        cevap: "Barbarlık ve medeniyet algısının mutlak olmadığını; bakan kişinin/toplumun kültürel konumuna, taraflılığına ve coğrafyasına göre değişen göreceli (rölatif) bir kavram olduğunu öğretir."
    },
    {
        soru: "<i>Kaynak: Etienne Gilson, Ortaçağ Felsefesi Ruhu<br><br>\"İslam alimi Gazzâlî ve Hristiyan düşünür Thomas Aquinas, farklı dinlere mensup olsalar da benzer bir çaba içindeydiler: Antik Yunan felsefesindeki aklı (Aristoteles mantığını), kutsal kitaplardaki ilahi vahiyle (inançla) uyumlu hale getirmek.\"</i><br><br><b>Orta Çağ düşünce dünyasına damga vuran ve 'akıl ile inancı (din ile felsefeyi) uzlaştırma' çabası olarak bilinen bu felsefi ekolün (anlayışın) genel adı nedir?</b>",
        cevap: "Skolastik düşünce (Skolastisizm) veya dini/teolojik felsefedir."
    },
    {
        soru: "<i>Kaynak: Edebiyat Tarihi Çalışmaları<br><br>\"Geç Orta Çağ'da ünlü şair Dante, 'İlahi Komedya' adlı dev eserini dönemin evrensel eğitim ve din dili olan Latince yerine, sokaktaki halkın konuştuğu yerel dil olan İtalyanca (Toskana lehçesi) ile yazdı.\"</i><br><br><b>Edebi eserlerin Latince yerine İtalyanca gibi yerel (vernaküler) dillerde yazılmaya başlanmasının kültürel sonucu ne olmuştur?</b>",
        cevap: "Kilisenin ve elitlerin dil (Latince) üzerindeki tekelinin kırılmasına, edebiyatın geniş halk kitlelerine yayılmasına ve milli/yerel kültürlerin doğuşuna öncülük etmiştir."
    },
    {
        soru: "<i>Kaynak: Johan Huizinga, Ortaçağ'ın Günbatımı<br><br>\"Orta Çağ Avrupa'sında, veba salgınları ve sürekli savaşların yarattığı karamsar tablo, sanatta 'Ölüm Dansı' (Danse Macabre) temasının yaygınlaşmasına neden oldu. Bu eserlerde krallar, papalar ve köylüler iskeletlerle yan yana dans ederken tasvir ediliyordu.\"</i><br><br><b>'Ölüm Dansı' temasının sanat eserlerinde yaygınlaşması, Orta Çağ insanının ölüm ve toplumsal eşitlik algısı hakkında neyi vurgulamaktadır?</b>",
        cevap: "Ölümün her an kapıda olduğu korkusunu ve toplumsal statü (kral, papa veya köylü) fark etmeksizin ölüm karşısında herkesin eşit olduğu inancını yansıtmaktadır."
    }
];